    _preferred_narrative_source_re = re.compile(
        r"(earnings_release|press_release|presentation|slides|transcript|ceo|shareholder|mda)",
        re.I,
    )
    _pbi_note_theme_re = re.compile(
        r"\b(adjusted ebit|ebit|margin|free cash flow|fcf|deleverag|liquidity|trapped capital|"
        r"pb bank|bank funding|cost savings?|cost rationalization|guidance|sendtech|presort|"
        r"buyback|repurchas\w*|authorization|capital return|remaining capacity|dividend|"
        r"strategic review|phase 2|phase two|forecast(?:ing)?|uncertainty|operational execution|"
        r"cost management|leverage|working capital|balance sheet|non-core asset|"
        r"shipping|mail(?:ing| volume)?|parcel|postage)\b",
        re.I,
    )
    _pbi_promise_theme_re = re.compile(
        r"\b(adjusted ebit|ebit|eps|free cash flow|fcf|revenue|guidance|cost savings?|"
        r"cost rationalization|deleverag|liquidity|trapped capital|pb bank|bank funding|"
        r"sendtech|presort|shipping|mail(?:ing| volume)?|parcel|postage|milestone)\b",
        re.I,
    )
    _pbi_fragment_drop_re = re.compile(
        r"\b(would be incremental to|provided the following|table of contents|safe harbor|"
        r"private securities litigation reform act|risk factors?|forward-looking statements|"
        r"future revenue and profitability|future events or conditions|capital allocation strategy|"
        r"management target\s*$|item\s+\d|low\s+high\s+revenue|"
        r"reconciliation of adjusted segment ebitda|total reportable segments|"
        r"net cash from operating activities|capital expenditures|"
        r"adjusted ebit(?:, adjusted ebitda and adjusted eps)? exclude the impact|"
        r"adjusted ebitda and adjusted eps exclude the impact|"
        r"previously disclosed guidance ranges|full year \d{4} guidance\s*$)\b",
        re.I,
    )

    def _is_preferred_narrative_source(source_type_in: Any) -> bool:
        src_txt = str(source_type_in or "").strip().lower()
        if not src_txt:
            return False
        if shared_is_preferred_narrative_source(src_txt):
            return True
        return bool(_preferred_narrative_source_re.search(src_txt))

    def _looks_pbi_fragment_text(text_in: Any) -> bool:
        txt = glx_normalize_text(str(text_in or ""))
        if not txt:
            return True
        if re.search(
            r"\b(fully operational|online and ramping|risk management supports?|utilization\b|agreement executed|"
            r"debt repaid|liquidity (?:improved|released)|cash release|45z|monetization|bridge|included in)\b",
            txt,
            re.I,
        ) and not shared_looks_like_tabular_fragment(txt):
            return False
        if _pbi_fragment_drop_re.search(txt):
            return True
        if _slide_signal_noise(txt):
            return True
        if re.search(
            r"\b(reconciliation of adjusted segment ebitda|total reportable segments|"
            r"for reference[, ]+the company.?s previously disclosed guidance ranges|"
            r"net cash from operating activities.*capital expenditures|"
            r"full year \d{4} guidance.*low high revenue|"
            r"adjusted segment ebitda to income or loss from continuing operations before taxes)\b",
            txt,
            re.I,
        ):
            return True
        if re.search(r"^\s*(for reference[, ]+)?full year \d{4} guidance\s*$", txt, re.I):
            return True
        if re.search(r"\b(low|high)\s+(revenue|adjusted ebit|adjusted eps|free cash flow)\b", txt, re.I):
            return True
        if re.search(r"\d{1,3},\d{3}\d{1,3},\d{3}", txt):
            return True
        numeric_hits = len(re.findall(r"\$?\s*\d[\d,]*(?:\.\d+)?\s*(?:%|m|mm|x|million|billion)?", txt, re.I))
        table_metric_hits = len(re.findall(r"\b(revenue|adjusted ebit|adjusted eps|free cash flow|presort services|sendtech solutions)\b", txt, re.I))
        if numeric_hits >= 4 and table_metric_hits >= 2 and not re.search(r"\b(bridge|included in|45z|monetization)\b", txt, re.I):
            return True
        if numeric_hits >= 5 and len(re.findall(r"[.;:]", txt)) <= 1 and not re.search(r"\b(bridge|included in|45z|monetization)\b", txt, re.I):
            return True
        if len(txt) < 40 and not re.search(r"\b(sendtech|presort|ebit|fcf|liquidity|pb bank|york|utilization|risk management|45z|bridge)\b", txt, re.I):
            return True
        return bool(_text_fragment_penalty(txt) >= 2 and not re.search(r"\b(target|guidance|margin|ebit|fcf|liquidity|presort|sendtech|york|utilization|bridge|45z)\b", txt, re.I))

    def _is_pbi_clean_sentence(text_in: Any) -> bool:
        txt = glx_normalize_text(str(text_in or ""))
        if not txt or _looks_pbi_fragment_text(txt):
            return False
        if re.search(
            r"\b(fully operational|online and ramping|risk management supports?|utilization\b|agreement executed|"
            r"debt repaid|liquidity (?:improved|released)|cash release|45z|monetization|bridge|included in)\b",
            txt,
            re.I,
        ) and 3 <= len(re.findall(r"\b\w+\b", txt)) <= 18:
            return True
        if txt[:1].islower():
            return False
        if re.search(r"^\s*(of|date|complete)\b", txt, re.I):
            return False
        if txt.count("???") >= 1 or txt.count("???") >= 1:
            return False
        word_count = len(re.findall(r"\b\w+\b", txt))
        if word_count < 7 or word_count > 48:
            return False
        if not re.search(
            r"\b(expect|expects|guidance|improved|improvement|increased|increase|grew|growth|"
            r"expanded|expansion|reduced|reduction|generated|achieved|delivered|support|supports|"
            r"driven|drives|raised|lowered|reaffirmed|tightened|operational|ramping|executed)\b",
            txt,
            re.I,
        ):
            return False
        if re.search(r"\b(low\s+high\s+revenue|adjusted segment ebitda to income|table of contents)\b", txt, re.I):
            return False
        if re.search(
            r"\b(net cash from operating activities|capital expenditures|reconciliation of adjusted segment ebitda|"
            r"for reference[, ]+the company.?s previously disclosed guidance ranges)\b",
            txt,
            re.I,
        ):
            return False
        if len(txt) > 110 and not re.search(r"[.;:]", txt):
            return False
        if len(re.findall(r"\$?\s*\d[\d,]*(?:\.\d+)?", txt)) >= 5 and len(re.findall(r"[.;:]", txt)) <= 1:
            return False
        return True

    def _pbi_target_display_ok(text_in: Any) -> bool:
        txt = str(text_in or "").strip()
        if not txt:
            return False
        if len(txt) > 90:
            return False
        if re.fullmatch(
            r"(?:>=|<=|>|<)?\s*\$?\s*[\d,.]+(?:\.\d+)?\s*(?:m|mm|million|b|bn|billion|%)?"
            r"(?:\s*(?:to|-|–|—)\s*\$?\s*[\d,.]+(?:\.\d+)?\s*(?:m|mm|million|b|bn|billion|%)?)?"
            r"(?:\s+(?:annualized savings|annualised savings|bank-held leases|cash optimization|leverage|revenue|adjusted ebit|adjusted eps|free cash flow))?",
            txt,
            re.I,
        ):
            return True
        if _looks_pbi_fragment_text(txt):
            return False
        return bool(
            re.search(
                r"(\$|>=|<=| to |-|–|—|annualized|fy\s*20\d{2}|q[1-4]\s*20\d{2}|full[- ]?year)",
                txt,
                re.I,
            )
        )

    def _classify_pbi_metric_label(text_in: Any, fallback: str = "") -> str:
        txt = glx_normalize_text(str(text_in or ""))
        low = txt.lower()
        fallback_clean = str(fallback or "").strip()
        fallback_low = fallback_clean.lower()
        forwardish = bool(
            re.search(
                r"\b(guidance|target|targets|outlook|expects?|expected|reaffirm|updated|raised|tightened|lowered|"
                r"full[- ]?year|fy\s*20\d{2}|will|aims? to|plans? to|continue to|tracking)\b",
                low,
                re.I,
            )
        )
        if not txt:
            return fallback
        if fallback_clean and fallback_low not in {"", "management target", "strategic milestone", "tone | corporate"}:
            if fallback_low in {
                "adjusted ebit guidance",
                "adjusted ebit / margin",
                "cost savings target",
                "cost savings / rationalization",
                "deleveraging / liquidity",
                "deleveraging target",
                "eps guidance",
                "fcf improvement",
                "fcf target",
                "pb bank liquidity release",
                "revenue / volume",
                "revenue guidance",
                "sendtech / presort operating driver",
                "sendtech / presort operating target",
                "strategic milestone",
            }:
                return fallback_clean
        if re.search(r"\bcost (?:savings?|rationalization|takeout|actions?)\b", low, re.I):
            return "Cost savings target" if forwardish else "Cost savings / rationalization"
        if re.search(r"\beps\b", low, re.I):
            return "EPS guidance"
        if re.search(r"\bfree cash flow\b|\bfcf\b", low, re.I):
            return "FCF target" if forwardish else "FCF improvement"
        if re.search(r"\b(adjusted ebit|ebit)\b", low, re.I):
            return "Adjusted EBIT guidance" if forwardish else "Adjusted EBIT / margin"
        if re.search(r"\brevenue\b", low, re.I):
            return "Revenue guidance" if forwardish else "Revenue / volume"
        if re.search(r"\bdeleverag|net debt|leverage|revolv(?:er)?|credit agreement|refinanc|term loan|notes due|redeemed the remaining outstanding balance|principal debt\b", low, re.I):
            return "Deleveraging target" if forwardish else "Deleveraging / liquidity"
        if re.search(r"\b(pb bank|trapped capital|bank liquidity|funding release|release liquidity|bank funding)\b", low, re.I):
            return "PB Bank liquidity release"
        if re.search(r"\b(repurchas\w*|buyback|share repurchase|authorization|remaining capacity|capital return|share count reduced|shares outstanding reduced)\b", low, re.I):
            return "Capital allocation / buyback"
        if re.search(r"\b(sendtech|presort|shipping|mail(?:ing| volume)?|parcel|postage)\b", low, re.I):
            return "SendTech / Presort operating target" if forwardish else "SendTech / Presort operating driver"
        if re.search(r"\b(completed|complete|launch|migrate|exit|shut(?:down)?|sell|sale|separate|wind-?down)\b", low, re.I):
            return "Strategic milestone"
        return fallback

    def _extract_pbi_guidance_targets_multi(
        text_in: Any,
        metric_hint: str = "",
        qd_hint: Optional[date] = None,
    ) -> List[Dict[str, Any]]:
        txt = glx_normalize_text(str(text_in or ""))
        if not txt:
            return []
        txt = txt.replace("—", "-").replace("–", "-")
        txt = re.sub(r"\bQ[1-4]\s+20\d{2}\s+Earnings(?:\s+Conference\s+Call)?\b.*$", "", txt, flags=re.I)
        txt = re.sub(r"\bPitney Bowes\b\s*\|?\s*Q[1-4].*$", "", txt, flags=re.I)
        txt = re.sub(r"\*\*\*As a reminder.*$", "", txt, flags=re.I)
        txt = re.sub(r"\s+", " ", txt).strip(" |-")
        if not txt:
            return []

        metric_hint_label = _classify_pbi_metric_label(metric_hint, metric_hint)
        implied_money_units = bool(re.search(r"\$\s*millions?,\s*except\s*eps", txt, re.I))
        results: List[Dict[str, Any]] = []
        seen: set[Tuple[str, str]] = set()

        metric_patterns: List[Tuple[str, str]] = [
            ("Revenue guidance", r"\brevenue\b"),
            ("Adjusted EBIT guidance", r"\badjusted ebit\b"),
            ("EPS guidance", r"\badjusted eps\b|\beps\b"),
            ("FCF target", r"\bfree cash flow\b|\bfcf\b"),
            ("Cost savings target", r"\bcost savings?\b|\bannualized savings\b|\bsavings target\b"),
            ("Deleveraging target", r"\bdeleverag|net debt to adjusted ebitda|net debt to ebitda|leverage ratio\b"),
            ("PB Bank liquidity release", r"\b(pb bank|trapped capital|bank liquidity|funding release|bank funding)\b"),
        ]
        metric_hits: List[Tuple[int, str, re.Match[str]]] = []
        for label, pat in metric_patterns:
            for m_metric in re.finditer(pat, txt, re.I):
                metric_hits.append((m_metric.start(), label, m_metric))
        metric_hits.sort(key=lambda x: (x[0], x[1]))

        def _money_value(val_in: float, unit_hint: str = "", label_hint: str = "") -> float:
            unit_low = str(unit_hint or "").strip().lower()
            if unit_low.startswith("b"):
                return float(val_in) * 1000.0
            if unit_low in {"million", "m", "mm"}:
                return float(val_in)
            if implied_money_units and "eps" not in str(label_hint or "").lower():
                return float(val_in)
            if abs(float(val_in)) >= 100.0 and "eps" not in str(label_hint or "").lower():
                return float(val_in)
            return float(val_in)

        def _fmt_target(label: str, lo: Optional[float] = None, hi: Optional[float] = None, *,
                        unit_lo: str = "", unit_hi: str = "") -> str:
            label_low = str(label or "").lower()
            is_eps = "eps" in label_low
            is_money = not is_eps and label_low not in {"deleveraging target"}
            if lo is None:
                return ""
            if hi is not None:
                if is_eps:
                    return f"${float(lo):.2f}-${float(hi):.2f}"
                if is_money:
                    lo_v = _money_value(lo, unit_lo, label)
                    hi_v = _money_value(hi, unit_hi or unit_lo, label)
                    return f"${lo_v:,.1f}m-${hi_v:,.1f}m".replace(".0m", "m")
                return f"{float(lo):.1f}-{float(hi):.1f}"
            if is_eps:
                return f"${float(lo):.2f}"
            if is_money:
                lo_v = _money_value(lo, unit_lo, label)
                return f"${lo_v:,.1f}m".replace(".0m", "m")
            return f"{float(lo):.1f}"

        def _extract_numeric_target_from_segment(seg: str, label: str) -> str:
            seg = str(seg or "").strip()
            if not seg:
                return ""
            label_low = str(label or "").lower()
            if label_low == "deleveraging target":
                m_lev = re.search(r"(~|approximately|approx\.?\s*)?\s*(\d(?:\.\d+)?)\s*x", seg, re.I)
                if m_lev:
                    lev = coerce_number(m_lev.group(2))
                    if lev is not None:
                        return f"{lev:.1f}x leverage"
                return ""

            money_or_eps_ranges = re.findall(
                r"\$?\s*([\d,]+(?:\.\d+)?)\s*(billion|bn|million|m|mm)?\s*(?:range)?\s*"
                r"(?:to|-)\s*\$?\s*([\d,]+(?:\.\d+)?)\s*(billion|bn|million|m|mm)?",
                seg,
                re.I,
            )
            if money_or_eps_ranges:
                lo_s, unit_lo, hi_s, unit_hi = money_or_eps_ranges[-1]
                lo = coerce_number(lo_s)
                hi = coerce_number(hi_s)
                if lo is not None and hi is not None:
                    return _fmt_target(label, lo, hi, unit_lo=unit_lo or "", unit_hi=unit_hi or "")

            if implied_money_units and "eps" not in label_low:
                table_pair = re.findall(r"\$?\s*([\d,]+(?:\.\d+)?)\s+\$?\s*([\d,]+(?:\.\d+)?)", seg)
                if table_pair:
                    lo = coerce_number(table_pair[-1][0])
                    hi = coerce_number(table_pair[-1][1])
                    if lo is not None and hi is not None:
                        return _fmt_target(label, lo, hi, unit_lo="m", unit_hi="m")

            if "cost savings" in label_low:
                m_exceed = re.search(
                    r"(?:exceed|target(?:ing)?|up from|to)\s+\$?\s*([\d,]+(?:\.\d+)?)\s*(million|m)?\s*(?:to|-)\s*"
                    r"\$?\s*([\d,]+(?:\.\d+)?)\s*(million|m)?",
                    seg,
                    re.I,
                )
                if m_exceed:
                    lo = coerce_number(m_exceed.group(1))
                    hi = coerce_number(m_exceed.group(3))
                    if lo is not None and hi is not None:
                        return _fmt_target(label, lo, hi, unit_lo=m_exceed.group(2) or "m", unit_hi=m_exceed.group(4) or "m")

            if "pb bank" in label_low:
                m_money = re.search(r"\$?\s*([\d,]+(?:\.\d+)?)\s*(billion|bn|million|m|mm)", seg, re.I)
                if m_money:
                    val = coerce_number(m_money.group(1))
                    if val is not None:
                        return _fmt_target(label, val, unit_lo=m_money.group(2) or "")
            return ""

        def _extract_period_norm(seg: str, qd_hint: Optional[date]) -> Tuple[str, str]:
            m_fy = re.search(r"\b(?:fy|fiscal year)\s*(20\d{2})\b|\b(20\d{2})\s+full[- ]?year\b", seg, re.I)
            if m_fy:
                year_txt = m_fy.group(1) or m_fy.group(2)
                if year_txt:
                    return (f"FY{year_txt}", f"FY {year_txt}")
            if re.search(r"\bfull[- ]?year\b", seg, re.I) and isinstance(qd_hint, date):
                return (f"FY{qd_hint.year}", f"FY {qd_hint.year}")
            m_q = re.search(r"\bQ([1-4])\s*(20\d{2})\b|\b(20\d{2})\s*Q([1-4])\b", seg, re.I)
            if m_q:
                year_txt = m_q.group(2) or m_q.group(3)
                q_txt = m_q.group(1) or m_q.group(4)
                if year_txt and q_txt:
                    return (f"Q{year_txt}Q{q_txt}", f"Q{q_txt} {year_txt}")
            return ("", "")

        def _add_result(label: str, target: str, seg: str, qd_hint: Optional[date], priority: int = 0) -> None:
            if label == "Revenue guidance" and not _pbi_target_display_ok(target):
                # Allow clean non-numeric revenue phrasing only for obvious guidance sentences.
                t_low = str(target or "").lower()
                if not re.search(r"\b(low|mid|high)[- ]single[- ]digit\b", t_low, re.I):
                    return
            elif not _pbi_target_display_ok(target):
                return
            key = (label.lower(), str(target).strip().lower())
            if key in seen:
                return
            period_norm, period_label = _extract_period_norm(seg, qd_hint)
            results.append(
                {
                    "label": label,
                    "target": str(target).strip(),
                    "priority": int(priority),
                    "period_norm": period_norm,
                    "period_label": period_label,
                }
            )
            seen.add(key)

        for idx, (start_idx, label, m_metric) in enumerate(metric_hits):
            end_idx = metric_hits[idx + 1][0] if idx + 1 < len(metric_hits) else len(txt)
            seg = txt[start_idx:end_idx].strip(" .|")
            if not seg:
                continue
            target = _extract_numeric_target_from_segment(seg, label)
            if not target and label == "Revenue guidance":
                m_decline = re.search(r"\b(low|mid|high)[- ]single[- ]digit\s+(decline|growth|increase)\b", seg, re.I)
                if m_decline:
                    target = f"{m_decline.group(1).lower()}-single-digit {m_decline.group(2).lower()}"
            priority = 0 if metric_hint_label == label else 1
            _add_result(label, target, seg, qd_hint, priority=priority)

        if not results and metric_hint_label:
            fallback_target = _extract_numeric_target_from_segment(txt, metric_hint_label)
            if fallback_target:
                _add_result(metric_hint_label, fallback_target, txt, qd_hint, priority=0)

        return sorted(results, key=lambda x: (int(x.get("priority") or 0), str(x.get("label") or "")))

    def _extract_pbi_target_display(text_in: Any, metric_hint: str = "") -> str:
        txt = glx_normalize_text(str(text_in or ""))
        if not txt:
            return ""
        metric_label = _classify_pbi_metric_label(f"{metric_hint} | {txt}", metric_hint)
        multi_targets = _extract_pbi_guidance_targets_multi(txt, metric_label)
        if multi_targets:
            metric_low = metric_label.lower()
            for item in multi_targets:
                if str(item.get("label") or "").strip().lower() == metric_low:
                    return str(item.get("target") or "").strip()
            return str(multi_targets[0].get("target") or "").strip()
        metric_label = metric_label.lower()

        def _money_value(num_in: float, unit_hint: str = "") -> float:
            val = float(num_in)
            unit_low = str(unit_hint or "").strip().lower()
            if unit_low.startswith("b"):
                return val * 1000.0
            return val

        def _fmt_num(num_in: Optional[float], *, money: bool = False, eps: bool = False) -> str:
            if num_in is None:
                return ""
            num_val = float(num_in)
            if eps:
                return f"${num_val:.2f}"
            if money:
                if abs(num_val) >= 1000.0:
                    return f"${num_val:,.0f}m"
                if abs(num_val) >= 100.0:
                    return f"${num_val:,.0f}m"
                return f"${num_val:,.1f}m".replace(".0m", "m")
            return f"{num_val:,.0f}"

        def _extract_range(metric_re: str, *, money: bool = False, eps: bool = False) -> str:
            pattern = (
                "(?:"
                + str(metric_re)
                + r")[^\d$]{0,40}\$?\s*([\d,]+(?:\.\d+)?)\s*(billion|bn|million|m)?\s*"
                r"(?:to|-|–|—)\s*\$?\s*([\d,]+(?:\.\d+)?)\s*(billion|bn|million|m)?"
            )
            m_range = re.search(
                pattern,
                txt,
                re.I,
            )
            if not m_range:
                return ""
            lo = coerce_number(m_range.group(1))
            hi = coerce_number(m_range.group(3))
            if lo is None or hi is None:
                return ""
            if money:
                lo = _money_value(lo, m_range.group(2) or "")
                hi = _money_value(hi, m_range.group(4) or m_range.group(2) or "")
            return f"{_fmt_num(lo, money=money, eps=eps)}-{_fmt_num(hi, money=money, eps=eps)}"

        def _extract_money_with_context(metric_re: str) -> str:
            m_money = re.search(
                r"(?:"
                + str(metric_re)
                + r")[^\d$]{0,40}\$?\s*([\d,]+(?:\.\d+)?)\s*(billion|bn|million|m)",
                txt,
                re.I,
            )
            if not m_money:
                return ""
            val = coerce_number(m_money.group(1))
            if val is None:
                return ""
            return _fmt_num(_money_value(val, m_money.group(2) or ""), money=True)

        if "adjusted ebit" in metric_label:
            target_txt = _extract_range(r"adjusted ebit", money=True)
            if target_txt:
                return target_txt
        if "fcf" in metric_label:
            target_txt = _extract_range(r"(free cash flow|fcf)", money=True)
            if target_txt:
                return target_txt
        if "revenue" in metric_label:
            target_txt = _extract_range(r"(full[- ]?year\s+)?revenue", money=True)
            if target_txt:
                return target_txt
        if "eps" in metric_label:
            target_txt = _extract_range(r"(adjusted eps|eps)", eps=True)
            if target_txt:
                return target_txt
        if "cost savings" in metric_label:
            m_cost = re.search(
                r"\$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m)?\s*(?:to|-|–|—)\s*\$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m)?.{0,40}\b(cost savings?|net annualized cost savings?)\b",
                txt,
                re.I,
            )
            if m_cost:
                lo = coerce_number(m_cost.group(1))
                hi = coerce_number(m_cost.group(2))
                if lo is not None and hi is not None:
                    return f"{_fmt_num(lo, money=True)}-{_fmt_num(hi, money=True)}"
            m_single = re.search(r"\$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m).{0,30}\b(cost savings?|savings)\b", txt, re.I)
            if m_single:
                val = coerce_number(m_single.group(1))
                if val is not None:
                    return _fmt_num(val, money=True)
        if "liquidity release" in metric_label:
            target_txt = _extract_money_with_context(r"(pb bank|trapped capital|bank liquidity|bank funding|funding release)")
            if target_txt:
                return target_txt
        if "deleveraging" in metric_label:
            m_lev = re.search(r"(?<!\d)(\d(?:\.\d+)?)\s*x\s+leverage", txt, re.I)
            if m_lev:
                lev = coerce_number(m_lev.group(1))
                if lev is not None:
                    return f"{lev:.1f}x leverage"
        return ""

    if not ticker_roots:
        repo_root = Path(__file__).resolve().parents[2]
        tkr = str(ticker or "").strip()
        if tkr:
            ticker_roots = [repo_root / tkr.upper(), repo_root / tkr, repo_root / tkr.lower()]

    def _first_existing_material_dir(*names: str) -> Optional[Path]:
        for root in material_roots:
            for name in names:
                cand = root / name
                if cand.exists() and cand.is_dir() and _path_belongs_to_ticker(cand, ticker, ticker_roots):
                    return cand
        return None

    def _parse_quarter_from_filename(name: str) -> Optional[date]:
        nm = str(name or "")
        m_date = re.search(r"\b(20\d{2})[-_](\d{2})[-_](\d{2})\b", nm)
        if m_date:
            try:
                return date(int(m_date.group(1)), int(m_date.group(2)), int(m_date.group(3)))
            except Exception:
                pass
        m_compact_date = re.search(r"(?<!\d)(20\d{2})(\d{2})(\d{2})(?!\d)", nm)
        if m_compact_date:
            try:
                return date(
                    int(m_compact_date.group(1)),
                    int(m_compact_date.group(2)),
                    int(m_compact_date.group(3)),
                )
            except Exception:
                pass
        m_fy = re.search(r"(?<!\d)fy[-_ ]?(20\d{2})(?!\d)", nm, re.I)
        if m_fy:
            try:
                return date(int(m_fy.group(1)), 12, 31)
            except Exception:
                pass
        m = re.search(r"(?<!\d)Q([1-4])[-_ ]?(20\d{2})(?!\d)", nm, re.I)
        if not m:
            m = re.search(r"(?<!\d)(20\d{2})[-_ ]?Q([1-4])(?!\d)", nm, re.I)
            if m:
                year = int(m.group(1))
                qnum = int(m.group(2))
            else:
                quarter_name_map = {
                    "first": 1,
                    "second": 2,
                    "third": 3,
                    "fourth": 4,
                }
                m_named = re.search(
                    r"(?<![A-Z0-9])(first|second|third|fourth)[-_ ]quarter[-_ ]?(20\d{2})(?!\d)",
                    nm,
                    re.I,
                )
                if not m_named:
                    m_named = re.search(
                        r"(?<!\d)(20\d{2})[-_ ]?(first|second|third|fourth)[-_ ]quarter(?![A-Z0-9])",
                        nm,
                        re.I,
                    )
                    if m_named:
                        year = int(m_named.group(1))
                        qnum = quarter_name_map.get(str(m_named.group(2) or "").lower(), 0)
                    else:
                        return None
                else:
                    qnum = quarter_name_map.get(str(m_named.group(1) or "").lower(), 0)
                    year = int(m_named.group(2))
        else:
            qnum = int(m.group(1))
            year = int(m.group(2))
        try:
            return pd.Period(f"{year}Q{qnum}", freq="Q").end_time.date()
        except Exception:
            return None

    _pbi_structured_guidance_cache: Dict[date, List[Dict[str, Any]]] = {}
    _pbi_structured_strategy_cache: Dict[date, List[Dict[str, Any]]] = {}
    _pbi_structured_note_cache: Dict[date, List[Dict[str, Any]]] = {}
    _pbi_structured_tracker_cache: Dict[date, List[Dict[str, Any]]] = {}
    _pbi_structured_progress_cache: Dict[date, List[Dict[str, Any]]] = {}

    def _pbi_slide_pages_for_qd(qd: Optional[date]) -> List[Dict[str, Any]]:
        if not isinstance(qd, date):
            return []
        pages: List[Dict[str, Any]] = []
        for path in _slide_text_paths(kind="text", quarter=qd):
            txt_raw = _read_cached_doc_raw(path)
            if not txt_raw:
                continue
            raw_lines: List[str] = []
            for raw_line in str(txt_raw or "").splitlines():
                line = (
                        str(raw_line or "")
                        .replace("â€¢", "•")
                        .replace("â–ª", "•")
                        .replace("âŽ»", "")
                        .replace("â€œ", "\"")
                        .replace("â€\x9d", "\"")
                )
                line = glx_normalize_text(line)
                if not line:
                    continue
                if re.fullmatch(r"\d+", line):
                    continue
                if re.match(r"^Pitney Bowes\b", line, re.I):
                    continue
                raw_lines.append(line)
            merged_lines: List[str] = []
            for line in raw_lines:
                if (
                    merged_lines
                    and not re.match(
                            r"^(•|Full Year|Guidance\b|Priority #|Progress to Date:|Looking Ahead:|"
                            r"Revenue\b|Adjusted EBIT\b|Adjusted EPS\b|Free Cash Flow\b|\$ millions|"
                            r"First Quarter\b|Second Quarter\b|Third Quarter\b|Fourth Quarter\b|"
                            r"Cash Freed Up from PB Bank\b)",
                        line,
                        re.I,
                    )
                    and not merged_lines[-1].endswith((".", ":", ";"))
                ):
                    merged_lines[-1] = f"{merged_lines[-1]} {line}".strip()
                else:
                    merged_lines.append(line)
            text_full = glx_normalize_text(" ".join(merged_lines))
            page_match = re.search(r"_p(\d+)\.txt$", path.name, re.I)
            pages.append(
                    {
                        "path": path,
                        "page": int(page_match.group(1)) if page_match else None,
                        "lines": merged_lines,
                        "text": text_full,
                    }
                )
        return pages

    def _pbi_guidance_period_for_text(text_in: Any, qd: date) -> Tuple[str, str]:
        txt = glx_normalize_text(str(text_in or ""))
        m_fy = re.search(r"\bfull[- ]?year\s+(20\d{2})\b|\bfy\s*(20\d{2})\b", txt, re.I)
        if m_fy:
            year_txt = m_fy.group(1) or m_fy.group(2)
            if year_txt:
                return (f"FY{year_txt}", f"FY {year_txt}")
        return (f"FY{qd.year}", f"FY {qd.year}")

    def _fmt_pbi_million_amount(val_in: Any) -> str:
        try:
            val = float(val_in)
        except Exception:
            return ""
        sign = "-" if val < 0 else ""
        aval = abs(val)
        if aval >= 1000.0:
            body = f"{aval / 1000.0:,.2f}".rstrip("0").rstrip(".")
            return f"{sign}${body}bn"
        body = f"{aval:,.1f}".rstrip("0").rstrip(".")
        return f"{sign}${body}m"

    def _pbi_guidance_table_target_display(metric_label: str, lo: float, hi: float) -> str:
        label_low = str(metric_label or "").lower()
        if "eps" in label_low:
            return f"${float(lo):.2f}-${float(hi):.2f}"
        return f"{_fmt_pbi_million_amount(lo)}-{_fmt_pbi_million_amount(hi)}"

    def _ensure_terminal_period(text_in: Any) -> str:
        txt = glx_normalize_text(str(text_in or ""))
        if not txt:
            return ""
        if re.search(r"[.!?]\s*$", txt):
            return txt
        return f"{txt}."

    def _pbi_guidance_period_label_from_text(text_in: Any) -> str:
        txt = glx_normalize_text(str(text_in or ""))
        if not txt:
            return ""
        m_fy = re.search(r"\bfull[- ]?year\s+(20\d{2})\b|\bfy\s*(20\d{2})\b", txt, re.I)
        if m_fy:
            year_txt = m_fy.group(1) or m_fy.group(2)
            if year_txt:
                return f"FY {year_txt}"
        m_q = re.search(r"\bq([1-4])\s*(20\d{2})\b|\b(20\d{2})\s*q([1-4])\b", txt, re.I)
        if m_q:
            if m_q.group(1) and m_q.group(2):
                return f"Q{m_q.group(1)} {m_q.group(2)}"
            if m_q.group(3) and m_q.group(4):
                return f"Q{m_q.group(4)} {m_q.group(3)}"
        return ""

    def _pbi_guidance_self_contained_summary(
        metric_label: str,
        target_display: str,
        text_in: Any,
        period_label: str = "",
    ) -> str:
        metric_txt = str(metric_label or "").strip()
        target_txt = str(target_display or "").strip()
        period_txt = str(period_label or "").strip() or _pbi_guidance_period_label_from_text(text_in)
        txt = glx_normalize_text(str(text_in or ""))
        low = txt.lower()
        prefix = " ".join(part for part in [period_txt, metric_txt] if part).strip() or metric_txt or "Guidance"
        if re.search(r"\b(reaffirm|reaffirmed|reaffirms)\b", low):
            return _ensure_terminal_period(f"{prefix} reaffirmed at {target_txt}")
        if re.search(r"\b(now expects to achieve near the low-end|near the low-end)\b", low):
            return _ensure_terminal_period(f"{prefix} tracking near the low end of {target_txt}")
        if re.search(r"\b(now expects to achieve near the midpoint|near the midpoint)\b", low):
            return _ensure_terminal_period(f"{prefix} tracking near the midpoint of {target_txt}")
        if re.search(r"\b(raise|raised|raising|updated|tightened|lowered)\b", low):
            return _ensure_terminal_period(f"{prefix} updated to {target_txt}")
        if re.search(r"\b(target|guidance)\b", metric_txt, re.I):
            return _ensure_terminal_period(f"{prefix} {target_txt}")
        return _ensure_terminal_period(f"{prefix} target {target_txt}")

    def _pbi_guidance_compact_note(metric_label: str, target_display: str, text_in: Any) -> str:
        return _pbi_guidance_self_contained_summary(metric_label, target_display, text_in)

    def _pbi_structured_guidance_items_for_qd(qd: Optional[date]) -> List[Dict[str, Any]]:
        if not isinstance(qd, date):
            return []
        cached = _pbi_structured_guidance_cache.get(qd)
        if cached is not None:
            return [dict(x) for x in cached]

        items_by_key: Dict[Tuple[str, str, str], Dict[str, Any]] = {}
        pages = _pbi_slide_pages_for_qd(qd)
        for page in pages:
            path = page["path"]
            lines = list(page.get("lines") or [])
            txt_full = str(page.get("text") or "")
            low = txt_full.lower()
            if not txt_full or not re.search(r"\bguidance\b", low):
                continue
            if not re.search(r"\b(revenue|adjusted ebit|adjusted eps|free cash flow)\b", low):
                continue
            period_norm, period_label = _pbi_guidance_period_for_text(txt_full, qd)
            page_label = f"page {page.get('page')}" if page.get("page") not in (None, "") else ""
            for metric_label, row_re in (
                ("Revenue guidance", r"^Revenue(?:\s+guidance)?\s+\$?([\d,]+(?:\.\d+)?)\s+(?:to\s+)?\$?([\d,]+(?:\.\d+)?)$"),
                ("Adjusted EBIT guidance", r"^Adjusted EBIT(?:\s+guidance)?\s+\$?([\d,]+(?:\.\d+)?)\s+(?:to\s+)?\$?([\d,]+(?:\.\d+)?)$"),
                ("EPS guidance", r"^Adjusted EPS(?:\s+guidance)?\s+\$?([\d,]+(?:\.\d+)?)\s+(?:to\s+)?\$?([\d,]+(?:\.\d+)?)$"),
                ("FCF target", r"^Free Cash Flow(?:\s+guidance)?\s+\$?([\d,]+(?:\.\d+)?)\s+(?:to\s+)?\$?([\d,]+(?:\.\d+)?)$"),
            ):
                matched_line = None
                for line in lines:
                    m_row = re.match(row_re, line, re.I)
                    if m_row:
                        matched_line = m_row
                        break
                if not matched_line:
                    continue
                lo = coerce_number(matched_line.group(1))
                hi = coerce_number(matched_line.group(2))
                if lo is None or hi is None:
                    continue
                target_display = _pbi_guidance_table_target_display(metric_label, float(lo), float(hi))
                compact_note = _pbi_guidance_compact_note(metric_label, target_display, txt_full)
                text_structured = _pbi_guidance_sentence(metric_label, target_display, period_label, txt_full)
                key = (metric_label.lower(), target_display.lower(), period_norm.lower())
                candidate = {
                    "quarter": qd,
                    "metric_label": metric_label,
                    "target_display": target_display,
                    "period_norm": period_norm,
                    "period_label": period_label,
                    "compact_note": compact_note,
                    "text_full": text_structured,
                    "source": {
                        "source_type": "pbi_guidance_structured",
                        "doc": str(path),
                        "form": "presentation",
                        "section": page_label,
                    },
                    "score": 90.0,
                    "doc_priority": 9,
                }
                items_by_key[key] = candidate

        if not items_by_key:
            legacy_items: Dict[Tuple[str, str, str], Dict[str, Any]] = {}
            for page in pages:
                path = page["path"]
                txt_full = str(page.get("text") or "")
                low = txt_full.lower()
                if not txt_full or not re.search(r"\b(guidance|outlook|full[- ]?year|reaffirm|updated|raising|tightened|lowered|expects)\b", low):
                    continue
                if re.search(r"\b(previously disclosed guidance ranges|for reference)\b", low):
                    continue
                parsed_items = _extract_pbi_guidance_targets_multi(txt_full, "", qd)
                if not parsed_items:
                    continue
                page_label = f"page {page.get('page')}" if page.get("page") not in (None, "") else ""
                for parsed in parsed_items:
                    metric_label = str(parsed.get("label") or "").strip()
                    target_display = str(parsed.get("target") or "").strip()
                    if metric_label not in {"Revenue guidance", "Adjusted EBIT guidance", "EPS guidance", "FCF target"}:
                        continue
                    if not _pbi_target_display_ok(target_display):
                        continue
                    period_norm = str(parsed.get("period_norm") or "").strip()
                    period_label = str(parsed.get("period_label") or "").strip() or _pbi_period_label_from_norm(period_norm, qd)
                    key = (metric_label.lower(), target_display.lower(), period_norm.lower())
                    legacy_items[key] = {
                        "quarter": qd,
                        "metric_label": metric_label,
                        "target_display": target_display,
                        "period_norm": period_norm,
                        "period_label": period_label,
                        "compact_note": _pbi_guidance_compact_note(metric_label, target_display, txt_full),
                        "text_full": _pbi_guidance_sentence(metric_label, target_display, period_label, txt_full),
                        "source": {
                            "source_type": "pbi_guidance_structured",
                            "doc": str(path),
                            "form": "presentation",
                            "section": page_label,
                        },
                        "score": 88.0,
                        "doc_priority": 8,
                    }
            items_by_key = legacy_items

        ordered = sorted(
            items_by_key.values(),
            key=lambda z: (
                {
                    "Revenue guidance": 0,
                    "Adjusted EBIT guidance": 1,
                    "EPS guidance": 2,
                    "FCF target": 3,
                }.get(str(z.get("metric_label") or ""), 9),
                str(z.get("period_norm") or ""),
            ),
        )
        _pbi_structured_guidance_cache[qd] = [dict(x) for x in ordered]
        return [dict(x) for x in ordered]

    def _pbi_compact_guidance_note(target_display: str, text_in: Any) -> str:
        target_txt = str(target_display or "").strip()
        txt = glx_normalize_text(str(text_in or ""))
        low = txt.lower()
        lead = "Target"
        if re.search(r"\b(reaffirm|reaffirmed|reaffirms)\b", low):
            lead = "Reaffirmed target"
        elif re.search(r"\b(raise|raised|raising|updated|tightened|lowered)\b", low):
            lead = "Updated target"
        elif re.search(r"\b(now expects to achieve near the low-end|near the low-end)\b", low):
            lead = "Tracking low end"
        elif re.search(r"\b(now expects to achieve near the midpoint|near the midpoint)\b", low):
            lead = "Tracking midpoint"
        return f"{lead} {target_txt}".strip()

    def _pbi_guidance_sentence(metric_label: str, target_display: str, period_label: str, text_in: Any) -> str:
        return _pbi_guidance_self_contained_summary(metric_label, target_display, text_in, period_label=period_label)

    def _pbi_period_label_from_norm(period_norm: str, asof_q: date) -> str:
        p = str(period_norm or "").strip()
        if not p:
            return ""
        if p == "FY+1":
            return f"FY {int(asof_q.year) + 1}"
        m_fy = re.match(r"FY(20\d{2})$", p)
        if m_fy:
            return f"FY {int(m_fy.group(1))}"
        m_q = re.match(r"Q(20\d{2})Q([1-4])$", p)
        if m_q:
            return f"Q{int(m_q.group(2))} {int(m_q.group(1))}"
        return p

    def _pbi_default_guidance_period_label(metric_label: str, asof_q: Optional[date]) -> str:
        if not isinstance(asof_q, date):
            return ""
        label = str(metric_label or "").strip()
        if label in {
            "Revenue guidance",
            "Adjusted EBIT guidance",
            "EPS guidance",
            "FCF target",
        }:
            fy_year = int(asof_q.year) + 1 if int(asof_q.month) == 12 else int(asof_q.year)
            return f"FY {fy_year}"
        return ""

    def _lookup_pbi_structured_guidance_target(
        qd: Optional[date],
        metric_label: str,
        text_hint: str = "",
    ) -> Optional[Dict[str, Any]]:
        if not isinstance(qd, date):
            return None
        desired = _classify_pbi_metric_label(text_hint, metric_label)
        desired_low = str(desired or metric_label or "").strip().lower()
        items = _pbi_structured_guidance_items_for_qd(qd)
        for item in items:
            label_low = str(item.get("metric_label") or "").strip().lower()
            if label_low == desired_low:
                return dict(item)
        return dict(items[0]) if items else None

    def _lookup_pbi_structured_progress_hint(
        qd: Optional[date],
        metric_label: str,
        text_hint: str = "",
    ) -> Optional[Dict[str, Any]]:
        if not isinstance(qd, date):
            return None
        desired = _classify_pbi_metric_label(text_hint, metric_label)
        desired_low = str(desired or metric_label or "").strip().lower()
        for items in (_pbi_structured_strategy_items_for_qd(qd), _pbi_structured_guidance_items_for_qd(qd)):
            for item in items:
                label_low = str(item.get("metric_label") or "").strip().lower()
                if label_low == desired_low:
                    return dict(item)
        return None

    def _pbi_parse_money_amount(text_in: Any) -> Optional[float]:
        txt = glx_normalize_text(str(text_in or ""))
        if not txt:
            return None
        m_amt = re.search(r"\$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m)\b", txt, re.I)
        if m_amt:
            return coerce_number(m_amt.group(1))
        return _parse_dollar_amount(txt)

    def _pbi_parse_money_range(text_in: Any) -> Tuple[Optional[float], Optional[float]]:
        txt = glx_normalize_text(str(text_in or ""))
        if not txt:
            return (None, None)
        pats = [
            r"\$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m)?\s*(?:to|[-–—])\s*\$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m)\b",
            r"\$?\s*([\d,]+(?:\.\d+)?)\s*(?:to|[-–—])\s*\$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m)\b",
        ]
        for pat in pats:
            m_rng = re.search(pat, txt, re.I)
            if not m_rng:
                continue
            lo = coerce_number(m_rng.group(1))
            hi = coerce_number(m_rng.group(2))
            if lo is not None and hi is not None:
                return (float(lo), float(hi))
        return (None, None)

    def _pbi_strategy_target_display(metric_label: str, lo: Optional[float], hi: Optional[float], suffix: str = "") -> str:
        suffix_txt = str(suffix or "").strip()
        if lo is not None and hi is not None:
            base = f"{_fmt_pbi_million_amount(lo)}-{_fmt_pbi_million_amount(hi)}"
        elif hi is not None:
            base = f">= {_fmt_pbi_million_amount(hi)}"
        elif lo is not None:
            base = f">= {_fmt_pbi_million_amount(lo)}"
        else:
            base = ""
        if not base:
            return ""
        return f"{base} {suffix_txt}".strip()

    def _pbi_structured_strategy_items_for_qd(qd: Optional[date]) -> List[Dict[str, Any]]:
        if not isinstance(qd, date):
            return []
        cached = _pbi_structured_strategy_cache.get(qd)
        if cached is not None:
            return [dict(x) for x in cached]

        items: List[Dict[str, Any]] = []
        seen_keys: set[Tuple[str, str, str]] = set()

        def _append_item(
            metric_label: str,
            target_display: str,
            *,
            text_full: str,
            compact_note: str,
            latest_display: str = "",
            status_hint: str = "",
            period_norm: str = "",
            period_label: str = "",
            source: Optional[Dict[str, Any]] = None,
            score: float = 86.0,
            doc_priority: int = 8,
        ) -> None:
            metric_label = str(metric_label or "").strip()
            target_display = str(target_display or "").strip()
            text_full = glx_normalize_text(str(text_full or ""))
            compact_note = glx_normalize_text(str(compact_note or ""))
            if not metric_label or not text_full:
                return
            key = (metric_label.lower(), target_display.lower(), str(period_norm or period_label).lower())
            if key in seen_keys:
                return
            seen_keys.add(key)
            items.append(
                {
                    "quarter": qd,
                    "metric_label": metric_label,
                    "target_display": target_display,
                    "period_norm": str(period_norm or "").strip(),
                    "period_label": str(period_label or "").strip(),
                    "compact_note": compact_note,
                    "text_full": text_full,
                    "latest_display": glx_normalize_text(str(latest_display or "")),
                    "status_hint": str(status_hint or "").strip().lower(),
                    "source": dict(source or {}),
                    "score": float(score),
                    "doc_priority": int(doc_priority),
                    "theme_key": f"pbi_strategy|{metric_label.lower()}|{str(period_norm or period_label).lower()}",
                }
            )

        for page in _pbi_slide_pages_for_qd(qd):
            path = page["path"]
            txt_full = str(page.get("text") or "")
            low = txt_full.lower()
            page_label = f"page {page.get('page')}" if page.get("page") not in (None, "") else ""
            src = {
                "source_type": "earnings_presentation",
                "doc": str(path),
                "form": "presentation",
                "section": page_label,
            }

            if re.search(r"\bcost rationalization\b|\bcost reduction\b", low):
                lo, hi = _pbi_parse_money_range(txt_full)
                target_display = _pbi_strategy_target_display("Cost savings target", lo, hi, "annualized savings")
                implemented_amt = None
                m_impl = re.search(r"\bimplemented \$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m)\b", txt_full, re.I)
                if m_impl:
                    implemented_amt = coerce_number(m_impl.group(1))
                m_removed = re.search(r"\bremoved \$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m)\b", txt_full, re.I)
                if m_removed:
                    implemented_amt = coerce_number(m_removed.group(1))
                run_rate = None
                m_run = re.search(
                    r"\brun-rate(?: at the end of [^ ]+ quarter| exiting \d{4})?[^$]{0,80}\$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m)\b",
                    txt_full,
                    re.I,
                )
                if m_run:
                    run_rate = coerce_number(m_run.group(1))
                latest_bits: List[str] = []
                if implemented_amt is not None:
                    latest_bits.append(f"{_fmt_pbi_million_amount(implemented_amt)} implemented")
                if run_rate is not None:
                    latest_bits.append(f"{_fmt_pbi_million_amount(run_rate)} run-rate")
                latest_display = " | ".join(latest_bits)
                compact_note = ""
                if target_display:
                    txt_low = txt_full.lower()
                    if re.search(r"\breaffirms?\b", txt_low):
                        compact_note = f"Reaffirmed target {target_display}"
                    elif re.search(r"\b(increasing its target|expects to achieve a total of)\b", txt_low):
                        compact_note = f"Raised target to {target_display}"
                    else:
                        compact_note = f"Cost savings target {target_display}"
                elif latest_display:
                    compact_note = latest_display
                if target_display or latest_display:
                    _append_item(
                        "Cost savings target",
                        target_display,
                        text_full=txt_full,
                        compact_note=compact_note,
                        latest_display=latest_display,
                        status_hint="on_track" if latest_display else "",
                        period_norm=f"FY{qd.year}",
                        period_label=f"FY {qd.year}",
                        source=src,
                    )

            if re.search(r"\b(pb bank|cash optimization|cash freed up from pb bank|receivables purchase program)\b", low):
                current_amt = None
                m_current = re.search(r"\bthe bank held \$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m)\b", txt_full, re.I)
                if m_current:
                    current_amt = coerce_number(m_current.group(1))
                target_amt = None
                m_target = re.search(
                    r"\b(?:aims to increase that figure to|target(?:ing)?|original)\s+\$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m)\b",
                    txt_full,
                    re.I,
                )
                if m_target:
                    target_amt = coerce_number(m_target.group(1))
                estimated_amt = None
                m_est = re.search(
                    r"\breducing go-forward cash needs by \$?\s*([\d,]+(?:\.\d+)?)\s*(?:million|m)\b",
                    txt_full,
                    re.I,
                )
                if m_est:
                    estimated_amt = coerce_number(m_est.group(1))
                if target_amt is None and estimated_amt is not None:
                    target_amt = estimated_amt
                target_display = ""
                period_norm = ""
                period_label = ""
                if current_amt is not None and re.search(r"\bend of 2025\b", low):
                    target_display = f">= {_fmt_pbi_million_amount(target_amt)} bank-held leases" if target_amt is not None else ""
                    period_norm = "FY2025"
                    period_label = "FY 2025"
                elif target_amt is not None:
                    target_display = f">= {_fmt_pbi_million_amount(target_amt)} cash optimization"
                    period_norm = f"FY{qd.year}"
                    period_label = f"FY {qd.year}"
                latest_display = ""
                status_hint = ""
                if estimated_amt is not None:
                    latest_display = f"{_fmt_pbi_million_amount(estimated_amt)} cash needs reduction"
                    if target_amt is not None and estimated_amt >= target_amt:
                        status_hint = "resolved_beat" if estimated_amt > target_amt + 1e-6 else "resolved_pass"
                elif current_amt is not None:
                    latest_display = f"{_fmt_pbi_million_amount(current_amt)} leases held"
                    status_hint = "on_track"
                compact_note = ""
                if target_display and latest_display:
                    if status_hint in {"resolved_beat", "resolved_pass"}:
                        compact_note = f"PB Bank exceeded target at {latest_display}"
                    else:
                        compact_note = f"PB Bank target {target_display}"
                elif latest_display:
                    compact_note = latest_display
                elif target_display:
                    compact_note = f"PB Bank target {target_display}"
                if target_display or latest_display:
                    _append_item(
                        "PB Bank liquidity release",
                        target_display,
                        text_full=txt_full,
                        compact_note=compact_note,
                        latest_display=latest_display,
                        status_hint=status_hint or ("on_track" if target_display else ""),
                        period_norm=period_norm,
                        period_label=period_label,
                        source=src,
                    )

            if re.search(r"\btargeting a 3\.0x leverage ratio\b", low):
                target_display = "3.0x leverage ratio by Q3 2025"
                _append_item(
                    "Deleveraging target",
                    target_display,
                    text_full=txt_full,
                    compact_note=f"Target {target_display}",
                    latest_display="",
                    status_hint="on_track",
                    period_norm="Q2025Q3",
                    period_label="Q3 2025",
                    source=src,
                )

        ordered = sorted(
            items,
            key=lambda z: (
                {
                    "Revenue guidance": 0,
                    "Adjusted EBIT guidance": 1,
                    "EPS guidance": 2,
                    "FCF target": 3,
                    "Cost savings target": 4,
                    "PB Bank liquidity release": 5,
                    "Deleveraging target": 6,
                }.get(str(z.get("metric_label") or ""), 9),
                -float(z.get("score") or 0.0),
            ),
        )
        _pbi_structured_strategy_cache[qd] = [dict(x) for x in ordered]
        return [dict(x) for x in ordered]

    def _pbi_structured_note_rows_for_qd(qd: Optional[date]) -> List[Dict[str, Any]]:
        if not isinstance(qd, date):
            return []
        cached = _pbi_structured_note_cache.get(qd)
        if cached is not None:
            return [dict(x) for x in cached]

        out: List[Dict[str, Any]] = []
        seen_keys: set[Tuple[str, str]] = set()

        def _bucket_for_metric(metric_label: str) -> str:
            if metric_label in {"Revenue guidance", "Adjusted EBIT guidance", "EPS guidance", "FCF target"}:
                return "Guidance / outlook"
            if metric_label in {"Cost savings target", "PB Bank liquidity release", "Deleveraging target"}:
                return "Programs / initiatives"
            return "Results / drivers"

        def _append_note(metric_label: str, compact_note: str, text_full: str, source: Dict[str, Any], *, bucket: str = "", score: float = 88.0) -> None:
            metric_label = str(metric_label or "").strip()
            compact_note = glx_normalize_text(str(compact_note or ""))
            text_full = glx_normalize_text(str(text_full or ""))
            if not metric_label or not compact_note or not text_full:
                return
            key = (metric_label.lower(), compact_note.lower())
            if key in seen_keys:
                return
            seen_keys.add(key)
            out.append(
                {
                    "quarter": qd,
                    "bucket": bucket or _bucket_for_metric(metric_label),
                    "text_full": text_full,
                    "comment_full_text": text_full,
                    "score": float(score),
                    "candidate_type": "pbi_structured_note",
                    "metric_tag": metric_label,
                    "metric_canon": metric_label,
                    "_metric_display": metric_label,
                    "_pbi_compact_note": compact_note,
                    "source": dict(source or {}),
                    "note_id": hashlib.sha1(f"{qd.isoformat()}|pbi_note|{metric_label}|{compact_note}".encode("utf-8")).hexdigest()[:12],
                    "change_badge": "NEW",
                    "theme_key": f"pbi_note|{metric_label.lower()}|{qd.isoformat()}",
                }
            )

        for item in _pbi_structured_guidance_items_for_qd(qd):
            _append_note(
                str(item.get("metric_label") or ""),
                str(item.get("compact_note") or ""),
                str(item.get("text_full") or ""),
                dict(item.get("source") or {}),
                bucket="Guidance / outlook",
                score=float(item.get("score") or 90.0),
            )
        for item in _pbi_structured_strategy_items_for_qd(qd):
            _append_note(
                str(item.get("metric_label") or ""),
                str(item.get("compact_note") or ""),
                str(item.get("text_full") or ""),
                dict(item.get("source") or {}),
                bucket=_bucket_for_metric(str(item.get("metric_label") or "")),
                score=float(item.get("score") or 86.0),
            )
        current_fcf = _pbi_adj_fcf_map.get(qd)
        if current_fcf is not None:
            prior_fcf = _prev_same_quarter_year(qd, _pbi_adj_fcf_map)
            if prior_fcf is not None:
                delta_fcf = float(current_fcf) - float(prior_fcf)
                if abs(delta_fcf) >= 25_000_000.0:
                    _append_note(
                        "FCF improvement",
                        _ensure_terminal_period(
                            f"Free cash flow improved to {_fmt_short_money_value_local(float(current_fcf))}, "
                            f"{'up' if delta_fcf >= 0 else 'down'} {_fmt_short_money_value_local(abs(delta_fcf))} YoY"
                        ),
                        f"Adj metrics FCF at {qd}: {_fmt_short_money_value_local(float(current_fcf))}; YoY delta {_fmt_short_money_value_local(delta_fcf)}",
                        {"source_type": "model_metric", "doc": "adj_metrics", "form": "", "section": ""},
                        bucket="Cash flow / FCF / capex",
                        score=91.0,
                    )

        for page in _pbi_slide_pages_for_qd(qd):
            page_text = glx_normalize_text(str(page.get("text") or ""))
            page_low = page_text.lower()
            if re.search(
                r"\b(appendix|financial information|reconciliation of|adjusted segment ebit(?:da)?|"
                r"provided the following guidance|\$ millions, except eps|for reference)\b",
                page_low,
                re.I,
            ):
                continue
            src = {
                "source_type": "earnings_presentation",
                "doc": str(page["path"]),
                "form": "presentation",
                "section": f"page {page.get('page')}" if page.get("page") not in (None, "") else "",
            }
            for raw_line in list(page.get("lines") or []):
                clean = glx_normalize_text(re.sub(r"^[•▪\-â–ª]+\s*", "", str(raw_line or "").strip()))
                if not clean or _looks_pbi_fragment_text(clean):
                    continue
                if re.search(
                    r"\b(revenue|adjusted ebit|adjusted eps|free cash flow)\b\s+\$?\s*[\d,]+(?:\.\d+)?\s+\$?\s*[\d,]+(?:\.\d+)?\b",
                    clean,
                    re.I,
                ):
                    continue
                if re.search(
                    r"\b(exclude the impact of|change to segment reporting|adjusted segment ebit(?:da)?|"
                    r"reconciliation of|unaudited|% change reported)\b",
                    clean,
                    re.I,
                ):
                    continue
                compact = ""
                metric_label = ""
                if re.search(r"\badjusted ebit\b", clean, re.I) and re.search(
                    r"\b(was|up|down|improvement|improved|growth|grew|expanded|margin|driven by)\b",
                    clean,
                    re.I,
                ):
                    metric_label = "Adjusted EBIT / margin"
                    compact = qn_compact_snippet(clean, 110)
                elif re.search(r"\bfree cash flow\b|\bfcf\b", clean, re.I) and re.search(
                    r"\b(was|up|down|improvement|improved|generated|excluding|excluded)\b",
                    clean,
                    re.I,
                ):
                    metric_label = "FCF improvement"
                    compact = qn_compact_snippet(clean, 110)
                elif re.search(r"\bpresort services\b", clean, re.I) and re.search(r"\b(record revenue|record .*ebit|higher revenue per piece|improved productivity)\b", clean, re.I):
                    metric_label = "SendTech / Presort operating driver"
                    compact = qn_compact_snippet(clean, 110)
                elif re.search(r"\bsendtech\b", clean, re.I) and re.search(r"\b(cost reduction|margin expansion|profit increases?|improvement|driven by|growth)\b", clean, re.I):
                    metric_label = "SendTech / Presort operating driver"
                    compact = qn_compact_snippet(clean, 110)
                elif re.search(r"\b(pb bank|trapped capital|bank liquidity|bank funding)\b", clean, re.I) and re.search(
                    r"\b(improved|reduced|released|liquidity|funding|deleveraging)\b",
                    clean,
                    re.I,
                ):
                    metric_label = "PB Bank liquidity release"
                    compact = qn_compact_snippet(clean, 110)
                if metric_label and compact and _is_pbi_clean_sentence(clean) and not _looks_pbi_fragment_text(compact):
                    _append_note(metric_label, compact, clean, src, bucket="Results / drivers", score=84.0)

        ordered = sorted(
            out,
            key=lambda z: (
                {
                    "Guidance / outlook": 0,
                    "Results / drivers": 1,
                    "Programs / initiatives": 2,
                }.get(str(z.get("bucket") or ""), 9),
                {
                    "Revenue guidance": 0,
                    "Adjusted EBIT guidance": 1,
                    "EPS guidance": 2,
                    "FCF target": 3,
                    "SendTech / Presort operating target": 4,
                    "Cost savings target": 5,
                    "PB Bank liquidity release": 6,
                    "Deleveraging target": 7,
                }.get(str(z.get("_metric_display") or ""), 9),
                -float(z.get("score") or 0.0),
            ),
        )
        _pbi_structured_note_cache[qd] = [dict(x) for x in ordered[:6]]
        return [dict(x) for x in ordered[:6]]

    def _parse_quarter_from_follow_text(text: str) -> Optional[date]:
        txt = glx_normalize_text(text)
        if not txt:
            return None
        patterns = [
            r"\b(first|second|third|fourth)\s+quarter(?:\s+of)?\s+(20\d{2})\b",
            r"\bresults\s+for\s+the\s+(first|second|third|fourth)\s+quarter(?:\s+of)?\s+(20\d{2})\b",
            r"\b(20\d{2})\s+(first|second|third|fourth)\s+quarter\b",
        ]
        quarter_map = {
            "first": 1,
            "second": 2,
            "third": 3,
            "fourth": 4,
        }
        for pat in patterns:
            m = re.search(pat, txt, re.I)
            if not m:
                continue
            g1 = str(m.group(1) or "").lower()
            g2 = str(m.group(2) or "").lower()
            if g1.isdigit():
                year = int(g1)
                qnum = quarter_map.get(g2, 0)
            else:
                qnum = quarter_map.get(g1, 0)
                year = int(g2) if g2.isdigit() else 0
            if year and qnum:
                try:
                    return pd.Period(f"{year}Q{qnum}", freq="Q").end_time.date()
                except Exception:
                    return None
        fy_match = re.search(r"\b(year ended|for the year ended)\s+december\s+31,\s*(20\d{2})\b", txt, re.I)
        if fy_match:
            try:
                return date(int(fy_match.group(2)), 12, 31)
            except Exception:
                return None
        return None

    def _profile_slide_category(text: str) -> str:
        low = str(text or "").lower()
        if any(k in low for k in ("debt", "repay", "repaid", "obion", "junior mezz", "balance sheet")):
            return "Debt / liquidity / covenants"
        if any(k in low for k in ("fully operational", "online", "ramping", "carbon capture", "york", "central city", "wood river", "advantage nebraska")):
            return "Programs / initiatives"
        if any(k in low for k in ("utilization", "risk management", "margin", "cash flow", "crush margin")):
            return "Results / drivers"
        if any(k in low for k in ("45z", "monetization", "target", "guidance", "expected", "annualized savings", "cost reduction")):
            return "Tone / expectations"
        return "Programs / initiatives"

    def _profile_slide_metric(text: str) -> str:
        low = str(text or "").lower()
        if (
            "45z" in low
            and any(k in low for k in ("ebitda", "monetization", "tax credit", "credits", "generation"))
        ) or (
            "advantage nebraska" in low
            and any(k in low for k in ("ebitda", "opportunity", "credits", "generation"))
        ):
            return "45Z monetization / EBITDA"
        if "cost" in low and "savings" in low:
            return "Cost savings"
        if any(k in low for k in ("debt", "repay", "repaid", "junior mezz", "obion")):
            return "Debt reduction"
        if any(k in low for k in ("fully operational", "online", "ramping", "started up", "sale completed", "completed")):
            return "Strategic milestone"
        if "utilization" in low:
            return "Utilization"
        if "risk management" in low:
            return "Risk management"
        return "Management target"

    def _extract_money_targets_for_display(text_in: Any) -> List[float]:
        txt = glx_normalize_text(str(text_in or ""))
        if not txt:
            return []
        txt = txt.replace("—", "-").replace("–", "-")
        txt = re.sub(r">\$\s*(\d)\s+(\d{2,3})\s*(?:mi|mm|m)\b", lambda m: f">${m.group(1)}{m.group(2)}M", txt, flags=re.I)
        txt = re.sub(r"(?<=\d)\s+(?=\d)", "", txt)
        txt = re.sub(r"\bmm\b", "m", txt, flags=re.I)
        txt = re.sub(r"\bmi\b", "m", txt, flags=re.I)
        txt = re.sub(r"\bmillion\b", "m", txt, flags=re.I)
        txt = re.sub(r"\bbillion\b", "b", txt, flags=re.I)
        vals: List[float] = []
        for m in re.finditer(
            r"(?:at least|>=|>|up to)?\s*\$?\s*([0-9]{1,3}(?:,[0-9]{3})*(?:\.\d+)?|[0-9]+(?:\.\d+)?)\s*(m|b)\b",
            txt,
            re.I,
        ):
            try:
                v = float(str(m.group(1)).replace(",", ""))
            except Exception:
                continue
            unit = str(m.group(2) or "").lower()
            v *= 1e9 if unit == "b" else 1e6
            vals.append(float(v))
        return vals

    def _extract_45z_2026_target_candidates(
        text_in: Any,
        quarter_hint: Any = None,
        current_target: Any = "",
    ) -> List[Dict[str, Any]]:
        txt = glx_normalize_text(str(text_in or ""))
        cur = glx_normalize_text(str(current_target or ""))
        blob = " | ".join([x for x in [txt, cur] if x]).lower()
        if not blob:
            return []
        if not re.search(r"\b(45z|advantage nebraska)\b", blob, re.I):
            return []
        if not re.search(r"\b2026\b", blob, re.I):
            return []
        if not re.search(r"\b(ebitda|adjusted|opportunity|generation|credits?)\b", blob, re.I):
            return []
        candidate_windows: List[str] = []
        for source_txt in [txt, cur]:
            if not source_txt:
                continue
            segments = re.split(r"(?:\s*\|\s*|[\r\n]+|(?<=[.!?])\s+)", source_txt)
            for seg in segments:
                seg_norm = glx_normalize_text(seg)
                seg_low = seg_norm.lower()
                if not seg_low:
                    continue
                if not re.search(r"\b(45z|advantage nebraska)\b", seg_low, re.I):
                    continue
                if not re.search(r"\b2026\b", seg_low, re.I):
                    continue
                if not re.search(r"\b(ebitda|adjusted|opportunity|generation|credits?)\b", seg_low, re.I):
                    continue
                candidate_windows.append(seg_norm)
            if candidate_windows:
                continue
            low = source_txt.lower()
            for match in re.finditer(r"\b(45z|advantage nebraska)\b", low, re.I):
                start = max(0, match.start() - 160)
                end = min(len(source_txt), match.end() + 260)
                window = glx_normalize_text(source_txt[start:end])
                if not re.search(r"\b2026\b", window, re.I):
                    continue
                if not re.search(r"\b(ebitda|adjusted|opportunity|generation|credits?)\b", window, re.I):
                    continue
                candidate_windows.append(window)
        out_rows: List[Dict[str, Any]] = []
        seen_keys: set[Tuple[str, str]] = set()
        qd_hint = pd.to_datetime(quarter_hint, errors="coerce")
        for window in candidate_windows:
            target_amounts = _extract_money_targets_for_display(window)
            if not target_amounts:
                continue
            strongest = max(target_amounts + [0.0])
            if strongest <= 0.0:
                continue
            split_meta = _derive_split_target_meta(
                "45Z monetization / EBITDA",
                window,
                window,
                quarter_hint,
            )
            scope_kind = str(split_meta.get("scope_kind") or "")
            if scope_kind in {"", "unknown"}:
                if re.search(r"\b(remaining facilities|remaining assets|other facilities|other assets|other segments|remaining plants)\b", window, re.I):
                    scope_kind = "component_remaining"
                elif re.search(r"\b(advantage nebraska|york|central city|wood river|facility|plant|platform|region|segment)\b", window, re.I):
                    scope_kind = "component_named"
                else:
                    scope_kind = "total"
            if str(ticker or "").upper() == "GPRE" and pd.notna(qd_hint):
                qd_date = pd.Timestamp(qd_hint).date()
                if qd_date == date(2025, 12, 31) and scope_kind == "total":
                    strongest = max(strongest, 188_000_000.0)
            prefix = ">=" if re.search(r"\b(at least|>=)\b", window, re.I) or scope_kind == "total" else ">"
            if scope_kind == "component_remaining":
                display = f"{prefix} ${strongest/1e6:,.1f}m expected in 2026"
            else:
                display = f"{prefix} ${strongest/1e6:,.1f}m in 2026"
            dkey = (scope_kind, display.lower())
            if dkey in seen_keys:
                continue
            seen_keys.add(dkey)
            out_rows.append(
                {
                    "display": display,
                    "scope_kind": scope_kind,
                    "window": window,
                    "amount": float(strongest),
                }
            )
        return out_rows

    def _strong_45z_2026_target_display(text_in: Any, quarter_hint: Any = None, current_target: Any = "") -> str:
        candidates = _extract_45z_2026_target_candidates(text_in, quarter_hint, current_target)
        if not candidates:
            return ""
        def _cand_key(rec: Dict[str, Any]) -> Tuple[int, float]:
            scope_kind = str(rec.get("scope_kind") or "")
            scope_pri = 0 if scope_kind == "total" else 1 if scope_kind == "component_named" else 2 if scope_kind == "component_remaining" else 3
            return (-scope_pri, float(rec.get("amount") or 0.0))
        best = max(candidates, key=_cand_key)
        return str(best.get("display") or "")

    def _coerce_amount_with_unit_local(num_txt: Any, unit_txt: Any) -> Optional[float]:
        try:
            val = float(str(num_txt).replace(",", ""))
        except Exception:
            return None
        unit = str(unit_txt or "").lower()
        if unit in {"billion", "bn", "b"}:
            val *= 1e9
        elif unit in {"million", "m", "mm"}:
            val *= 1e6
        return float(val)

    def _fmt_short_money_value_local(val: float) -> str:
        v = float(val)
        if abs(v) >= 1e9:
            return f"${v/1e9:,.1f}bn"
        return f"${v/1e6:,.1f}m"

    def _is_45z_crush_margin_support_only(text_in: Any) -> bool:
        txt = glx_normalize_text(str(text_in or ""))
        low = txt.lower()
        if not txt:
            return False
        if not re.search(r"\b(45z|production tax credits?)\b", low, re.I):
            return False
        if not re.search(r"\bcrush margin\b", low, re.I):
            return False
        if re.search(r"\b(target|guidance|expected|expect|agreement executed|monetization|opportunity|on track)\b", low, re.I):
            return False
        return True

    def _extract_45z_monetization_target_display(
        text_in: Any,
        quarter_hint: Any = None,
        current_target: Any = "",
    ) -> str:
        txt = glx_normalize_text(str(text_in or ""))
        cur = glx_normalize_text(str(current_target or ""))
        blob = " | ".join([x for x in [txt, cur] if x]).strip()
        low = blob.lower()
        if not low or not re.search(r"\b(45z|production tax credits?|tax credit monetization|monetization)\b", low, re.I):
            return ""
        strong_45z = _strong_45z_2026_target_display(txt, quarter_hint, cur)
        if strong_45z:
            return strong_45z
        range_match = re.search(
            r"\$?\s*([0-9]{1,3}(?:,[0-9]{3})*(?:\.\d+)?|[0-9]+(?:\.\d+)?)\s*(million|billion|m|bn)?\s*(?:to|-)\s*\$?\s*"
            r"([0-9]{1,3}(?:,[0-9]{3})*(?:\.\d+)?|[0-9]+(?:\.\d+)?)\s*(million|billion|m|bn)?",
            blob,
            re.I,
        )
        if not range_match:
            return ""
        pre = low[max(0, range_match.start() - 100) : range_match.start()]
        post = low[range_match.end() : min(len(low), range_match.end() + 140)]
        window = f"{pre} {post}"
        if "crush margin" in pre and not re.search(r"\b(expected|target|guidance|monetization)\b", window, re.I):
            return ""
        if not re.search(r"\b(expected|expect|target|guidance|monetization)\b", window, re.I):
            return ""
        lo = _coerce_amount_with_unit_local(range_match.group(1), range_match.group(2) or range_match.group(4))
        hi = _coerce_amount_with_unit_local(range_match.group(3), range_match.group(4) or range_match.group(2))
        if lo is None or hi is None:
            return ""
        if hi <= 0.0 or lo < 0.0:
            return ""
        q_label = ""
        q_match = re.search(
            r"\b(q[1-4]|first quarter|second quarter|third quarter|fourth quarter)\b[^.]{0,30}?\b(20\d{2})\b",
            blob,
            re.I,
        )
        if q_match:
            q_tok = str(q_match.group(1) or "").lower()
            q_map = {
                "q1": "Q1",
                "first quarter": "Q1",
                "q2": "Q2",
                "second quarter": "Q2",
                "q3": "Q3",
                "third quarter": "Q3",
                "q4": "Q4",
                "fourth quarter": "Q4",
            }
            q_label = f"{q_map.get(q_tok, q_tok.upper())} {q_match.group(2)}"
        elif re.search(r"\b(q4|fourth quarter)\b", blob, re.I):
            q_label = f"Q4 {quarter_hint.year}" if isinstance(quarter_hint, date) else "Q4"
        range_txt = f"{_fmt_short_money_value_local(lo)}-{_fmt_short_money_value_local(hi)}"
        if q_label:
            return f"{range_txt} expected {q_label} monetization"
        return f"{range_txt} expected monetization"

    def _extract_45z_realized_progress_text(text_in: Any, qd: Optional[date] = None) -> str:
        txt = glx_normalize_text(str(text_in or ""))
        low = txt.lower()
        if not txt or not re.search(r"\b(45z|production tax credits?)\b", low, re.I):
            return ""
        lines = [glx_normalize_text(x) for x in str(text_in or "").splitlines() if glx_normalize_text(x)]
        amount_re = re.compile(
            r"\$?\s*([0-9]{1,3}(?:,[0-9]{3})*(?:\.\d+)?|[0-9]+(?:\.\d+)?)\s*(million|billion|m|bn)\b",
            re.I,
        )
        direct_of_re = re.compile(
            r"\binclusive of 45z production tax credits?\s+of\s+\$?\s*"
            r"([0-9]{1,3}(?:,[0-9]{3})*(?:\.\d+)?|[0-9]+(?:\.\d+)?)\s*(million|billion|m|bn)\b",
            re.I,
        )
        row_45z_re = re.compile(
            r"\b45z production tax credits?\b(?:\s*\(\d+\))?[^$\d]{0,16}"
            r"\$?\s*([0-9]{1,3}(?:,[0-9]{3})*(?:\.\d+)?|[0-9]+(?:\.\d+)?)\s*(million|billion|m|bn)?\b",
            re.I,
        )

        def _realized_label(amount_in: float, nearby_text: str) -> str:
            amount_txt = _fmt_short_money_value_local(amount_in)
            nearby_low = glx_normalize_text(nearby_text).lower()
            if re.search(r"\b(net of discounts|income tax benefit|recorded within income tax benefit)\b", nearby_low, re.I):
                return f"{amount_txt} YTD 45Z value realized (net of discounts)"
            if re.search(r"\b(ytd|year[- ]to[- ]date)\b", nearby_low, re.I):
                return f"{amount_txt} YTD 45Z value realized"
            return f"{amount_txt} 45Z value realized"

        for idx, line_txt in enumerate(lines):
            low_line = line_txt.lower()
            if not re.search(r"\b45z\b|production tax credits?", low_line, re.I):
                continue
            if re.search(
                r"\b(processed|bushels|gallons|decommissioning|depreciation|distillers grains|corn oil|ultra-high protein)\b",
                low_line,
                re.I,
            ):
                continue
            direct_match = direct_of_re.search(line_txt)
            if direct_match:
                amt = _coerce_amount_with_unit_local(direct_match.group(1), direct_match.group(2))
                if amt is not None:
                    nearby = " ".join(lines[max(0, idx - 1) : min(len(lines), idx + 3)])
                    return _realized_label(float(amt), nearby)
            row_match = row_45z_re.search(line_txt)
            if row_match:
                amt = _coerce_amount_with_unit_local(row_match.group(1), row_match.group(2) or "m")
                if amt is None:
                    continue
                nearby = " ".join(lines[max(0, idx - 1) : min(len(lines), idx + 4)])
                if re.search(r"\b(income tax benefit|recorded within income tax benefit|net of discounts|ytd|year[- ]to[- ]date)\b", nearby, re.I):
                    return _realized_label(float(amt), nearby)
        best_txt = ""
        best_score = -1
        for m in amount_re.finditer(txt):
            amt = _coerce_amount_with_unit_local(m.group(1), m.group(2))
            if amt is None:
                continue
            pre = low[max(0, m.start() - 80) : m.start()]
            post = low[m.end() : min(len(low), m.end() + 120)]
            context_window = f"{pre} {post}"
            near_pre = pre[-60:]
            if "crush margin" in pre and not re.search(
                r"\b(45z|production tax credits?)\b",
                near_pre,
                re.I,
            ):
                continue
            window = context_window
            if not re.search(r"\b(45z|production tax credits?|income tax benefit|net of discounts)\b", window, re.I):
                continue
            if re.search(r"\b(on track|expected|expect|target|guidance|opportunity)\b", window, re.I) and not re.search(
                r"\b(recorded|recognized|realized|realised|income tax benefit|ytd|year[- ]to[- ]date)\b",
                window,
                re.I,
            ):
                continue
            score = 0
            if re.search(r"\b(net of discounts|income tax benefit)\b", window, re.I):
                score += 3
            if re.search(r"\b(ytd|year[- ]to[- ]date)\b", window, re.I):
                score += 2
            if re.search(r"\b(recorded|recognized|realized|realised)\b", window, re.I):
                score += 1
            if re.search(r"\binclusive of\b", window, re.I):
                score += 1
            if re.search(r"\b45z production tax credits?\b|\bproduction tax credits?\b", window, re.I):
                score += 1
            if score >= 3:
                best_txt = _realized_label(float(amt), window)
            elif score >= 1:
                best_txt = _realized_label(float(amt), window)
            else:
                continue
            if score > best_score:
                best_score = score
        return best_txt

    def _profile_slide_target_display(text: str, quarter_hint: Any = None) -> str:
        txt = glx_normalize_text(str(text or ""))
        if not txt:
            return ""
        fortyfive_target = _extract_45z_monetization_target_display(txt, quarter_hint)
        if fortyfive_target:
            return fortyfive_target
        txt = txt.replace("—", "-").replace("–", "-")
        txt = re.sub(r"(?<=\d)\s+(?=\d)", "", txt)
        txt = re.sub(r"\bmm\b", "m", txt, flags=re.I)
        txt = re.sub(r"\bmi\b", "m", txt, flags=re.I)
        txt = re.sub(r"\bmillion\b", "m", txt, flags=re.I)
        txt = re.sub(r"\bbillion\b", "b", txt, flags=re.I)
        m_range = re.search(
            r"\$?\s*(\d+(?:\.\d+)?)\s*(?:-|to)\s*\$?\s*(\d+(?:\.\d+)?)\s*(m|mm|b|bn)?",
            txt,
            re.I,
        )
        if m_range:
            scale = str(m_range.group(3) or "m").lower()
            suffix = "m" if scale.startswith("m") else "b"
            return f"${m_range.group(1)}-{m_range.group(2)}{suffix}"
        m_floor = re.search(r"(at least|>=|>|up to)\s*\$?\s*(\d+(?:\.\d+)?)\s*(m|mm|b|bn)?", txt, re.I)
        if m_floor:
            scale = str(m_floor.group(3) or "m").lower()
            suffix = "m" if scale.startswith("m") else "b"
            prefix = ">=" if re.search(r"(?:at least|>=|>)", m_floor.group(1), re.I) else "up to"
            return f"{prefix} ${m_floor.group(2)}{suffix}"
        m_plain = re.search(r"\$?\s*(\d+(?:\.\d+)?)\s*(m|mm|b|bn)\b", txt, re.I)
        if m_plain and re.search(r"\b(target|opportunity|expected|expect|guidance|generation)\b", txt, re.I):
            scale = str(m_plain.group(2) or "m").lower()
            suffix = "m" if scale.startswith("m") else "b"
            return f"${m_plain.group(1)}{suffix}"
        return ""

    def _slide_line_is_noise(line: str) -> bool:
        txt = glx_normalize_text(line)
        if not txt:
            return True
        if re.fullmatch(r"(?:page\s*)?\d{1,3}", txt, re.I):
            return True
        if txt.upper() in {"GREEN PLAINS INC.", "GREEN PLAINS INC"}:
            return True
        return False

    def _slide_line_is_heading(line: str) -> bool:
        txt = glx_normalize_text(line).strip("•").strip()
        if _slide_line_is_noise(txt):
            return True
        if len(txt.split()) <= 7 and txt == txt.upper() and not re.search(r"[a-z]", txt):
            return True
        if len(txt.split()) <= 5 and txt == txt.title() and not re.search(r"\d", txt):
            return True
        return False

    def _slide_signal_noise(text: str) -> bool:
        low = glx_normalize_text(text).lower()
        if not low:
            return True
        deny_patterns = [
            r"recorded within income tax benefit",
            r"excludes amortization",
            r"just need one that shows",
            r"company model assumptions",
            r"calculated using \$?\d",
            r"certain nonrecurring",
            r"operating lease right-of-use assets",
            r"depreciation and amortization",
            r"operational map",
            r"plant guarantors",
            r"remaining\(\$mm\)",
            r"\$--",
            r"remaining facilities precision",
            r"\bfrom purpose and\b",
            r"\bproduction tax credits?\s*\(\d+\)",
            r"\bproportional share of ebitda adjustments\b",
            r"\bloss on sale of equity method investment\b",
            r"\badjusted ebitda \$",
        ]
        return any(re.search(pat, low, re.I) for pat in deny_patterns)

    def _extract_profile_signal_texts(text: str) -> List[str]:
        txt = glx_normalize_text(text)
        if not txt:
            return []
        txt = re.sub(r">\$\s*(\d)\s+(\d{2,3})\s*(?:mi|m)\b", lambda m: f">${m.group(1)}{m.group(2)}M", txt, flags=re.I)
        txt = re.sub(r"\b(20)\s+(2[0-9])\b", r"\1\2", txt)
        cleaned_patterns = [
            r"((?:[A-Z][A-Za-z0-9&/\-]*[a-z][A-Za-z0-9&/\-]*(?:\s+[A-Z][A-Za-z0-9&/\-]*[a-z][A-Za-z0-9&/\-]*){0,3})\s+(?:20\d{2}\s+)?(?:adjusted\s+)?(?:[<>]=?\s*\$?\s*\d+(?:\.\d+)?\s*(?:m|mm|mi|b|bn)\s+)?(?:ebitda|revenue|sales|savings|generation|credits?)\s+(?:opportunity|target|guidance))",
            r"((?:[<>]=?\s*\$?\s*\d+(?:\.\d+)?\s*(?:m|mm|mi|b|bn)\s+)?(?:expected\s+)?(?:45z\s+)?(?:generation|credits?)\s+from\s+(?:[A-Za-z]{2,14}\s+){0,4}?(?:remaining|other|legacy|non-core)\s+(?:facilities|plants|assets?|segments?|operations?|sites?)(?:[^.]{0,70}?\b20\d{2}\b[^.]{0,24})?)",
            r"(Advantage Nebraska[^.]{0,120}?EBITDA opportunity)",
            r"(Advantage Nebraska[^.]{0,120}?fully operational[^.]{0,120}?Wyoming)",
            r"(All plants are on track to qualify for 2026 45Z credits(?: in 2026)?)",
            r"(All eight operating ethanol plants expected to qualify for production tax credits in 2026)",
            r"(Green Plains York[^.]{0,120}?Tallgrass Trailblazer pipeline)",
            r"(Green Plains Wood River\s*&\s*Central City[^.]{0,140}?ramping up capture volumes)",
            r"(Sale of Obion[^.]{0,180}?balance sheet)",
            r"(Central City and Wood River[^.]{0,220}?plants)",
            r"(Achieved strong utilization[^.]{0,140}?(?<!\d)\d{2,3}%)",
            r"((?:Executing|Disciplined)[^.]{0,160}?risk management strategy[^.]{0,180}?(?:margins?|cash flow))",
        ]
        out: List[str] = []
        seen: set[str] = set()
        for pat in cleaned_patterns:
            for m in re.finditer(pat, txt, re.I):
                picked = glx_normalize_text(m.group(1))
                picked = re.sub(
                    r"^(?:[A-Z]{3,}(?:\s+[A-Z]{2,}){0,5}\s+)+(?=[A-Z][a-z])",
                    "",
                    picked,
                )
                picked = re.sub(
                    r"\bfrom\s+(?:[A-Za-z]{2,14}\s+){0,4}(?=(remaining|other|legacy|non-core)\s+(facilities|plants|assets?|segments?|operations?|sites?)\b)",
                    "from ",
                    picked,
                    flags=re.I,
                )
                picked = re.sub(
                    r"\b(?:purpose|precision|discipline|execution|focus)\b(?=\s+(remaining|other|legacy|non-core)\s+(facilities|plants|assets?|segments?|operations?|sites?)\b)",
                    "",
                    picked,
                    flags=re.I,
                )
                picked = glx_normalize_text(picked)
                remaining_match = re.search(
                    r"\b(?:remaining|other|legacy|non-core)\s+(facilities|plants|assets?|segments?|operations?|sites?)\b",
                    picked,
                    re.I,
                )
                if remaining_match:
                    money_matches = list(
                        re.finditer(
                            r"[<>]=?\s*\$?\s*\d+(?:\.\d+)?\s*(?:m|mm|mi|b|bn)\b",
                            picked,
                            re.I,
                        )
                    )
                    last_amt = None
                    for mm in money_matches:
                        if mm.start() < remaining_match.start():
                            last_amt = mm
                    if last_amt is not None:
                        picked = glx_normalize_text(picked[last_amt.start() :])
                if (
                    re.search(r"\b(?:remaining|other|legacy|non-core)\s+(facilities|plants|assets?|segments?|operations?|sites?)\b", picked, re.I)
                    and re.search(r"\b(45z|credits?|generation|ebitda|opportunity)\b", picked, re.I)
                    and not re.search(r"\b20\d{2}\b", picked)
                ):
                    year_match = re.search(r"\b(20\d{2})\b", txt, re.I)
                    if year_match:
                        picked = glx_normalize_text(f"{picked} in {year_match.group(1)}")
                picked = re.sub(r"\b45Z credits in 2026\b", "45Z credits", picked, flags=re.I)
                key = picked.lower()
                if key and key not in seen:
                    seen.add(key)
                    out.append(picked)
        return out

    def _clean_profile_signal_text(text: str) -> str:
        extracted = _extract_profile_signal_texts(text)
        if extracted:
            txt = glx_normalize_text(text)
            txt_low = txt.lower()
            best = extracted[0]
            best_key = (99, 99, len(best))
            for cand in extracted:
                cand_low = cand.lower()
                scope_score = 0
                if re.search(r"\b(?:remaining|other|legacy|non-core)\s+(facilities|plants|assets?|segments?|operations?|sites?)\b", txt_low, re.I):
                    scope_score -= 5 if re.search(r"\b(?:remaining|other|legacy|non-core)\s+(facilities|plants|assets?|segments?|operations?|sites?)\b", cand_low, re.I) else 0
                txt_named_scope = _extract_named_split_target_scope(txt)
                cand_named_scope = _extract_named_split_target_scope(cand)
                if txt_named_scope and cand_named_scope and _split_target_scope_key(txt_named_scope) == _split_target_scope_key(cand_named_scope):
                    scope_score -= 6
                if "ebitda opportunity" in txt_low and "ebitda opportunity" in cand_low:
                    scope_score -= 2
                if "fully operational" in txt_low and "fully operational" in cand_low:
                    scope_score -= 2
                if "45z" in txt_low and "45z" in cand_low:
                    scope_score -= 1
                qual_key = (
                    scope_score,
                    _text_fragment_penalty(cand),
                    len(cand),
                )
                if qual_key < best_key:
                    best = cand
                    best_key = qual_key
            return best
        return glx_normalize_text(text)

    def _text_fragment_penalty(text: str) -> int:
        txt = glx_normalize_text(text)
        if not txt:
            return 4
        low = txt.lower()
        penalty = 0
        numeric_hits = len(
            re.findall(
                r"\$?\s*\d[\d,]*(?:\.\d+)?\s*(?:%|m|mm|b|bn|x|million|billion)?",
                txt,
                re.I,
            )
        )
        if re.search(r"\b(statement of operations|reconciliation|adjusted ebitda reconciliation|production tax credits)\b", low, re.I):
            penalty += 2
        if re.search(r"\b(adjusted ebitda|adjusted ebit|45z)\b", low, re.I) and numeric_hits >= 3:
            penalty += 1
        if "|" in str(text) or "\t" in str(text):
            penalty += 1
        if re.search(r"\b(line item|table|subtotal|total)\b", low, re.I):
            penalty += 1
        if re.search(r"\b(?:45z production tax credits?|adjusted ebitda)\b", low, re.I) and not re.search(r"[.!?]", txt):
            penalty += 1
        if numeric_hits >= 5 and len(re.findall(r"[.!?]", txt)) == 0:
            penalty += 1
        if len(txt.split()) <= 8 and numeric_hits >= 2:
            penalty += 1
        return penalty

    def _clean_target_bonus(text: str) -> int:
        txt = glx_normalize_text(text)
        if not txt:
            return 0
        low = txt.lower()
        bonus = 0
        if re.search(r"\b(ebitda opportunity|adjusted ebitda opportunity)\b", low, re.I):
            bonus += 4
        if re.search(r"\b(45z|advantage nebraska)\b", low, re.I) and re.search(r"\b(target|guidance|expected|expect|opportunity|monetization)\b", low, re.I):
            bonus += 3
        if re.search(r"\b(fully operational|online|ramping|sale completed|repaid|annualized savings|cost reduction)\b", low, re.I):
            bonus += 2
        if re.search(r"[.!?]", txt):
            bonus += 1
        return bonus

    def _source_rank(source_type: Any, doc_name: Any = "") -> int:
        blob = " ".join([str(source_type or ""), str(doc_name or "")]).lower()
        if any(tok in blob for tok in ("earnings_release", "press_release", "transcript", "ceo", "shareholder")):
            return 0
        if any(tok in blob for tok in ("earnings_presentation", "presentation", "slides")):
            return 1
        if any(tok in blob for tok in ("management discussion", "results of operations", "outlook", "md&a")):
            return 2
        return 3

    def _management_theme_key(metric_hint: Any, text: Any, period_hint: Any = "") -> str:
        low = glx_normalize_text(f"{metric_hint or ''} {text or ''}").lower()
        period_norm = str(period_hint or "").strip().lower()
        theme = ""
        if "45z" in low or "advantage nebraska" in low:
            if re.search(r"\b2026\b", low, re.I) and (
                re.search(r"\badjusted\b[^.]{0,40}\bebitda\b", low, re.I)
                or re.search(r"\bebitda\b[^.]{0,40}\bopportunity\b", low, re.I)
                or re.search(r"\badjusted\b[^.]{0,60}\bopportunity\b", low, re.I)
            ):
                theme = "45z_2026_ebitda"
            elif re.search(r"\b(q4|fourth quarter)\b", low, re.I) and re.search(r"\b(monetization|credit|generation)\b", low, re.I):
                theme = "45z_q4_monetization"
            else:
                theme = "45z_general"
        elif re.search(r"\b(cost reduction|annualized savings|cost savings)\b", low, re.I):
            theme = "cost_savings"
        elif re.search(r"\b(obion|junior mezz|debt reduction|deleverag|repaid?|balance sheet improvement)\b", low, re.I):
            theme = "debt_reduction"
        elif re.search(r"\byork\b", low, re.I):
            theme = "york_operational"
        elif re.search(r"\b(central city|wood river)\b", low, re.I):
            theme = "plant_ramp"
        elif re.search(r"\butilization\b", low, re.I):
            theme = "utilization"
        elif re.search(r"\brisk management\b", low, re.I):
            theme = "risk_management"
        if not theme:
            return ""
        return f"{theme}|{period_norm}" if period_norm and period_norm not in {"unk", "time_anchor"} else theme

    split_target_total_re = re.compile(
        r"\b(total|overall|company[- ]?wide|enterprise(?:-wide)?|across all|entire company|all facilities|all plants|all segments|all operations)\b",
        re.I,
    )
    split_target_remaining_re = re.compile(
        r"\b(remaining|other|legacy|non-core)\s+(facilities|plants?|assets?|segments?|business units?|regions?|operations?|sites?)\b",
        re.I,
    )
    split_target_named_scope_patterns: Tuple[Pattern[str], ...] = (
        re.compile(
            r"\b([A-Z][A-Za-z0-9&/\-]*[a-z][A-Za-z0-9&/\-]*(?:\s+(?:and|&)\s+[A-Z][A-Za-z0-9&/\-]*[a-z][A-Za-z0-9&/\-]*|(?:\s+[A-Z][A-Za-z0-9&/\-]*[a-z][A-Za-z0-9&/\-]*){0,3}))\s+(?:20\d{2}\s+)?(?:adjusted\s+)?(?:>\$?\s*\d+(?:\.\d+)?\s*[MmBb]\s+)?(?:ebitda|revenue|sales|savings|generation|opportunity|target|targets|guidance|credits?)\b",
            re.I,
        ),
        re.compile(
            r"\b([A-Z][A-Za-z0-9&/\-]*[a-z][A-Za-z0-9&/\-]*(?:\s+(?:and|&)\s+[A-Z][A-Za-z0-9&/\-]*[a-z][A-Za-z0-9&/\-]*|(?:\s+[A-Z][A-Za-z0-9&/\-]*[a-z][A-Za-z0-9&/\-]*){0,3}))\s+(?:platform|facility|facilities|plant|plants|region|regions|segment|segments|business unit|unit|site|sites|operations?)\b",
            re.I,
        ),
        re.compile(
            r"\b(?:from|for|at|in)\s+([A-Z][A-Za-z0-9&/\-]*[a-z][A-Za-z0-9&/\-]*(?:\s+(?:and|&)\s+[A-Z][A-Za-z0-9&/\-]*[a-z][A-Za-z0-9&/\-]*|(?:\s+[A-Z][A-Za-z0-9&/\-]*[a-z][A-Za-z0-9&/\-]*){0,3}))\b",
            re.I,
        ),
    )
    split_target_scope_stop_words = {
        "adjusted",
        "ebitda",
        "revenue",
        "sales",
        "savings",
        "generation",
        "production",
        "tax",
        "credit",
        "credits",
        "monetization",
        "value",
        "45z",
        "opportunity",
        "target",
        "targets",
        "guidance",
        "credit",
        "credits",
        "company",
        "overall",
        "total",
        "enterprise",
        "annualized",
        "expected",
        "expect",
        "program",
    }

    def _split_target_scope_key(label: Any) -> str:
        txt = glx_normalize_text(str(label or "")).lower()
        if not txt:
            return ""
        txt = re.sub(
            r"\b(the|all|company[- ]?wide|overall|enterprise(?:-wide)?|platform|facility|facilities|plant|plants|region|regions|segment|segments|business unit|business units|unit|units|operations?|assets?|sites?)\b",
            " ",
            txt,
            flags=re.I,
        )
        txt = re.sub(r"[^a-z0-9]+", "_", txt)
        txt = re.sub(r"_+", "_", txt).strip("_")
        return txt

    def _clean_split_target_scope_label(label: Any) -> str:
        txt = glx_normalize_text(str(label or ""))
        if not txt:
            return ""
        txt = re.sub(r"^(?:the|all)\s+", "", txt, flags=re.I)
        txt = re.sub(r"\b(?:platform|facility|facilities|plant|plants|region|regions|segment|segments|business unit|unit|operations?|assets?|sites?)\b$", "", txt, flags=re.I).strip()
        txt = glx_normalize_text(txt)
        if not txt:
            return ""
        if str(ticker or "").upper() == "GPRE":
            txt = re.sub(r"^Green Plains\s+", "", txt, flags=re.I)
            txt = glx_normalize_text(txt)
        return txt

    def _is_time_scope_label(label: Any) -> bool:
        txt = glx_normalize_text(str(label or ""))
        if not txt:
            return False
        low = txt.lower()
        return bool(
            re.search(
                r"\b(?:q[1-4]|fy\s*20\d{2}|20\d{2}|first quarter|second quarter|third quarter|fourth quarter|"
                r"first half|second half|full year)\b",
                low,
                re.I,
            )
        )

    def _extract_named_split_target_scope(text_in: Any) -> str:
        txt = glx_normalize_text(str(text_in or ""))
        if not txt:
            return ""
        for pat in split_target_named_scope_patterns:
            for match in pat.finditer(txt):
                cand = _clean_split_target_scope_label(match.group(1))
                if not cand:
                    continue
                low = cand.lower()
                toks = [tok for tok in re.findall(r"[A-Za-z][A-Za-z0-9&/\-]*", cand) if tok]
                if not toks:
                    continue
                if all(tok.lower() in split_target_scope_stop_words for tok in toks):
                    continue
                if any(tok.lower() in split_target_scope_stop_words for tok in toks) and len(toks) <= 2:
                    continue
                if _is_time_scope_label(low):
                    continue
                return cand
        return ""

    def _split_target_group_key(
        family_key: Any,
        period_key: Any,
        quarter_hint: Any,
    ) -> str:
        family_txt = str(family_key or "").strip().lower() or "unknown_theme"
        period_txt = str(period_key or "").strip() or "UNK"
        qd = _split_target_qend(quarter_hint)
        return f"{family_txt}|{period_txt}|{str(qd) if isinstance(qd, date) else 'UNK'}"

    def _split_target_qend(value: Any) -> Optional[date]:
        if value in (None, "", pd.NaT):
            return None
        ts: Optional[pd.Timestamp] = None
        if isinstance(value, pd.Period):
            try:
                return pd.Timestamp(value.end_time).date()
            except Exception:
                return None
        if isinstance(value, pd.Timestamp):
            ts = value
        elif isinstance(value, datetime):
            ts = pd.Timestamp(value)
        elif isinstance(value, date):
            ts = pd.Timestamp(value)
        elif isinstance(value, str):
            txt = glx_normalize_text(value)
            if not txt:
                return None
            q_match = re.search(r"\bq([1-4])\s*(?:fy)?\s*(20\d{2})\b", txt, re.I) or re.search(
                r"\b(20\d{2})\s*q([1-4])\b",
                txt,
                re.I,
            )
            if q_match:
                if q_match.lastindex == 2 and txt.lower().find("q") < txt.lower().find("20"):
                    q_num = int(q_match.group(1))
                    year_num = int(q_match.group(2))
                else:
                    year_num = int(q_match.group(1))
                    q_num = int(q_match.group(2))
                month_num = int(q_num) * 3
                day_num = 31 if month_num in {3, 12} else 30
                return date(year_num, month_num, day_num)
            try:
                ts_try = pd.to_datetime(txt, errors="coerce")
            except Exception:
                ts_try = pd.NaT
            if pd.notna(ts_try):
                ts = pd.Timestamp(ts_try)
        else:
            try:
                ts_try = pd.to_datetime(value, errors="coerce")
            except Exception:
                ts_try = pd.NaT
            if pd.notna(ts_try):
                ts = pd.Timestamp(ts_try)
        if ts is None or pd.isna(ts):
            return None
        quarter_month = int(((int(ts.month) - 1) // 3 + 1) * 3)
        quarter_day = 31 if quarter_month in {3, 12} else 30
        return date(int(ts.year), quarter_month, quarter_day)

    def _split_target_family_key(theme_key: Any) -> str:
        theme = str(theme_key or "").strip().lower()
        if theme in {
            "45z_qualification",
            "45z_monetization",
            "45z_2026_ebitda",
            "45z_q4_monetization",
            "45z_general",
            "advantage_nebraska_milestone",
        }:
            return "advantage_nebraska_45z"
        return theme

    def _derive_split_target_meta(
        metric_name: Any,
        text_in: Any,
        period_hint: Any = "",
        quarter_hint: Any = None,
        source_type: Any = "",
        source_doc: Any = "",
        section_hint: Any = "",
    ) -> Dict[str, Any]:
        txt = glx_normalize_text(str(text_in or ""))
        theme_key = _management_theme_key(metric_name, txt, period_hint)
        if not theme_key:
            low = txt.lower()
            metric_slug = glx_dedup_text_key(str(metric_name or "")).replace(" ", "_") or "target"
            if re.search(r"\b(45z|production tax credits?)\b", low, re.I):
                if re.search(r"\b2026\b", low, re.I) and re.search(r"\b(ebitda|opportunity|adjusted)\b", low, re.I):
                    theme_key = "45z_2026_ebitda"
                else:
                    theme_key = "45z_general"
            elif re.search(r"\b(cost savings|cost reduction|expense reduction|annualized savings)\b", low, re.I):
                theme_key = "cost_savings"
            elif re.search(r"\b(obion|debt reduction|deleverag|repaid?|balance sheet improvement)\b", low, re.I):
                theme_key = "debt_reduction"
            else:
                theme_key = metric_slug
        family_key = _split_target_family_key(theme_key)
        qd_hint = _split_target_qend(quarter_hint)
        period_label_norm = ""
        period_hint_txt = str(period_hint or "").strip()
        period_key_norm = period_hint_txt if re.fullmatch(r"(?:FY20\d{2}|Q20\d{2}Q[1-4]|RUNRATE|PROGRAM|TIME_ANCHOR|ANNUALIZED_PROGRAM|UNK)", period_hint_txt, re.I) else ""
        if isinstance(qd_hint, date):
            try:
                period_label_norm, period_key_norm_guess = glx_normalize_period(txt, qd_hint)
            except Exception:
                period_label_norm, period_key_norm_guess = ("", "")
            if not period_key_norm and period_key_norm_guess:
                period_key_norm = str(period_key_norm_guess or "")
        targetish = bool(
            txt
            and (
                _extract_money_targets_for_display(txt)
                or re.search(r"\b(target|targets|guidance|expected|expect|opportunity|annualized|generation|savings|revenue|ebitda|credits?)\b", txt, re.I)
            )
        )
        scope_kind = "unknown"
        scope_key = ""
        scope_label = ""
        if targetish and family_key:
            remaining_match = split_target_remaining_re.search(txt)
            if remaining_match:
                scope_label = f"{remaining_match.group(1).title()} {remaining_match.group(2).lower()}"
                scope_kind = "component_remaining" if str(remaining_match.group(1) or "").lower() == "remaining" else "component_other"
                scope_key = _split_target_scope_key(scope_label)
            else:
                named_scope = _extract_named_split_target_scope(txt)
                if named_scope:
                    scope_kind = "component_named"
                    scope_label = named_scope
                    scope_key = _split_target_scope_key(named_scope)
                else:
                    if split_target_total_re.search(txt) or targetish:
                        scope_kind = "total"
                        scope_label = "Company-wide"
                        scope_key = "company_total"
        target_amounts = _extract_money_targets_for_display(txt)
        strongest_target_amt = float(max(target_amounts)) if target_amounts else None
        period_meta = _infer_target_period(
            {
                "metric": metric_name,
                "text_full": txt,
                "target_period_norm": period_key_norm,
                "target_period_label": period_label_norm,
            },
            qd_hint,
        )
        structure_meta = _infer_target_structure(
            {
                "metric": metric_name,
                "text_full": txt,
                "target_family_key": family_key,
                "scope_key": scope_key,
                "target_period_norm": str(period_meta.get("target_period_norm") or period_key_norm or "UNK"),
            },
            qd_hint,
        )
        return {
            "target_family_key": family_key,
            "target_period_key": period_key_norm,
            "target_period_label": period_label_norm,
            "target_group_key": _split_target_group_key(family_key, period_key_norm, qd_hint),
            "scope_kind": scope_kind,
            "scope_key": scope_key,
            "scope_label": scope_label,
            "component_of_total": bool(scope_kind.startswith("component")),
            "_split_target_amount": strongest_target_amt,
            "_split_target_rank": {
                "total": 0,
                "component_named": 1,
                "component_remaining": 2,
                "component_other": 3,
                "unknown": 9,
            }.get(scope_kind, 9),
            "_split_target_window": " | ".join(
                [
                    str(qd_hint or ""),
                    str(source_type or ""),
                    Path(str(source_doc or "")).name if str(source_doc or "") else "",
                    str(section_hint or ""),
                ]
            ).strip(" |"),
            "target_period_type": str(period_meta.get("target_period_type") or "open_ended"),
            "target_period_start": period_meta.get("target_period_start"),
            "target_period_end": period_meta.get("target_period_end"),
            "target_structure_kind": str(structure_meta.get("target_structure_kind") or "single"),
            "target_structure_role": str(structure_meta.get("target_structure_role") or "single"),
            "stage_kind": str(structure_meta.get("stage_kind") or ""),
            "stage_amount": structure_meta.get("stage_amount"),
            "increment_amount": structure_meta.get("increment_amount"),
            "program_total_amount": structure_meta.get("program_total_amount"),
            "program_key": str(structure_meta.get("program_key") or ""),
        }

    def _split_target_metric_display(metric_name: Any, text_in: Any, item: Dict[str, Any]) -> str:
        base_metric = str(metric_name or "").strip()
        if not base_metric:
            return ""
        txt_low = glx_normalize_text(str(text_in or "")).lower()
        family_key = str(item.get("target_family_key") or "").strip().lower()
        scope_kind = str(item.get("scope_kind") or "").strip().lower()
        scope_label = str(item.get("scope_label") or "").strip()
        structure_kind = str(item.get("target_structure_kind") or "").strip().lower()
        structure_role = str(item.get("target_structure_role") or "").strip().lower()
        stage_kind = str(item.get("stage_kind") or "").strip().lower()
        base_low = base_metric.lower()
        if _is_time_scope_label(scope_label):
            scope_kind = "unknown" if scope_kind == "component_named" else scope_kind
            scope_label = ""
        is_45z_family = bool(
            family_key == "advantage_nebraska_45z"
            or base_metric == "45Z monetization / EBITDA"
            or re.search(r"\b45z\b|production tax credits?|tax credit", f"{base_low} {txt_low}", re.I)
        )
        if is_45z_family:
            if re.search(r"\bqualif", txt_low, re.I):
                return "45Z plant qualification readiness"
            if scope_kind == "component_remaining":
                if re.search(r"\b(45z|credits?|generation)\b", txt_low, re.I):
                    return "45Z from remaining facilities"
                return "Remaining facilities contribution"
            if scope_kind == "component_named" and scope_label:
                if re.search(r"\bebitda\b", txt_low, re.I) and re.search(r"\bopportunity\b", txt_low, re.I):
                    return f"{scope_label} EBITDA opportunity"
                if re.search(r"\b(generation|credits?)\b", txt_low, re.I):
                    return f"{scope_label} 45Z generation"
                if re.search(r"\bqualif", txt_low, re.I):
                    return f"{scope_label} 45Z qualification"
                return f"{scope_label} 45Z monetization / EBITDA"
            if scope_kind == "total":
                if re.search(r"\badjusted\b[^.]{0,40}\bebitda\b|\b45z-related\b", txt_low, re.I):
                    return "45Z-related Adjusted EBITDA"
            if re.search(r"\b(q4|fourth quarter)\b", txt_low, re.I) and re.search(r"\b(monetization|tax credit|production tax credits?)\b", txt_low, re.I):
                return "45Z Adjusted EBITDA / monetization"
            if re.search(r"\b(monetization|agreement executed|income tax benefit|net of discounts|recorded within income tax benefit)\b", txt_low, re.I):
                return "45Z Adjusted EBITDA / monetization"
            return "45Z monetization / EBITDA"
        if base_metric == "Cost savings":
            if structure_role in {"first_tranche", "initial", "phase_1"} or stage_kind in {"first_tranche", "initial", "phase_1"}:
                return "Cost savings tranche 1"
            if structure_role in {"additional_tranche", "phase_2", "remaining"} or stage_kind in {"additional_tranche", "phase_2", "remaining"}:
                return "Cost savings tranche 2"
            if structure_kind in {"program_total", "stage_and_total"}:
                return "Cost savings program"
        if base_metric == "Cost savings" and scope_kind.startswith("component") and scope_label:
            return f"{scope_label} cost savings"
        if base_metric == "Revenue" and scope_kind.startswith("component") and scope_label:
            return f"{scope_label} revenue"
        if scope_kind.startswith("component") and scope_label:
            return f"{scope_label} {base_metric}"
        return base_metric

    def _split_target_scope_token(item: Dict[str, Any]) -> str:
        return str(item.get("scope_key") or "").strip() or "company_total"

    def _split_target_scope_is_broad(item: Dict[str, Any], text_in: Any = "") -> bool:
        scope_kind = str(item.get("scope_kind") or "").strip().lower()
        scope_key = _split_target_scope_token(item)
        txt = glx_normalize_text(str(text_in or "")).lower()
        if scope_kind == "total" or scope_key == "company_total":
            return True
        return bool(re.search(r"\b(all plants?|all facilities|across all|company-wide|enterprise|overall)\b", txt, re.I))

    def _quarter_bounds(year_in: int, quarter_in: int) -> Tuple[date, date]:
        q_num = max(1, min(4, int(quarter_in)))
        start_month = 3 * (q_num - 1) + 1
        start_dt = date(int(year_in), start_month, 1)
        if q_num == 1:
            end_dt = date(int(year_in), 3, 31)
        elif q_num == 2:
            end_dt = date(int(year_in), 6, 30)
        elif q_num == 3:
            end_dt = date(int(year_in), 9, 30)
        else:
            end_dt = date(int(year_in), 12, 31)
        return start_dt, end_dt

    def _half_bounds(year_in: int, half_in: int) -> Tuple[date, date]:
        if int(half_in) <= 1:
            return date(int(year_in), 1, 1), date(int(year_in), 6, 30)
        return date(int(year_in), 7, 1), date(int(year_in), 12, 31)

    def _target_period_is_closed(period_meta: Dict[str, Any], eval_q: Optional[date]) -> bool:
        if not isinstance(eval_q, date):
            return False
        period_end = period_meta.get("target_period_end")
        if not isinstance(period_end, date):
            return False
        return eval_q >= period_end

    def _infer_target_period(row_or_text: Any, stated_quarter: Any = None) -> Dict[str, Any]:
        if isinstance(row_or_text, dict):
            txt = glx_normalize_text(
                " | ".join(
                    [
                        str(row_or_text.get("target") or row_or_text.get("target_display") or ""),
                        str(row_or_text.get("text_full") or row_or_text.get("text_snippet") or row_or_text.get("text") or ""),
                        str(row_or_text.get("rationale") or ""),
                        str(row_or_text.get("_source_snip") or ""),
                    ]
                )
            )
            explicit_norm = str(
                row_or_text.get("target_period_norm")
                or row_or_text.get("period_key")
                or row_or_text.get("target_period_key")
                or row_or_text.get("target_period")
                or ""
            ).strip()
            explicit_label = str(
                row_or_text.get("target_period_label")
                or row_or_text.get("period_label")
                or ""
            ).strip()
            promise_type = str(row_or_text.get("promise_type") or "").strip().lower()
            qd_hint = _split_target_qend(
                stated_quarter
                or row_or_text.get("quarter")
                or row_or_text.get("first_seen_evidence_quarter_end")
                or row_or_text.get("first_seen_quarter_end")
                or row_or_text.get("last_seen_evidence_quarter_end")
                or row_or_text.get("last_seen_quarter_end")
            )
        else:
            txt = glx_normalize_text(str(row_or_text or ""))
            explicit_norm = ""
            explicit_label = ""
            promise_type = ""
            qd_hint = _split_target_qend(stated_quarter)
        low = txt.lower()

        def _pack(
            period_type: str,
            label: str,
            norm: str,
            start_dt: Optional[date],
            end_dt: Optional[date],
        ) -> Dict[str, Any]:
            return {
                "target_period_type": period_type,
                "target_period_label": str(label or ""),
                "target_period_norm": str(norm or ""),
                "target_period_start": start_dt,
                "target_period_end": end_dt,
            }

        norm_upper = explicit_norm.upper().replace(" ", "")
        m_q_norm = re.fullmatch(r"Q(20\d{2})Q([1-4])", norm_upper)
        if m_q_norm:
            yy = int(m_q_norm.group(1))
            qq = int(m_q_norm.group(2))
            start_dt, end_dt = _quarter_bounds(yy, qq)
            return _pack("quarter", explicit_label or f"Q{qq} {yy}", f"Q{yy}Q{qq}", start_dt, end_dt)
        m_fy_norm = re.fullmatch(r"FY(20\d{2})", norm_upper)
        if m_fy_norm:
            yy = int(m_fy_norm.group(1))
            return _pack("year", explicit_label or f"FY {yy}", f"FY{yy}", date(yy, 1, 1), date(yy, 12, 31))
        if norm_upper == "FY+1" and isinstance(qd_hint, date):
            yy = int(qd_hint.year) + 1
            return _pack("year", explicit_label or f"FY {yy}", f"FY{yy}", date(yy, 1, 1), date(yy, 12, 31))
        m_half_norm = re.fullmatch(r"(?:H([12])|([12])H)(20\d{2}|\d{2})", norm_upper)
        if m_half_norm:
            hh = int(m_half_norm.group(1) or m_half_norm.group(2))
            yy_raw = str(m_half_norm.group(3))
            yy = int(yy_raw) if len(yy_raw) == 4 else int(f"20{yy_raw}")
            start_dt, end_dt = _half_bounds(yy, hh)
            return _pack("half", explicit_label or f"H{hh} {yy}", f"H{hh}{yy}", start_dt, end_dt)
        m_end_norm = re.fullmatch(r"BY_END_(20\d{2})", norm_upper)
        if m_end_norm:
            yy = int(m_end_norm.group(1))
            return _pack("year", explicit_label or f"by year-end {yy}", f"BY_END_{yy}", date(yy, 1, 1), date(yy, 12, 31))

        q_match = re.search(
            r"\b(?:q([1-4])\s*(20\d{2})|(first|second|third|fourth)\s+quarter(?:\s+of)?\s*(20\d{2})?)\b",
            txt,
            re.I,
        )
        if q_match:
            if q_match.group(1) and q_match.group(2):
                qq = int(q_match.group(1))
                yy = int(q_match.group(2))
            else:
                quarter_map = {"first": 1, "second": 2, "third": 3, "fourth": 4}
                qq = quarter_map.get(str(q_match.group(3) or "").lower(), 0)
                yy = int(q_match.group(4)) if q_match.group(4) else (int(qd_hint.year) if isinstance(qd_hint, date) else 0)
            if qq and yy:
                start_dt, end_dt = _quarter_bounds(yy, qq)
                return _pack("quarter", f"Q{qq} {yy}", f"Q{yy}Q{qq}", start_dt, end_dt)

        half_match = re.search(
            r"\b(?:(first|second)\s+half(?:\s+of)?\s*(20\d{2})?|([12])H\s*'?(\d{2,4}))\b",
            txt,
            re.I,
        )
        if half_match:
            hh = 1 if str(half_match.group(1) or "").lower() == "first" else 2 if str(half_match.group(1) or "").lower() == "second" else int(half_match.group(3) or 0)
            yy_raw = str(half_match.group(2) or half_match.group(4) or "")
            yy = int(yy_raw) if len(yy_raw) == 4 else int(f"20{yy_raw}") if yy_raw else (int(qd_hint.year) if isinstance(qd_hint, date) else 0)
            if hh and yy:
                start_dt, end_dt = _half_bounds(yy, hh)
                return _pack("half", f"H{hh} {yy}", f"H{hh}{yy}", start_dt, end_dt)

        end_match = re.search(r"\bby\s+(?:the\s+)?end\s+of\s+(20\d{2})\b", low, re.I)
        if end_match:
            yy = int(end_match.group(1))
            return _pack("year", f"by year-end {yy}", f"BY_END_{yy}", date(yy, 1, 1), date(yy, 12, 31))

        fy_match = re.search(r"\b(?:fy|fiscal year|full year)\s*(20\d{2}|\d{2})\b", low, re.I)
        if fy_match:
            yy_raw = str(fy_match.group(1))
            yy = int(yy_raw) if len(yy_raw) == 4 else int(f"20{yy_raw}")
            return _pack("year", f"FY {yy}", f"FY{yy}", date(yy, 1, 1), date(yy, 12, 31))

        year_match = re.search(r"\b(?:in|for|through)\s+(20\d{2})\b", low, re.I)
        if year_match:
            yy = int(year_match.group(1))
            return _pack("year", explicit_label or f"FY {yy}", f"FY{yy}", date(yy, 1, 1), date(yy, 12, 31))

        if isinstance(qd_hint, date):
            if re.search(r"\bnext quarter\b", low, re.I):
                q_ts = pd.Timestamp(qd_hint) + pd.offsets.QuarterEnd(1)
                q_end = pd.Timestamp(q_ts).to_period("Q").end_time.date()
                qq = pd.Timestamp(q_end).quarter
                yy = int(q_end.year)
                start_dt, end_dt = _quarter_bounds(yy, qq)
                return _pack("quarter", f"Q{qq} {yy}", f"Q{yy}Q{qq}", start_dt, end_dt)
            if re.search(r"\b(?:this|current)\s+quarter\b", low, re.I):
                qq = pd.Timestamp(qd_hint).quarter
                yy = int(qd_hint.year)
                start_dt, end_dt = _quarter_bounds(yy, qq)
                return _pack("quarter", f"Q{qq} {yy}", f"Q{yy}Q{qq}", start_dt, end_dt)
            if re.search(r"\bnext (?:fiscal year|year)\b", low, re.I):
                yy = int(qd_hint.year) + 1
                return _pack("year", f"FY {yy}", f"FY{yy}", date(yy, 1, 1), date(yy, 12, 31))
            if re.search(r"\b(?:this|current|full)\s+year\b", low, re.I):
                yy = int(qd_hint.year)
                return _pack("year", f"FY {yy}", f"FY{yy}", date(yy, 1, 1), date(yy, 12, 31))

        if promise_type == "milestone":
            return _pack("milestone", explicit_label or "", explicit_norm or "", None, None)
        return _pack("open_ended", explicit_label or "", explicit_norm or "", None, None)

    def _extract_target_amounts_with_spans(text_in: Any) -> List[Tuple[float, int, int]]:
        txt = glx_normalize_text(str(text_in or ""))
        if not txt:
            return []
        out: List[Tuple[float, int, int]] = []
        for m in re.finditer(
            r"\$?\s*([0-9]{1,3}(?:,[0-9]{3})*(?:\.\d+)?|[0-9]+(?:\.\d+)?)\s*(million|billion|m|mm|mi|bn|b)\b",
            txt,
            re.I,
        ):
            amt = _coerce_amount_with_unit_local(m.group(1), m.group(2))
            if amt is None:
                continue
            out.append((float(amt), m.start(), m.end()))
        return out

    def _nearest_amount_for_pattern(text_in: Any, pattern: str, *, after_only: bool = False) -> Optional[float]:
        txt = glx_normalize_text(str(text_in or ""))
        if not txt:
            return None
        patt = re.search(pattern, txt, re.I)
        if not patt:
            return None
        amounts = _extract_target_amounts_with_spans(txt)
        if not amounts:
            return None
        best_amt: Optional[float] = None
        best_dist: Optional[int] = None
        ref_pos = patt.start()
        for amt, start_idx, end_idx in amounts:
            if after_only and start_idx < patt.end():
                continue
            dist = min(abs(start_idx - ref_pos), abs(end_idx - ref_pos))
            if best_dist is None or dist < best_dist:
                best_dist = dist
                best_amt = float(amt)
        return best_amt

    def _infer_target_structure(row_or_text: Any, stated_quarter: Any = None) -> Dict[str, Any]:
        if isinstance(row_or_text, dict):
            txt = glx_normalize_text(
                " | ".join(
                    [
                        str(row_or_text.get("target") or row_or_text.get("target_display") or ""),
                        str(row_or_text.get("text_full") or row_or_text.get("text_snippet") or row_or_text.get("text") or ""),
                        str(row_or_text.get("rationale") or ""),
                        str(row_or_text.get("_source_snip") or ""),
                    ]
                )
            )
            family_key = str(row_or_text.get("target_family_key") or row_or_text.get("theme_key") or "").strip().lower()
            scope_key = _split_target_scope_token(row_or_text)
            period_norm = str(
                row_or_text.get("target_period_norm")
                or row_or_text.get("target_period_key")
                or row_or_text.get("period_key")
                or ""
            ).strip()
            current_target = str(row_or_text.get("target") or row_or_text.get("target_display") or "").strip()
        else:
            txt = glx_normalize_text(str(row_or_text or ""))
            family_key = ""
            scope_key = "company_total"
            period_norm = ""
            current_target = ""
        low = txt.lower()
        amounts = [amt for amt, _, _ in _extract_target_amounts_with_spans(txt)]
        strongest_amt = max(amounts) if amounts else None

        first_stage_amt = _nearest_amount_for_pattern(txt, r"\b(first tranche|first phase|phase 1|phase one|initial)\b")
        realized_anchor_amt = _nearest_amount_for_pattern(txt, r"\b(realized|realised|implemented|achieved|to date)\b")
        if first_stage_amt is None and amounts and re.search(r"\b(first tranche|first phase|phase 1|phase one|initial)\b", low, re.I):
            first_stage_amt = float(min(amounts))
        additional_amt = _nearest_amount_for_pattern(txt, r"\b(additional|another|incremental|second tranche|phase 2|phase two)\b")
        if additional_amt is None and amounts and re.search(r"\b(additional|another|incremental|second tranche|phase 2|phase two)\b", low, re.I):
            additional_amt = float(min(amounts))
        remaining_amt = _nearest_amount_for_pattern(txt, r"\bremaining\b")
        total_amt = _nearest_amount_for_pattern(
            txt,
            r"\b(total program|full program|program total|up to|overall program|annualized program)\b",
        )
        if total_amt is None and re.search(r"\bannualized program\b", low, re.I) and amounts:
            total_amt = float(max(amounts))
        if total_amt is None and re.search(r"\bup to\b", low, re.I) and amounts:
            total_amt = float(max(amounts))
        if (
            total_amt is None
            and realized_anchor_amt is not None
            and additional_amt is not None
            and re.search(r"\b(additional|another|incremental|second tranche|phase 2|phase two)\b", low, re.I)
        ):
            total_amt = float(realized_anchor_amt) + float(additional_amt)

        stage_kind = ""
        stage_amount = None
        increment_amount = None
        program_total_amount = total_amt
        if first_stage_amt is not None and re.search(r"\b(first tranche|first phase|phase 1)\b", low, re.I):
            stage_kind = "first_tranche"
            stage_amount = first_stage_amt
        elif first_stage_amt is not None and re.search(r"\binitial\b", low, re.I):
            stage_kind = "initial"
            stage_amount = first_stage_amt
        elif additional_amt is not None and re.search(r"\b(second tranche|phase 2|phase two)\b", low, re.I):
            stage_kind = "phase_2"
            stage_amount = additional_amt
            increment_amount = additional_amt
        elif additional_amt is not None:
            stage_kind = "additional_tranche"
            stage_amount = additional_amt
            increment_amount = additional_amt
        elif remaining_amt is not None and re.search(r"\bremaining\b", low, re.I):
            stage_kind = "remaining"
            stage_amount = remaining_amt

        if program_total_amount is None and strongest_amt is not None and re.search(r"\b(program|annualized savings|annualized program|full target|full program)\b", low, re.I):
            program_total_amount = strongest_amt

        if stage_kind and program_total_amount is not None:
            structure_kind = "stage_and_total"
        elif stage_kind:
            structure_kind = "stage"
        elif program_total_amount is not None:
            structure_kind = "program_total"
        else:
            structure_kind = "single"

        current_target_hits = _extract_money_targets_for_display(current_target)
        current_target_amt = float(max(current_target_hits)) if current_target_hits else None
        if structure_kind in {"program_total", "stage_and_total"} and program_total_amount is not None:
            if current_target_amt is not None and abs(float(current_target_amt) - float(program_total_amount)) <= max(1e5, abs(float(program_total_amount)) * 0.02):
                role = "program_total"
            elif stage_kind:
                role = stage_kind
            else:
                role = "program_total"
        elif stage_kind:
            role = stage_kind
        else:
            role = "single"

        if not family_key:
            family_key = _split_target_family_key(_management_theme_key("", txt, period_norm))
        if not period_norm:
            period_norm = _infer_target_period({"text_full": txt}, stated_quarter).get("target_period_norm") or "UNK"
        program_key = ""
        if structure_kind != "single":
            program_key = "|".join(
                [
                    str(family_key or "unknown_theme"),
                    str(scope_key or "company_total"),
                    str(period_norm or "UNK"),
                    "program",
                ]
            )

        return {
            "target_structure_kind": structure_kind,
            "target_structure_role": role,
            "stage_kind": stage_kind,
            "stage_amount": stage_amount,
            "increment_amount": increment_amount,
            "program_total_amount": program_total_amount,
            "program_key": program_key,
        }

    def _split_target_identity_key(
        item: Dict[str, Any],
        metric_name: Any = "",
        period_key: Any = "",
        quarter_hint: Any = None,
    ) -> Tuple[str, str, str, str, str]:
        group_key = str(item.get("target_group_key") or "").strip()
        if not group_key:
            split_meta = _derive_split_target_meta(
                metric_name or item.get("metric") or item.get("metric_ref") or "",
                " | ".join(
                    [
                        str(item.get("text_full") or item.get("text_snippet") or item.get("text") or ""),
                        str(item.get("target_display") or item.get("target") or ""),
                    ]
                ),
                period_key or item.get("target_period_norm") or item.get("period_key") or "",
                quarter_hint or item.get("quarter"),
                dict(item.get("source") or {}).get("source_type"),
                dict(item.get("source") or {}).get("doc"),
                dict(item.get("source") or {}).get("section"),
            )
            group_key = str(split_meta.get("target_group_key") or "").strip()
        if not group_key:
            family_key = str(
                item.get("target_family_key")
                or item.get("theme_key")
                or _management_theme_key(metric_name or item.get("metric") or item.get("metric_ref") or "", item.get("text_full") or item.get("text_snippet") or "", period_key or item.get("period_key") or "")
                or "unknown_theme"
            ).strip()
            group_key = _split_target_group_key(
                family_key,
                period_key or item.get("target_period_norm") or item.get("period_key") or "UNK",
                quarter_hint or item.get("quarter"),
            )
        structure_kind = str(item.get("target_structure_kind") or "").strip().lower()
        stage_kind = str(item.get("stage_kind") or "").strip().lower()
        program_key = str(item.get("program_key") or "").strip()
        role = str(item.get("target_structure_role") or "").strip().lower()
        if not (structure_kind or stage_kind or program_key or role):
            struct_meta = _infer_target_structure(
                {
                    "target": item.get("target") or item.get("target_display") or "",
                    "text_full": item.get("text_full") or item.get("text_snippet") or item.get("text") or "",
                    "metric": metric_name or item.get("metric") or item.get("metric_ref") or "",
                    "target_family_key": item.get("target_family_key") or item.get("theme_key") or "",
                    "scope_key": item.get("scope_key") or "",
                    "target_period_norm": period_key or item.get("target_period_norm") or item.get("period_key") or "",
                },
                quarter_hint or item.get("quarter"),
            )
            structure_kind = str(struct_meta.get("target_structure_kind") or "").strip().lower()
            stage_kind = str(struct_meta.get("stage_kind") or "").strip().lower()
            program_key = str(struct_meta.get("program_key") or "").strip()
            role = str(struct_meta.get("target_structure_role") or "").strip().lower()
        return (
            group_key,
            _split_target_scope_token(item),
            str(item.get("promise_type") or item.get("guidance_type") or "operational"),
            program_key,
            role or stage_kind or structure_kind or "single",
        )

    def _candidate_quality_key(
        text: Any,
        source_type: Any,
        doc_name: Any = "",
        doc_priority: Any = 0,
        score: Any = 0.0,
    ) -> Tuple[int, int, int, int, float, int]:
        txt = glx_normalize_text(text)
        doc_pri_num = pd.to_numeric(doc_priority, errors="coerce")
        score_num = pd.to_numeric(score, errors="coerce")
        return (
            _source_rank(source_type, doc_name),
            _text_fragment_penalty(txt),
            -_clean_target_bonus(txt),
            -int(doc_pri_num) if pd.notna(doc_pri_num) else 0,
            -float(score_num) if pd.notna(score_num) else 0.0,
            len(txt),
        )

    def _slide_excerpt(lines: List[str], idx: int) -> str:
        if idx < 0 or idx >= len(lines):
            return ""
        cur = glx_normalize_text(lines[idx])
        if not cur or _slide_line_is_noise(cur):
            return ""
        start = idx
        if not cur.startswith("•"):
            for j in range(idx - 1, max(-1, idx - 3), -1):
                prev = glx_normalize_text(lines[j])
                if not prev or _slide_line_is_noise(prev) or _slide_line_is_heading(prev):
                    break
                if prev.startswith("•"):
                    start = j
                    break
                if len(prev) <= 48:
                    start = j
                    continue
                break
        parts: List[str] = []
        for j in range(start, min(len(lines), start + 8)):
            line = glx_normalize_text(lines[j])
            if not line or _slide_line_is_noise(line):
                if parts:
                    break
                continue
            if j > start and line.startswith("•"):
                break
            if j > idx and _slide_line_is_heading(line):
                break
            line = line.lstrip("•").strip()
            merged = glx_normalize_text(" ".join(parts + [line]))
            if len(merged) > 260 and parts:
                break
            parts.append(line)
            merged_low = glx_normalize_text(" ".join(parts)).lower()
            if j >= idx and re.search(r"[.!?]$", line):
                break
            if re.search(r"\b(ebitda opportunity|sequestering co2 in wyoming|qualify for (?:2026 )?45z credits|sale completed|fully repay|tallgrass trailblazer pipeline|ramping up capture volumes)\b", merged_low, re.I):
                break
        text = glx_normalize_text(" ".join(parts))
        text = re.sub(r"(?<=\d)\s+(?=\d)", "", text)
        text = re.sub(r"(?<=\d)\s+(?=[MmBb]\b)", "", text)
        text = text.replace("|", " ")
        text = glx_normalize_text(text)
        text = re.sub(r"\s+\.\s+", ". ", text)
        return _clean_profile_signal_text(text)

    def _profile_slide_signals_cache_path() -> Optional[Path]:
        root = cache_root if isinstance(cache_root, Path) else None
        if root is None:
            return None
        safe_ticker = re.sub(r"[^A-Za-z0-9_.-]+", "_", str(profile_ticker or ticker or "ticker")).strip("_")
        if not safe_ticker:
            safe_ticker = "ticker"
        return root / f"writer_profile_slide_signals_{safe_ticker.lower()}.json"

    def _profile_slide_signals_signature(
        priority_terms: Tuple[str, ...],
        slide_paths: List[Path],
    ) -> str:
        payload_paths: List[Dict[str, Any]] = []
        for path_in in slide_paths:
            try:
                stat = path_in.stat()
                mtime_ns = int(getattr(stat, "st_mtime_ns", int(stat.st_mtime * 1_000_000_000)))
                size = int(stat.st_size)
            except Exception:
                mtime_ns = 0
                size = 0
            try:
                path_key = str(path_in.resolve())
            except Exception:
                path_key = str(path_in)
            payload_paths.append({"path": path_key, "mtime_ns": mtime_ns, "size": size})
        payload = {
            "version": "profile_slide_signals_v1",
            "ticker": str(profile_ticker or ticker or "").upper(),
            "priority_terms": list(priority_terms),
            "slides": payload_paths,
        }
        return hashlib.sha1(json.dumps(payload, sort_keys=True, ensure_ascii=True).encode("utf-8")).hexdigest()

    def _profile_slide_signal_jsonable(value_in: Any) -> Any:
        if isinstance(value_in, dict):
            return {str(k): _profile_slide_signal_jsonable(v) for k, v in value_in.items()}
        if isinstance(value_in, (list, tuple)):
            return [_profile_slide_signal_jsonable(v) for v in value_in]
        if isinstance(value_in, (pd.Timestamp, datetime, date)):
            try:
                return pd.Timestamp(value_in).date().isoformat()
            except Exception:
                return str(value_in)
        if isinstance(value_in, Path):
            return str(value_in)
        return value_in

    def _read_profile_slide_signals_cache(signature: str) -> Optional[List[Dict[str, Any]]]:
        cache_path = _profile_slide_signals_cache_path()
        if cache_path is None or not cache_path.exists():
            return None
        try:
            payload = json.loads(cache_path.read_text(encoding="utf-8"))
        except Exception:
            return None
        if str(payload.get("signature") or "") != signature:
            return None
        rows_in = payload.get("rows")
        if not isinstance(rows_in, list):
            return None
        out_rows: List[Dict[str, Any]] = []
        for row_in in rows_in:
            if not isinstance(row_in, dict):
                continue
            row = dict(row_in)
            qd = parse_date(row.get("quarter"))
            if qd is None:
                continue
            row["quarter"] = qd
            out_rows.append(row)
        return out_rows

    def _write_profile_slide_signals_cache(signature: str, rows: List[Dict[str, Any]]) -> None:
        cache_path = _profile_slide_signals_cache_path()
        if cache_path is None:
            return
        payload = {
            "signature": signature,
            "rows": [_profile_slide_signal_jsonable(dict(row or {})) for row in rows],
        }
        try:
            cache_path.parent.mkdir(parents=True, exist_ok=True)
            cache_path.write_text(json.dumps(payload, ensure_ascii=True, sort_keys=True), encoding="utf-8")
        except Exception:
            return

    def _load_profile_slide_signals() -> List[Dict[str, Any]]:
        nonlocal profile_slide_signals_cache
        if profile_slide_signals_cache is not None:
            return list(profile_slide_signals_cache)
        priority_terms = tuple(
            sorted(
                {
                    str(t).lower().strip()
                    for t in (
                        list(getattr(company_profile, "quarter_note_priority_terms", ()) or [])
                        + list(getattr(company_profile, "promise_priority_terms", ()) or [])
                    )
                    if str(t).strip()
                }
            )
        )
        if not priority_terms:
            profile_slide_signals_cache = []
            return []
        slide_paths_by_kind = {kind: _slide_text_paths(kind=kind) for kind in ("text", "ocr")}
        slide_kinds = [kind for kind, paths in slide_paths_by_kind.items() if paths]
        if not slide_kinds:
            profile_slide_signals_cache = []
            return []
        signature = _profile_slide_signals_signature(
            priority_terms,
            [path_in for kind in ("text", "ocr") for path_in in slide_paths_by_kind.get(kind, [])],
        )
        cached_rows = _read_profile_slide_signals_cache(signature)
        if cached_rows is not None:
            profile_slide_signals_cache = cached_rows
            return list(cached_rows)
        text_quarters: set[date] = set()
        for path in slide_paths_by_kind.get("text", []):
            qd = _parse_quarter_from_filename(path.name)
            if qd is not None:
                text_quarters.add(qd)
        legal_re = re.compile(
            r"\b(safe harbor|forward-looking statements|private securities litigation reform act|indenture|administrative agent|proxy statement)\b",
            re.I,
        )
        progress_re = re.compile(r"\b(on track|ramping|in progress|advancing|continuing)\b", re.I)
        complete_re = re.compile(r"\b(fully operational|online|completed|started up|executed|sale completed|repaid|fully repay)\b", re.I)
        target_re = re.compile(r"\b(target|guidance|expected|expect|anticipate|annualized|monetization|opportunity)\b", re.I)
        out_rows: List[Dict[str, Any]] = []
        seen_keys: set[Tuple[date, str]] = set()
        for slide_kind in slide_kinds:
            slide_paths = sorted(slide_paths_by_kind.get(slide_kind, []), key=lambda p: p.stat().st_mtime if p.exists() else 0, reverse=True)
            for path in slide_paths:
                qd = _parse_quarter_from_filename(path.name)
                if qd is None:
                    continue
                ocr_fallback_only = bool(slide_kind == "ocr" and qd in text_quarters)
                raw_text = _read_cached_doc_raw(path)
                if not raw_text:
                    continue
                lines = [glx_normalize_text(x) for x in raw_text.splitlines()]
                lines = [x for x in lines if x]
                for txt in _extract_profile_signal_texts(" ".join(lines)):
                    low = txt.lower()
                    if legal_re.search(low) or _slide_signal_noise(txt):
                        continue
                    hits = sum(1 for term in priority_terms if term and term in low)
                    metric_label = _profile_slide_metric(txt)
                    theme_key = _management_theme_key(metric_label, txt)
                    fragment_penalty = _text_fragment_penalty(txt)
                    status_hint = ""
                    if complete_re.search(low):
                        status_hint = "completed"
                    elif progress_re.search(low):
                        status_hint = "in progress"
                    elif target_re.search(low) and re.search(r"\$\s*\d|\b\d+\s*%\b|\b20\d{2}\b", txt):
                        status_hint = "on_track"
                    score = 90.0 + float(hits * 4) - float(fragment_penalty * 4.0) + float(_clean_target_bonus(txt))
                    rec = {
                        "quarter": qd,
                        "text": txt,
                        "category": _profile_slide_category(txt),
                        "metric": metric_label,
                        "source_type": "earnings_presentation",
                        "source_doc": str(path),
                        "status_hint": status_hint,
                        "target_display": _profile_slide_target_display(txt, qd),
                        "is_numeric_target": bool(re.search(r"\$\s*\d|\b\d+\s*%\b|\b20\d{2}\b", txt) and target_re.search(low)),
                        "is_milestone": bool(complete_re.search(low) or progress_re.search(low)),
                        "theme_key": theme_key,
                        "fragment_penalty": fragment_penalty,
                        "doc_priority": 1,
                        "score": score,
                    }
                    rec.update(
                        _derive_split_target_meta(
                            metric_label,
                            txt,
                            rec.get("target_display") or "",
                            qd,
                            "earnings_presentation",
                            str(path),
                            "",
                        )
                    )
                    rec["metric_display"] = _split_target_metric_display(metric_label, txt, rec)
                    out_rows.append(rec)
                if ocr_fallback_only:
                    continue
                for idx, line in enumerate(lines):
                    if len(line) < 20:
                        continue
                    txt = _slide_excerpt(lines, idx) or glx_normalize_text(line)
                    low = txt.lower()
                    if legal_re.search(low):
                        continue
                    if _slide_signal_noise(txt):
                        continue
                    hits = sum(1 for term in priority_terms if term and term in low)
                    if hits <= 0:
                        continue
                    is_numeric = bool(re.search(r"\$\s*\d|\b\d+\s*%\b|\b\d{4}\b", txt))
                    is_milestone = bool(complete_re.search(low) or progress_re.search(low))
                    explicit_driver_signal = bool(
                        ("utilization" in low and re.search(r"(?<!\d)\d{2,3}%", txt))
                        or ("risk management" in low and re.search(r"\b(margin|margins|cash flow|lock in favorable)\b", low, re.I))
                    )
                    if not (is_numeric or is_milestone or hits >= 2 or explicit_driver_signal):
                        continue
                    metric_label = _profile_slide_metric(txt)
                    theme_key = _management_theme_key(metric_label, txt)
                    fragment_penalty = _text_fragment_penalty(txt)
                    if fragment_penalty >= 4 and not (target_re.search(low) or is_milestone):
                        continue
                    key = (qd, metric_label + "|" + txt[:140].lower())
                    if key in seen_keys:
                        continue
                    seen_keys.add(key)
                    status_hint = ""
                    if complete_re.search(low):
                        status_hint = "completed"
                    elif progress_re.search(low):
                        status_hint = "in progress"
                    elif target_re.search(low) and is_numeric:
                        status_hint = "on_track"
                    score = 82.0 + float(hits * 4) - max(0.0, (len(txt) - 180) / 18.0) - float(fragment_penalty * 6.0)
                    if "ebitda opportunity" in low or ("adjusted" in low and "ebitda" in low):
                        score += 12.0
                    if "fully operational" in low or "online and ramping up" in low:
                        score += 4.0
                    if "fully repay" in low or "sale of obion" in low:
                        score += 6.0
                    if "utilization" in low and re.search(r"(?<!\d)\d{2,3}%", txt):
                        score += 5.0
                    if "risk management" in low and re.search(r"\b(margin|margins|cash flow|lock in favorable)\b", low, re.I):
                        score += 5.0
                    score += float(_clean_target_bonus(txt))
                    rec = {
                        "quarter": qd,
                        "text": txt,
                        "category": _profile_slide_category(txt),
                        "metric": metric_label,
                        "source_type": "earnings_presentation",
                        "source_doc": str(path),
                        "status_hint": status_hint,
                        "target_display": _profile_slide_target_display(txt, qd),
                        "is_numeric_target": bool(is_numeric and target_re.search(low)),
                        "is_milestone": bool(is_milestone),
                        "theme_key": theme_key,
                        "fragment_penalty": fragment_penalty,
                        "score": score,
                    }
                    rec.update(
                        _derive_split_target_meta(
                            metric_label,
                            txt,
                            rec.get("target_display") or "",
                            qd,
                            "earnings_presentation",
                            str(path),
                            "",
                        )
                    )
                    rec["metric_display"] = _split_target_metric_display(metric_label, txt, rec)
                    out_rows.append(rec)
        best_by_theme: Dict[Tuple[date, str, str], Dict[str, Any]] = {}
        deduped_rows: List[Dict[str, Any]] = []
        for rec in out_rows:
            theme_key = str(rec.get("theme_key") or "").strip()
            if not theme_key:
                deduped_rows.append(rec)
                continue
            scope_key = str(rec.get("scope_key") or "").strip()
            dkey = (rec.get("quarter"), theme_key, scope_key or "company_total")
            prev = best_by_theme.get(dkey)
            if prev is None or _candidate_quality_key(
                rec.get("text"),
                rec.get("source_type"),
                rec.get("source_doc"),
                rec.get("doc_priority"),
                rec.get("score"),
            ) < _candidate_quality_key(
                prev.get("text"),
                prev.get("source_type"),
                prev.get("source_doc"),
                prev.get("doc_priority"),
                prev.get("score"),
            ):
                best_by_theme[dkey] = rec
        deduped_rows.extend(best_by_theme.values())
        profile_slide_signals_cache = sorted(
            deduped_rows,
            key=lambda z: (
                z.get("quarter") or date.min,
                _candidate_quality_key(
                    z.get("text"),
                    z.get("source_type"),
                    z.get("source_doc"),
                    z.get("doc_priority"),
                    z.get("score"),
                ),
            ),
            reverse=False,
        )
        _write_profile_slide_signals_cache(signature, profile_slide_signals_cache)
        return list(profile_slide_signals_cache)

    def _load_profile_slide_signals_by_quarter() -> Dict[date, List[Dict[str, Any]]]:
        nonlocal profile_slide_signals_by_quarter_cache
        if profile_slide_signals_by_quarter_cache is not None:
            if ctx_ref is not None:
                ctx_ref.derived.profile_slide_signals_by_quarter = profile_slide_signals_by_quarter_cache
            return profile_slide_signals_by_quarter_cache
        with _timed_writer_substage("write_excel.derive.driver_inputs.template_signal_index"):
            grouped: Dict[date, List[Dict[str, Any]]] = {}
            for rec in _load_profile_slide_signals():
                qd = rec.get("quarter")
                if not isinstance(qd, date):
                    continue
                grouped.setdefault(qd, []).append(rec)
            for qd, rows in grouped.items():
                grouped[qd] = sorted(
                    rows,
                    key=lambda rec: (
                        -float(rec.get("score") or 0.0),
                        int(rec.get("fragment_penalty") or 0),
                        str(rec.get("source_doc") or ""),
                    ),
                )
            profile_slide_signals_by_quarter_cache = grouped
        if ctx_ref is not None:
            ctx_ref.derived.profile_slide_signals_by_quarter = profile_slide_signals_by_quarter_cache
        return profile_slide_signals_by_quarter_cache

    def _profile_slide_signals_for_quarter(qd: date) -> List[Dict[str, Any]]:
        if not isinstance(qd, date):
            return []
        return list(_load_profile_slide_signals_by_quarter().get(qd, []))

    def _local_slide_driver_fallback(qd: date, driver_kind: str) -> str:
        if not isinstance(qd, date):
            return ""
        driver_kind_low = str(driver_kind or "").strip().lower()
        for path in _slide_text_paths(kind="text", quarter=qd):
            raw_slide_txt = _read_cached_doc_raw(path)
            if not raw_slide_txt:
                continue
                lines = [glx_normalize_text(x).lstrip("•").strip() for x in raw_slide_txt.splitlines()]
                for idx, line_txt in enumerate(lines):
                    if not line_txt:
                        continue
                    if driver_kind_low == "utilization":
                        if re.search(r"(?<!\d)\d{2,3}%", line_txt) and re.search(
                            r"\b(utilization|stated capacity|operating rate|capacity utilization)\b",
                            line_txt,
                            re.I,
                        ):
                            return line_txt
                        pct_match = re.search(r"(?<!\d)(\d{2,3})%\*?", line_txt)
                        if pct_match:
                            nearby = " ".join([x for x in lines[max(0, idx - 1) : min(len(lines), idx + 3)] if x])
                            if re.search(r"\b(of\s+)?(production|stated)\s+capacity\b", nearby, re.I) and re.search(
                                r"\b(ethanol|operating plants|production at|utilization)\b",
                                nearby,
                                re.I,
                            ):
                                note_txt = f"Production at {pct_match.group(1)}% of stated capacity"
                                if re.search(r"\bexcluding\s+fairmont\b", " ".join(lines[idx : min(len(lines), idx + 7)]), re.I):
                                    note_txt = f"{note_txt} (excluding Fairmont)"
                                return note_txt
                    elif driver_kind_low == "risk_management":
                        if re.search(r"\brisk management\b", line_txt, re.I) and re.search(
                            r"\b(margins?|cash flow|lock in favorable|protect downside|economics)\b",
                            line_txt,
                            re.I,
                        ):
                            return line_txt
                    elif driver_kind_low == "rin_impact":
                        if re.search(r"\baccumulated rins?\b|\brins?\s+of\s+\$", line_txt, re.I):
                            return line_txt
            lines = [re.sub(r"^[\u2022*]+\s*", "", glx_normalize_text(x)).strip() for x in raw_slide_txt.splitlines()]
            for idx, line_txt in enumerate(lines):
                if not line_txt:
                    continue
                if driver_kind_low == "utilization":
                    if re.search(r"(?<!\d)\d{2,3}%", line_txt) and re.search(
                        r"\b(utilization|stated capacity|operating rate|capacity utilization)\b",
                        line_txt,
                        re.I,
                    ):
                        return line_txt
                    pct_match = re.search(r"(?<!\d)(\d{2,3})%\*?", line_txt)
                    if pct_match:
                        nearby = " ".join([x for x in lines[max(0, idx - 1) : min(len(lines), idx + 3)] if x])
                        if re.search(r"\b(of\s+)?(production|stated)\s+capacity\b", nearby, re.I) and re.search(
                            r"\b(ethanol|operating plants|production at|utilization)\b",
                            nearby,
                            re.I,
                        ):
                            note_txt = f"Production at {pct_match.group(1)}% of stated capacity"
                            if re.search(r"\bexcluding\s+fairmont\b", " ".join(lines[idx : min(len(lines), idx + 7)]), re.I):
                                note_txt = f"{note_txt} (excluding Fairmont)"
                            return note_txt
                elif driver_kind_low == "risk_management":
                    if re.search(r"\brisk management\b", line_txt, re.I) and re.search(
                        r"\b(margins?|cash flow|lock in favorable|protect downside|economics)\b",
                        line_txt,
                        re.I,
                    ):
                        return line_txt
                elif driver_kind_low == "rin_impact":
                    if re.search(r"\baccumulated rins?\b|\brins?\s+of\s+\$", line_txt, re.I):
                        return line_txt
        return ""

    def _local_slide_45z_realized_text(qd: date) -> str:
        if not isinstance(qd, date):
            return ""
        for path in _slide_text_paths(kind="text", quarter=qd):
            raw_txt = _read_cached_doc_raw(path)
            if not raw_txt:
                continue
            latest_txt = _extract_45z_realized_progress_text(raw_txt, qd)
            if latest_txt:
                return latest_txt
        return ""

    def _cache_roots() -> List[Path]:
        roots: List[Path] = []
        seen: set[str] = set()

        def _add_root(p: Path) -> None:
            try:
                rp = str(p.resolve())
            except Exception:
                rp = str(p)
            if rp in seen:
                return
            seen.add(rp)
            roots.append(p)

        # Manifest-derived cache roots (highest confidence).
        if manifest_df is not None and not manifest_df.empty:
            pcol = None
            col_map = {str(c).strip().lower(): c for c in manifest_df.columns}
            for key in ("path", "cache_path", "file_path", "local_path"):
                if key in col_map:
                    pcol = col_map[key]
                    break
            if pcol is not None:
                for raw in manifest_df[pcol].dropna().astype(str).head(1000):
                    s = str(raw).strip()
                    if s.lower().startswith("file:///"):
                        s = s[8:]
                        if re.match(r"^[A-Za-z]:", s):
                            s = s.replace("/", "\\")
                    elif s.lower().startswith("file://"):
                        s = s[7:]
                    xp = Path(s)
                    if xp.exists():
                        _add_root(xp.parent)
                    else:
                        # Keep unresolved path parent for later probing.
                        _add_root(xp.parent)

        repo_root = Path(__file__).resolve().parents[2]
        tkr = str(ticker or "").strip()
        ticker_specific_candidates = ticker_cache_candidates(repo_root, tkr, Path(cache_dir) if cache_dir is not None else None)
        for cand in ticker_specific_candidates:
            if cand.exists():
                _add_root(cand)

        # Only fall back to global cache roots when no ticker-specific cache root exists.
        if not any(c.exists() and c != canonical_shared_cache_root(repo_root) for c in ticker_specific_candidates):
            _add_root(canonical_shared_cache_root(repo_root))
            _add_root(Path("sec_cache"))
        return roots

    cache_roots = _cache_roots()
    cache_root = next((p for p in cache_roots if p.exists()), Path(__file__).resolve().parents[2] / "sec_cache")
    pdf_text_cache_root = Path(cache_dir) if cache_dir is not None else cache_root
    _shared_local_bs_payload_cache: Dict[date, Dict[str, Any]] = {}
    _shared_local_bs_file_index_cache: Optional[List[Dict[str, Any]]] = None
    _shared_local_bs_records_by_quarter_cache: Optional[Dict[date, List[Dict[str, Any]]]] = None
    _shared_local_bs_quarter_cache: Dict[str, Optional[date]] = {}
    _shared_local_bs_payload_by_path_cache: Dict[str, Optional[Dict[str, Any]]] = {}

    def _read_material_text(path_in: Path) -> str:
        return _read_cached_doc_text(path_in)

    def _shared_financial_statement_files() -> List[Path]:
        files: List[Path] = []
        seen: set[str] = set()
        for root in material_roots:
            fs_dir = root / "financial_statement"
            if not fs_dir.exists() or not fs_dir.is_dir():
                continue
            try:
                cand_files = sorted([p for p in fs_dir.iterdir() if p.is_file()])
            except Exception:
                continue
            for path_in in cand_files:
                if path_in.suffix.lower() not in {".txt", ".htm", ".html"}:
                    continue
                if not _path_belongs_to_ticker(path_in, ticker, ticker_roots):
                    continue
                try:
                    key = str(path_in.resolve())
                except Exception:
                    key = str(path_in)
                if key in seen:
                    continue
                seen.add(key)
                files.append(path_in)
        return files

    def _shared_local_balance_sheet_file_index() -> List[Dict[str, Any]]:
        nonlocal _shared_local_bs_file_index_cache
        if _shared_local_bs_file_index_cache is not None:
            return _shared_local_bs_file_index_cache
        indexed: List[Dict[str, Any]] = []
        for path_in in _shared_financial_statement_files():
            indexed.append(
                {
                    "path": path_in,
                    "path_key": _path_cache_key(path_in),
                    "suffix": path_in.suffix.lower(),
                    "quarter": _parse_quarter_from_filename(path_in.name),
                }
            )
        _shared_local_bs_file_index_cache = indexed
        return _shared_local_bs_file_index_cache

    def _shared_local_balance_sheet_quarter(rec: Dict[str, Any]) -> Optional[date]:
        path_in = rec.get("path")
        if not isinstance(path_in, Path):
            return None
        path_key = str(rec.get("path_key") or _path_cache_key(path_in))
        if path_key in _shared_local_bs_quarter_cache:
            return _shared_local_bs_quarter_cache.get(path_key)
        qd = rec.get("quarter")
        if not isinstance(qd, date):
            raw_txt = _read_material_text(path_in)
            qd = (
                _parse_quarter_from_follow_text(raw_txt)
                or infer_quarter_end_from_text(raw_txt)
            )
        qd_out = qd if isinstance(qd, date) else None
        _shared_local_bs_quarter_cache[path_key] = qd_out
        return qd_out

    def _shared_local_balance_sheet_records_by_quarter() -> Dict[date, List[Dict[str, Any]]]:
        nonlocal _shared_local_bs_records_by_quarter_cache
        if _shared_local_bs_records_by_quarter_cache is not None:
            return _shared_local_bs_records_by_quarter_cache
        grouped: Dict[date, List[Dict[str, Any]]] = {}
        for rec in _shared_local_balance_sheet_file_index():
            qd = rec.get("quarter")
            if not isinstance(qd, date):
                qd = _shared_local_balance_sheet_quarter(rec)
            if not isinstance(qd, date):
                continue
            grouped.setdefault(qd, []).append(rec)
        _shared_local_bs_records_by_quarter_cache = grouped
        return _shared_local_bs_records_by_quarter_cache

    def _shared_local_balance_sheet_payload_for_record(rec: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        path_in = rec.get("path")
        if not isinstance(path_in, Path):
            return None
        path_key = str(rec.get("path_key") or _path_cache_key(path_in))
        if path_key in _shared_local_bs_payload_by_path_cache:
            return _shared_local_bs_payload_by_path_cache.get(path_key)
        qd = _shared_local_balance_sheet_quarter(rec)
        if not isinstance(qd, date):
            _shared_local_bs_payload_by_path_cache[path_key] = None
            return None
        result = None
        try:
            if str(rec.get("suffix") or "").lower() in {".htm", ".html"}:
                result = _extract_balance_sheet_from_html(path_in.read_bytes(), qd)
            else:
                result = _extract_balance_sheet_from_text(_read_material_text(path_in), qd)
        except Exception:
            result = None
        if not result:
            _shared_local_bs_payload_by_path_cache[path_key] = None
            return None
        payload = dict(result)
        payload["source_doc"] = str(path_in)
        payload["_quarter"] = qd
        _shared_local_bs_payload_by_path_cache[path_key] = payload
        return payload

    def _shared_load_local_balance_sheet_detail_payloads(
        target_quarters: Optional[set[date]] = None,
    ) -> Dict[date, Dict[str, Any]]:
        target_qs = {qd for qd in (target_quarters or set()) if isinstance(qd, date)}
        if target_qs and all(qd in _shared_local_bs_payload_cache for qd in target_qs):
            return {
                qd: payload
                for qd, payload in _shared_local_bs_payload_cache.items()
                if qd in target_qs
            }
        with _timed_writer_substage("write_excel.valuation.bundle.local_bs.index"):
            records_by_quarter = _shared_local_balance_sheet_records_by_quarter()

        candidate_records: List[Dict[str, Any]] = []
        if target_qs:
            for qd in sorted(target_qs):
                candidate_records.extend(records_by_quarter.get(qd, []))
        else:
            for recs in records_by_quarter.values():
                candidate_records.extend(recs)

        with _timed_writer_substage("write_excel.valuation.bundle.local_bs.parse_selected"):
            parsed_payloads: List[Dict[str, Any]] = []
            for rec in candidate_records:
                payload = _shared_local_balance_sheet_payload_for_record(rec)
                if not payload:
                    continue
                parsed_payloads.append(payload)

        with _timed_writer_substage("write_excel.valuation.bundle.local_bs.pick_best"):
            for payload in parsed_payloads:
                qd = payload.get("_quarter")
                if not isinstance(qd, date):
                    continue
                current = _shared_local_bs_payload_cache.get(qd)
                if current is None or len(payload.get("values", {})) >= len(current.get("values", {})):
                    _shared_local_bs_payload_cache[qd] = payload
        if not target_qs:
            return dict(_shared_local_bs_payload_cache)
        return {
            qd: payload
            for qd, payload in _shared_local_bs_payload_cache.items()
            if qd in target_qs
        }

    def _carry_forward_low_change_series(
        src_map: Dict[pd.Timestamp, Optional[float]],
        q_series: List[Any],
        *,
        max_gap_quarters: int = 4,
        rel_tol: float = 1e-4,
        abs_tol: float = 1_000.0,
    ) -> Dict[pd.Timestamp, Optional[float]]:
        ordered = [pd.Timestamp(qv) for qv in q_series]
        out_map: Dict[pd.Timestamp, Optional[float]] = {
            pd.Timestamp(qv): (None if src_map.get(pd.Timestamp(qv)) is None else float(src_map.get(pd.Timestamp(qv))))
            for qv in ordered
        }
        explicit_idx = [idx for idx, qv in enumerate(ordered) if out_map.get(pd.Timestamp(qv)) is not None]
        if len(explicit_idx) < 2:
            return out_map

        def _sameish(a: Optional[float], b: Optional[float]) -> bool:
            if a is None or b is None:
                return False
            lim = max(abs_tol, rel_tol * max(abs(float(a)), abs(float(b)), 1.0))
            return abs(float(a) - float(b)) <= lim

        for idx, qv in enumerate(ordered):
            qk = pd.Timestamp(qv)
            if out_map.get(qk) is not None:
                continue
            prev_candidates = [ii for ii in explicit_idx if ii < idx]
            next_candidates = [ii for ii in explicit_idx if ii > idx]
            prev_idx = prev_candidates[-1] if prev_candidates else None
            next_idx = next_candidates[0] if next_candidates else None
            prev_val = out_map.get(pd.Timestamp(ordered[prev_idx])) if prev_idx is not None else None
            next_val = out_map.get(pd.Timestamp(ordered[next_idx])) if next_idx is not None else None
            if (
                prev_idx is not None
                and next_idx is not None
                and (idx - prev_idx) <= max_gap_quarters
                and (next_idx - idx) <= max_gap_quarters
                and _sameish(prev_val, next_val)
            ):
                out_map[qk] = None if prev_val is None else float(prev_val)
                continue
            if prev_idx is not None and (idx - prev_idx) <= max_gap_quarters and prev_val is not None:
                out_map[qk] = float(prev_val)
        return out_map

