    def _build_period_index(max_periods: int = 12) -> pd.DataFrame:
        if hist is None or hist.empty or "quarter" not in hist.columns:
            return pd.DataFrame()
        qs = sorted(pd.to_datetime(hist["quarter"], errors="coerce").dropna().unique())
        if len(qs) > max_periods:
            qs = qs[-max_periods:]
        rows = []
        for i, q in enumerate(qs, 1):
            rows.append({
                "period_end": q,
                "display_order": i,
                "vintage_policy": f"strictness={strictness}",
            })
        return pd.DataFrame(rows)

    def _build_report(statement: str, scale: float = 1e6) -> pd.DataFrame:
        if hist is None or hist.empty:
            return pd.DataFrame()
        lim = _build_lineitem_map()
        lim = lim[lim["statement"] == statement].sort_values(["sort", "metric"]).copy()
        periods = _build_period_index(12)
        if periods.empty:
            return pd.DataFrame()
        period_cols = [pd.to_datetime(p) for p in periods["period_end"]]
        # metadata from audit (latest quarter within window)
        meta: Dict[str, Dict[str, str]] = {}
        if audit is not None and not audit.empty:
            aud = _audit_view().copy()
            if "_quarter" in aud.columns:
                aud["quarter"] = aud["_quarter"]
            for metric in lim["metric"].unique():
                sub = aud[aud["metric"] == metric].copy()
                sub = sub[sub["quarter"].isin(period_cols)].copy()
                if sub.empty:
                    meta[metric] = {"source": "Missing", "tag": "", "accn": "", "qa": "FAIL"}
                    continue
                sub["source_rank"] = sub["source"].map(lambda s: 0 if str(s or "").lower() != "missing" else 1)
                latest = sub.sort_values(["quarter", "source_rank"], ascending=[False, True]).iloc[0]
                meta[metric] = {
                    "source": _source_label(latest.get("source")),
                    "tag": latest.get("tag", ""),
                    "accn": latest.get("accn", ""),
                    "qa": latest.get("qa_severity") or _source_qa(latest.get("source")),
                }
        rows = []
        h = _hist_view().copy()
        if "_quarter" in h.columns:
            h["quarter"] = h["_quarter"]
        ttm_vals: Dict[str, float] = {}
        if statement == "IS":
            for m in ["revenue", "ebitda", "cfo", "capex"]:
                if m in h.columns:
                    last4 = h.sort_values("quarter").tail(4)
                    ttm_vals[m] = pd.to_numeric(last4[m], errors="coerce").sum()
            if "cfo" in ttm_vals and "capex" in ttm_vals:
                ttm_vals["fcf"] = ttm_vals["cfo"] - ttm_vals["capex"]
        for _, r in lim.iterrows():
            metric = r["metric"]
            row = {
                "Section": r["section"],
                "Line Item": r["display_label"],
                "Source": meta.get(metric, {}).get("source", ""),
                "QA": meta.get(metric, {}).get("qa", ""),
                "Tag": meta.get(metric, {}).get("tag", ""),
                "Accn": meta.get(metric, {}).get("accn", ""),
            }
            for p in period_cols:
                if metric == "fcf":
                    val = None
                    if "cfo" in h.columns and "capex" in h.columns:
                        sub = h[h["quarter"] == p]
                        if not sub.empty:
                            cfo = pd.to_numeric(sub["cfo"], errors="coerce").iloc[0]
                            capex = pd.to_numeric(sub["capex"], errors="coerce").iloc[0]
                            if pd.notna(cfo) and pd.notna(capex):
                                val = cfo - capex
                else:
                    val = None
                    if metric in h.columns:
                        sub = h[h["quarter"] == p]
                        if not sub.empty:
                            val = pd.to_numeric(sub[metric], errors="coerce").iloc[0]
                row[p.date()] = (val / scale) if pd.notna(val) else None
            if metric == "fcf":
                has_fcf = any(pd.notna(row.get(p.date())) for p in period_cols)
                if has_fcf:
                    row["Source"] = "Derived"
                    row["QA"] = "PASS"
                    row["Tag"] = ""
                    row["Accn"] = ""
            if statement == "IS":
                ttm = ttm_vals.get(metric)
                row["TTM"] = (ttm / scale) if ttm is not None else None
            rows.append(row)
        if statement == "IS":
            rev_ttm = ttm_vals.get("revenue")
            ebitda_ttm = ttm_vals.get("ebitda")
            fcf_ttm = ttm_vals.get("fcf")
            # TTM rows
            for label, val in [
                ("Revenue TTM", rev_ttm),
                ("EBITDA TTM", ebitda_ttm),
                ("FCF TTM", fcf_ttm),
            ]:
                rows.append({
                    "Section": "TTM",
                    "Line Item": label,
                    "Source": "Derived",
                    "QA": "PASS",
                    "Tag": "",
                    "Accn": "",
                    "TTM": (val / scale) if val is not None else None,
                })
            # Margin rows
            if rev_ttm and ebitda_ttm is not None:
                rows.append({
                    "Section": "TTM",
                    "Line Item": "EBITDA margin",
                    "Source": "Derived",
                    "QA": "PASS",
                    "Tag": "",
                    "Accn": "",
                    "TTM": (ebitda_ttm / rev_ttm) if rev_ttm else None,
                })
            if rev_ttm and fcf_ttm is not None:
                rows.append({
                    "Section": "TTM",
                    "Line Item": "FCF margin",
                    "Source": "Derived",
                    "QA": "PASS",
                    "Tag": "",
                    "Accn": "",
                    "TTM": (fcf_ttm / rev_ttm) if rev_ttm else None,
                })
            # QoQ/YoY rows
            def _growth(series: pd.Series, periods_back: int) -> Dict[str, float]:
                out: Dict[str, float] = {}
                series = series.sort_index()
                for idx in range(periods_back, len(series)):
                    cur = series.iloc[idx]
                    prev = series.iloc[idx - periods_back]
                    if pd.notna(cur) and pd.notna(prev) and prev != 0:
                        out[series.index[idx]] = (float(cur) - float(prev)) / abs(float(prev))
                return out

            if "revenue" in h.columns:
                series = h.set_index("quarter")["revenue"]
                qoq = _growth(series, 1)
                yoy = _growth(series, 4)
                row_qoq = {"Section": "Growth", "Line Item": "Revenue QoQ %", "Source": "Derived", "QA": "PASS", "Tag": "", "Accn": ""}
                row_yoy = {"Section": "Growth", "Line Item": "Revenue YoY %", "Source": "Derived", "QA": "PASS", "Tag": "", "Accn": ""}
                for p in period_cols:
                    row_qoq[p.date()] = qoq.get(p)
                    row_yoy[p.date()] = yoy.get(p)
                rows.append(row_qoq)
                rows.append(row_yoy)
            if "ebitda" in h.columns:
                series = h.set_index("quarter")["ebitda"]
                qoq = _growth(series, 1)
                yoy = _growth(series, 4)
                row_qoq = {"Section": "Growth", "Line Item": "EBITDA QoQ %", "Source": "Derived", "QA": "PASS", "Tag": "", "Accn": ""}
                row_yoy = {"Section": "Growth", "Line Item": "EBITDA YoY %", "Source": "Derived", "QA": "PASS", "Tag": "", "Accn": ""}
                for p in period_cols:
                    row_qoq[p.date()] = qoq.get(p)
                    row_yoy[p.date()] = yoy.get(p)
                rows.append(row_qoq)
                rows.append(row_yoy)
        return pd.DataFrame(rows)

    def _write_report_sheet(name: str, df: pd.DataFrame, scale_label: str) -> None:
        ws = wb.create_sheet(title=name)
        if df is None or df.empty:
            ws["A1"] = "No data."
            return
        ws["A1"] = "Scale"
        ws["B1"] = scale_label
        ws["A2"] = "Values below are scaled."
        # header
        # preserve date headers as actual dates (not strings) for reliable lookups
        ws.append(list(df.columns))
        for _, row in df.iterrows():
            ws.append([None if pd.isna(row.get(c)) else _safe_cell(row.get(c)) for c in df.columns])
        # style
        header_row = 3
        ws.freeze_panes = "A4"
        for c in ws[header_row]:
            c.font = Font(bold=True, size=header_size)
            c.alignment = Alignment(vertical="center")
        _autowidth(ws, len(df.columns))
        ws.sheet_format.defaultRowHeight = 18
        ws.sheet_view.zoomScale = 110
        # date headers formatting
        for cell in ws[header_row]:
            if isinstance(cell.value, (datetime, date)):
                cell.number_format = "yyyy-mm-dd"
        for row in ws.iter_rows(min_row=1, max_row=ws.max_row, max_col=ws.max_column):
            for cell in row:
                size = header_size if cell.row == header_row else font_size
                cell.font = _updated_font(cell.font, size=size, bold=cell.font.b)
        try:
            headers = [c.value for c in ws[header_row]]
            if any(h is None or isinstance(h, (datetime, date)) or not isinstance(h, str) for h in headers):
                raise ValueError("Non-string headers; skip table")
            if len(headers) != len(set(headers)):
                raise ValueError("Duplicate headers; skip table")
            ref = f"A{header_row}:{get_column_letter(len(df.columns))}{ws.max_row}"
            t = Table(displayName=name.replace(" ", "").replace("-", ""), ref=ref)
            t.tableStyleInfo = TableStyleInfo(name="TableStyleMedium9", showRowStripes=True)
            ws.add_table(t)
        except Exception:
            pass

    def _write_summary_sheet(df: pd.DataFrame) -> None:
        ws = wb.create_sheet(title="SUMMARY")
        if df is None or df.empty:
            ws["A1"] = "No data."
            return

        ws.sheet_format.defaultRowHeight = 18
        ws.sheet_view.zoomScale = 110
        ws.freeze_panes = "A2"
        section_fill = PatternFill("solid", fgColor="5B9BD5")
        row_fill_a = PatternFill("solid", fgColor="D9EAF7")
        row_fill_b = PatternFill("solid", fgColor="EDF4FB")
        thick_black = Side(style="thick", color="000000")
        thin_gray = Side(style="thin", color="D9D9D9")
        overview_last_col = 6
        narrative_last_col = 6

        def _px_to_width(px: float) -> float:
            try:
                p = float(px)
            except Exception:
                p = 100.0
            return max(1.0, round((p - 5.0) / 7.0, 2))

        def _summary_unit_from_note(note: Any) -> str:
            txt = str(note or "").strip()
            if not txt:
                return ""
            low = txt.lower()
            if low == "date":
                return ""
            if low.startswith("units:"):
                return txt.split(":", 1)[1].strip().rstrip(".")
            if txt in {"$m", "%", "$/share", "x", "bps"}:
                return txt
            return ""

        def _summary_note_comment(note: Any) -> str:
            txt = str(note or "").strip()
            if not txt:
                return ""
            if txt.lower() == "date":
                return ""
            if txt.startswith("Units:"):
                return ""
            if txt in {"$m", "%", "$/share", "x", "bps"}:
                return ""
            return txt

        def _add_comment(cell, note_text: str) -> None:
            txt = str(note_text or "").strip()
            if not txt:
                return
            try:
                _set_cell_comment_local(cell, txt)
            except Exception:
                pass

        def _write_section_header(
            row_idx: int,
            title: str,
            title_size: float = 15.0,
            fill_color: str = "5B9BD5",
            font_color: str = "FFFFFF",
        ) -> int:
            ws.merge_cells(start_row=row_idx, start_column=1, end_row=row_idx, end_column=overview_last_col)
            cell = ws.cell(row=row_idx, column=1, value=title)
            cell.font = Font(bold=True, size=title_size, color=font_color)
            cell.alignment = Alignment(horizontal="center", vertical="center")
            cell.fill = PatternFill("solid", fgColor=fill_color)
            ws.row_dimensions[row_idx].height = 24
            for cc in range(1, overview_last_col + 1):
                ws.cell(row=row_idx, column=cc).fill = PatternFill("solid", fgColor=fill_color)
                ws.cell(row=row_idx, column=cc).border = Border(
                    top=thick_black,
                    left=thin_gray,
                    right=thin_gray,
                    bottom=thin_gray,
                )
            return row_idx + 1

        def _normalized_value_text(value: Any) -> str:
            if value is None or (isinstance(value, float) and pd.isna(value)):
                return ""
            if isinstance(value, str):
                return value.strip()
            return str(value)

        def _split_overview_value_lines(value_txt: str) -> List[str]:
            def _clean_overview_line(line_txt: str) -> str:
                s = glx_normalize_text(str(line_txt or ""))
                if s.startswith("- "):
                    s = f"• {s[2:].strip()}"
                if re.search(r"[.!?%]$|\d$", s):
                    return s
                last_word = re.sub(r"[^A-Za-z0-9%]+", "", s.split()[-1]) if s.split() else ""
                last_word_lc = last_word.lower()
                if len(s) > 100:
                    cut_candidates = [
                        s.rfind(". "),
                        s.rfind("; "),
                        s.rfind(": "),
                        s.rfind(", "),
                    ]
                    cut_idx = max(cut_candidates)
                    if cut_idx >= int(len(s) * 0.55):
                        trimmed = s[: cut_idx + 1].rstrip(" ,;:-")
                        if trimmed:
                            return trimmed
                if last_word_lc in {"around", "and", "the", "of", "to", "for", "in", "on", "with", "from", "by"}:
                    cut_candidates = [s.rfind("; "), s.rfind(", "), s.rfind(". ")]
                    cut_idx = max(cut_candidates)
                    if cut_idx >= int(len(s) * 0.45):
                        trimmed = s[: cut_idx + 1].rstrip(" ,;:-")
                        if trimmed:
                            return trimmed
                parts = s.split()
                while parts:
                    tail = re.sub(r"[^A-Za-z0-9%]+", "", parts[-1]).lower()
                    if len(tail) <= 3:
                        parts.pop()
                        continue
                    if len(tail) <= 4 and tail.isalpha() and tail == last_word_lc:
                        parts.pop()
                        continue
                    break
                while parts and re.sub(r"[^A-Za-z0-9%]+", "", parts[-1]).lower() in {"and", "the", "of", "to", "for", "in", "on", "with", "from", "by"}:
                    parts.pop()
                s = " ".join(parts).rstrip(" ,;:-")
                if s and not re.search(r"[.!?%]$|\d$", s):
                    sentence_cut = max(s.rfind(". "), s.rfind("! "), s.rfind("? "))
                    if sentence_cut >= int(len(s) * 0.55):
                        trimmed = s[: sentence_cut + 1].rstrip(" ,;:-")
                        if trimmed:
                            return trimmed
                    clause_cut = max(s.rfind("; "), s.rfind(": "), s.rfind(", "))
                    if clause_cut >= int(len(s) * 0.65):
                        trimmed = s[: clause_cut + 1].rstrip(" ,;:-")
                        if trimmed:
                            return trimmed
                return s or glx_normalize_text(str(line_txt or ""))

            parts: List[str] = []
            raw_parts = [str(p or "").strip() for p in str(value_txt or "").split("\n")]
            for part in raw_parts:
                if not part:
                    continue
                parts.append(_clean_overview_line(part))
            return parts or ["N/A"]

        def _prefix_is_label_like(prefix_txt: str, delimiter: str) -> bool:
            prefix = str(prefix_txt or "").strip()
            if not prefix:
                return False
            core = prefix.rstrip(":;").strip()
            if not core:
                return False
            words = [w for w in re.split(r"\s+", core) if w]
            if delimiter == ":":
                return len(words) <= 10 and len(core) <= 90
            labelish_terms = {
                "advantage",
                "dependencies",
                "dependency",
                "segment",
                "segments",
                "model",
                "revenue",
                "risk",
                "spread",
                "sensitivity",
                "policy",
                "technology",
                "execution",
            }
            return len(words) <= 7 and (
                "/" in core
                or any(term in core.lower() for term in labelish_terms)
            )

        def _split_overview_prefix(line_txt: str) -> Tuple[str, str]:
            s = str(line_txt or "").strip()
            if not s:
                return "", ""
            bullet_match = re.match(r"^(•\s*)(.*)$", s)
            bullet_txt = ""
            core_txt = s
            if bullet_match:
                bullet_txt, core_txt = bullet_match.groups()
                core_txt = core_txt.strip()
            rich_match = re.match(r"^(.{1,90}?)([:;])(\s*)(.+)$", core_txt)
            if not rich_match:
                return "", s
            lead_core, delimiter, spacer_txt, rest_txt = rich_match.groups()
            lead_txt = f"{lead_core}{delimiter}"
            if not _prefix_is_label_like(lead_txt, delimiter):
                return "", s
            if not rest_txt.strip():
                return "", s
            lead_display = f"{bullet_txt}{lead_txt}".strip()
            rest_display = f"{spacer_txt}{rest_txt}".strip()
            return lead_display, rest_display

        def _fill_row(row_idx: int, fill: PatternFill, end_col: int = overview_last_col) -> None:
            for cc in range(1, end_col + 1):
                ws.cell(row=row_idx, column=cc).fill = fill

        def _top_black_line(row_idx: int, end_col: int = overview_last_col) -> None:
            for cc in range(1, end_col + 1):
                cell = ws.cell(row=row_idx, column=cc)
                cell.border = Border(
                    top=thick_black,
                    left=thin_gray,
                    right=thin_gray,
                    bottom=thin_gray,
                )

        def _summary_narrative_row_height(text: str, col_chars: float) -> float:
            est_lines = _estimate_wrapped_line_count(
                text,
                col_chars,
                min_lines=1,
                max_lines=12,
            )
            row_h = _estimate_wrapped_row_height(
                text,
                col_chars,
                20,
                14,
                min_lines=1,
                max_lines=12,
            )
            if est_lines > 2.15:
                row_h += 4.0
            if est_lines > 3.15:
                row_h += 4.0
            if est_lines > 4.15:
                row_h += 2.0
            return min(96.0, max(24.0, row_h))

        rows = df.to_dict("records")
        company_rows = [r for r in rows if str(r.get("Section") or "").strip().lower() == "company overview"]
        metric_rows = [
            r
            for r in rows
            if str(r.get("Section") or "").strip()
            and str(r.get("Section") or "").strip().lower() not in {"company overview", "qa"}
        ]

        overview_items: List[Dict[str, str]] = []
        current_item: Optional[Dict[str, str]] = None
        for rec in company_rows:
            metric_txt = str(rec.get("Metric") or "").strip()
            value_txt = _normalized_value_text(rec.get("Value"))
            note_txt = str(rec.get("Note") or "").strip()
            if metric_txt:
                if current_item is not None:
                    overview_items.append(current_item)
                current_item = {"metric": metric_txt, "value": "", "note": note_txt}
            if current_item is None:
                continue
            if value_txt:
                if current_item["value"]:
                    current_item["value"] = f"{current_item['value']}\n{value_txt}"
                else:
                    current_item["value"] = value_txt
            if not current_item.get("note") and note_txt:
                current_item["note"] = note_txt
        if current_item is not None:
            overview_items.append(current_item)

        ws.column_dimensions["A"].width = 42
        ws.column_dimensions["B"].width = 18
        ws.column_dimensions["C"].width = 14
        ws.column_dimensions["D"].width = 12
        ws.column_dimensions["E"].width = 12
        ws.column_dimensions["F"].width = 12
        ws.column_dimensions["G"].width = 12
        ws.column_dimensions["H"].width = 12
        merged_text_width = sum(
            float(ws.column_dimensions[get_column_letter(col)].width or 0.0) for col in range(1, narrative_last_col + 1)
        ) or _px_to_width(714)

        row_idx = _write_section_header(1, "Company Overview", 15.0)
        overview_band_idx = 0
        for item_idx, item in enumerate(overview_items):
            metric_txt = str(item.get("metric") or "").strip()
            value_txt = str(item.get("value") or "").strip() or "N/A"
            note_txt = str(item.get("note") or "").strip()
            ws.merge_cells(start_row=row_idx, start_column=1, end_row=row_idx, end_column=narrative_last_col)
            label_cell = ws.cell(row=row_idx, column=1, value=metric_txt)
            label_cell.font = Font(bold=True, size=header_size)
            label_cell.alignment = Alignment(horizontal="left", vertical="center")
            _fill_row(row_idx, copy(section_fill), narrative_last_col)
            _top_black_line(row_idx, narrative_last_col)
            _add_comment(label_cell, note_txt)
            ws.row_dimensions[row_idx].height = 22
            row_idx += 1
            value_parts = _split_overview_value_lines(value_txt)
            for value_part in value_parts:
                lead_txt, rest_txt = _split_overview_prefix(value_part)
                band_fill = copy(row_fill_a if overview_band_idx % 2 == 0 else row_fill_b)
                _fill_row(row_idx, band_fill, narrative_last_col)
                if lead_txt and rest_txt:
                    label_cell = ws.cell(row=row_idx, column=1, value=lead_txt)
                    label_cell.font = Font(bold=True, size=font_size)
                    label_cell.alignment = Alignment(horizontal="left", vertical="top", wrap_text=True)
                    ws.merge_cells(start_row=row_idx, start_column=2, end_row=row_idx, end_column=narrative_last_col)
                    value_cell = ws.cell(row=row_idx, column=2, value=rest_txt)
                    value_cell.font = Font(size=font_size)
                    value_cell.alignment = Alignment(horizontal="left", vertical="top", wrap_text=True)
                    value_text_width = sum(
                        float(ws.column_dimensions[get_column_letter(col)].width or 0.0)
                        for col in range(2, narrative_last_col + 1)
                    ) or merged_text_width
                    label_width = float(ws.column_dimensions["A"].width or 0.0) or 20.0
                    label_height = _estimate_wrapped_row_height(
                        lead_txt,
                        label_width,
                        20,
                        14,
                        min_lines=1,
                        max_lines=4,
                    )
                    value_height = _summary_narrative_row_height(rest_txt, value_text_width)
                    ws.row_dimensions[row_idx].height = max(label_height, value_height)
                else:
                    ws.merge_cells(start_row=row_idx, start_column=1, end_row=row_idx, end_column=narrative_last_col)
                    value_cell = ws.cell(row=row_idx, column=1, value=value_part)
                    value_cell.font = Font(size=font_size)
                    value_cell.alignment = Alignment(horizontal="left", vertical="top", wrap_text=True)
                    ws.row_dimensions[row_idx].height = _summary_narrative_row_height(value_part, merged_text_width)
                ws.row_dimensions[row_idx].height = max(ws.row_dimensions[row_idx].height or 0, 24.0)
                overview_band_idx += 1
                row_idx += 1

        section_order: List[str] = []
        section_groups: Dict[str, List[Dict[str, Any]]] = {}
        for rec in metric_rows:
            sec = str(rec.get("Section") or "").strip()
            if not sec:
                continue
            section_groups.setdefault(sec, []).append(rec)
            if sec not in section_order:
                section_order.append(sec)

        for sec in section_order:
            row_idx = _write_section_header(row_idx, sec, float(header_size), "5B9BD5", "FFFFFF")
            band_idx = 0
            for rec in section_groups.get(sec, []):
                metric_txt = str(rec.get("Metric") or "").strip()
                if not metric_txt:
                    continue
                value = rec.get("Value")
                note_txt = str(rec.get("Note") or "").strip()
                unit_txt = _summary_unit_from_note(note_txt)
                metric_cell = ws.cell(row=row_idx, column=1, value=metric_txt)
                metric_cell.font = Font(size=font_size)
                metric_cell.alignment = Alignment(horizontal="left", vertical="center", wrap_text=True)
                _fill_row(row_idx, copy(row_fill_a if band_idx % 2 == 0 else row_fill_b))
                value_cell = ws.cell(row=row_idx, column=2, value=value)
                if hasattr(value, "year"):
                    value_cell.number_format = "yyyy-mm-dd"
                elif isinstance(value, (int, float)) and pd.notna(value):
                    if unit_txt == "%":
                        value_cell.number_format = "0.0%"
                    elif unit_txt in {"$m", "$/share"}:
                        value_cell.number_format = "#,##0.000"
                    elif unit_txt in {"x", "bps"}:
                        value_cell.number_format = "0.000"
                    else:
                        value_cell.number_format = "#,##0.000"
                else:
                    value_txt = _normalized_value_text(value)
                    value_cell.value = value_txt or "N/A"
                    value_cell.alignment = Alignment(horizontal="left", vertical="top", wrap_text=True)
                if not value_cell.alignment or not value_cell.alignment.wrap_text:
                    value_cell.alignment = Alignment(horizontal="center", vertical="center")
                unit_cell = ws.cell(row=row_idx, column=3, value=unit_txt or None)
                unit_cell.alignment = Alignment(horizontal="left", vertical="center")
                comment_txt = _summary_note_comment(note_txt)
                if comment_txt:
                    _add_comment(metric_cell, comment_txt)
                ws.row_dimensions[row_idx].height = max(ws.row_dimensions[row_idx].height or 18, 22)
                band_idx += 1
                row_idx += 1

    def _write_valuation_sheet() -> None:
        ws = wb.create_sheet(title="Valuation")
        ws.sheet_format.defaultRowHeight = 18
        ws.sheet_view.zoomScale = 110
        style_bundle = _get_valuation_style_bundle()
        # Keep quarter header close to top and freeze at the data start row.
        actuals_row = 5
        quarter_row = 6
        data_start_row = 7
        ws.freeze_panes = f"B{data_start_row}"

        def _px_to_width(px: float) -> float:
            # Approx conversion: Excel column width units from pixels.
            try:
                p = float(px)
            except Exception:
                p = 100.0
            return max(1.0, round((p - 5.0) / 7.0, 2))

        ws["A1"] = "Scale"
        ws["B1"] = "$m"
        ws["A2"] = "Values scaled to $m unless %"
        legend = [
            (3, "<=-15%", "A63A00"),
            (4, "-15..-5", "D55E00"),
            (5, "-5..+5", "DDDDDD"),
            (6, "+5..+15", "9BD3F5"),
            (7, ">=+15%", "2F80ED"),
        ]
        for col, txt, color in legend:
            c = ws.cell(row=1, column=col, value=txt)
            c.fill = PatternFill("solid", fgColor=color)
            c.font = Font(bold=True, size=11)
            c.alignment = Alignment(horizontal="center", vertical="center")

        if hist is None or hist.empty or "quarter" not in hist.columns:
            ws["A4"] = "No data."
            return

        qs = sorted(pd.to_datetime(hist["quarter"], errors="coerce").dropna().unique())
        if not qs:
            ws["A4"] = "No data."
            return
        qs = qs[-12:]
        qs_ts = [pd.Timestamp(q) for q in qs]
        start_col = 2  # B
        last_col = start_col + len(qs) - 1
        last_col_letter = get_column_letter(last_col)
        quarter_columns = [start_col + i for i in range(len(qs_ts))]

        header_fill = copy(style_bundle["header_fill"])
        section_fill = copy(style_bundle["section_fill"])
        input_fill = copy(style_bundle["input_fill"])
        bold = copy(style_bundle["bold_font"])
        regular_font = Font(size=font_size, bold=False)
        center_alignment = Alignment(horizontal="center")
        left_alignment = Alignment(horizontal="left")
        thick = Side(style="thick")
        thin_border = copy(style_bundle["thin_border"])

        # Header rows start after guidance canvas.
        for i, q in enumerate(qs_ts):
            col_idx = quarter_columns[i]
            qd = q.date()
            q_label = f"{qd.year}-Q{((qd.month - 1) // 3) + 1}"
            quarter_cell = ws.cell(row=quarter_row, column=col_idx, value=q_label)
            quarter_cell.font = bold
            quarter_cell.alignment = center_alignment

        # header rows
        quarter_hdr_cell = ws.cell(row=quarter_row, column=1, value="Quarter")
        quarter_hdr_cell.font = bold
        quarter_hdr_cell.alignment = left_alignment
        ws.merge_cells(start_row=actuals_row, start_column=start_col, end_row=actuals_row, end_column=last_col)
        actuals_cell = ws.cell(row=actuals_row, column=start_col, value="Actuals")
        actuals_cell.font = bold
        actuals_cell.alignment = center_alignment
        for col in quarter_columns:
            ws.cell(row=actuals_row, column=col).fill = header_fill
            ws.cell(row=quarter_row, column=col).fill = header_fill

        row_fill_elapsed = 0.0
        row_write_elapsed = 0.0

        def _row_fill(row_idx: int, fill: PatternFill) -> None:
            nonlocal row_fill_elapsed
            row_fill_started = time.perf_counter()
            for col in range(1, last_col + 1):
                ws.cell(row=row_idx, column=col).fill = fill
            row_fill_elapsed += time.perf_counter() - row_fill_started

        def _parse_pct_text(v: Any) -> Any:
            if not isinstance(v, str):
                return v
            s = str(v).strip()
            if not s or s.startswith("=") or "%" not in s:
                return v
            s = s.replace("\u2212", "-").replace("%", "").replace(" ", "").replace(",", ".")
            try:
                return float(s) / 100.0
            except Exception:
                return v

        def _excel_scalar_local(v: Any) -> Any:
            if v is None:
                return None
            try:
                if pd.isna(v):
                    return None
            except Exception:
                pass
            return v

        def _set_row(row_idx: int, label: str, values: Dict[pd.Timestamp, Any], number_format: str) -> None:
            nonlocal row_write_elapsed
            row_write_started = time.perf_counter()
            label_cell = ws.cell(row=row_idx, column=1, value=label)
            label_cell.font = regular_font
            is_pct_format = "%" in str(number_format)
            for i, _q in enumerate(qs_ts):
                col_idx = quarter_columns[i]
                val = values.get(_q)
                if is_pct_format:
                    val = _parse_pct_text(val)
                val = _excel_scalar_local(val)
                data_cell = ws.cell(row=row_idx, column=col_idx, value=val)
                data_cell.number_format = number_format
            row_write_elapsed += time.perf_counter() - row_write_started

        valuation_precompute_started = time.perf_counter()

        with _timed_writer_substage("write_excel.valuation.bundle"):
            render_bundle = _ensure_valuation_render_bundle(tuple(qs_ts), leverage_df)
        h = render_bundle.get("hist_indexed")
