        valuation_audit = dict(valuation_precompute_bundle.get("valuation_audit") or {})
        capital_return_resolved = dict(valuation_precompute_bundle.get("capital_return_resolved") or {})

        def _manifest_local_path(p: Any) -> Optional[Path]:
            if p is None:
                return None
            s = str(p).strip()
            if not s:
                return None
            sl = s.lower()
            if sl.startswith("file:///"):
                s = s[8:]
                if re.match(r"^[A-Za-z]:", s):
                    s = s.replace("/", "\\")
            elif sl.startswith("file://"):
                s = s[7:]
            x = Path(s)
            if x.exists():
                return x
            try_local: List[Path] = [Path.cwd() / s]
            for cr in cache_roots:
                try_local.append(cr / x.name)
                try_local.append(cr / s)
            for cand in try_local:
                if cand.exists():
                    return cand
            return None

        def _load_buyback_auth_source_bundle(manifest_src: pd.DataFrame) -> Dict[str, Any]:
            nonlocal valuation_buyback_auth_source_bundle_cache
            if valuation_buyback_auth_source_bundle_cache is not None:
                return valuation_buyback_auth_source_bundle_cache

            ck_col = None
            path_col = None
            mdf = pd.DataFrame()
            if manifest_src is not None and not manifest_src.empty:
                ck_col = _resolve_col(manifest_src, ["cache_key", "cachekey", "key"])
                path_col = _resolve_col(manifest_src, ["path", "cache_path", "file_path", "local_path"])
                status_col = _resolve_col(manifest_src, ["status"])
                if ck_col is not None and path_col is not None:
                    mdf = manifest_src.copy()
                    if status_col is not None:
                        ok_mask = mdf[status_col].astype(str).str.lower().isin(["ok", "cached", "hit", "success"])
                        if ok_mask.any():
                            mdf = mdf[ok_mask]

            doc_path_by_key: Dict[str, Path] = {}
            manifest_docs_by_accn: Dict[str, List[Tuple[str, Path]]] = {}
            if not mdf.empty and ck_col is not None and path_col is not None:
                for _, rr in mdf.iterrows():
                    k = str(rr.get(ck_col) or "").strip()
                    if not k or not k.startswith("doc_"):
                        continue
                    pth = _manifest_local_path(rr.get(path_col))
                    if pth is not None and pth.exists():
                        doc_path_by_key[k] = pth
                        parts = k.split("_", 2)
                        if len(parts) >= 3 and parts[1]:
                            manifest_docs_by_accn.setdefault(parts[1], []).append((k, pth))

            valuation_buyback_auth_source_bundle_cache = {
                "sub_candidates": _submission_cache_files(),
                "recent_rows": _submission_recent_rows(max_files=8),
                "doc_path_by_key": doc_path_by_key,
                "manifest_docs_by_accn": manifest_docs_by_accn,
                "docs_by_accn": {},
            }
            return valuation_buyback_auth_source_bundle_cache

        def _buyback_auth_docs_for_accession(
            accn_nd: str,
            primary_doc_key: str,
            source_bundle: Dict[str, Any],
        ) -> List[Tuple[str, Path]]:
            docs_cache = source_bundle.setdefault("docs_by_accn", {})
            if accn_nd in docs_cache:
                return list(docs_cache.get(accn_nd) or [])

            doc_path_by_key = dict(source_bundle.get("doc_path_by_key") or {})
            manifest_docs_by_accn = dict(source_bundle.get("manifest_docs_by_accn") or {})
            filing_docs: List[Tuple[str, Path]] = []
            seen_doc_paths: set[str] = set()

            def _add_doc(doc_key: str, doc_path: Optional[Path]) -> None:
                if doc_path is None or not doc_path.exists():
                    return
                try:
                    rk = str(doc_path.resolve())
                except Exception:
                    rk = str(doc_path)
                if rk in seen_doc_paths:
                    return
                seen_doc_paths.add(rk)
                filing_docs.append((doc_key, doc_path))

            _add_doc(primary_doc_key, doc_path_by_key.get(primary_doc_key))
            if primary_doc_key not in doc_path_by_key:
                p_alt = None
                for cr in cache_roots:
                    p_alt = _manifest_local_path(cr / primary_doc_key)
                    if p_alt is not None:
                        break
                if p_alt is None:
                    hits: List[Path] = []
                    for cr in cache_roots:
                        hits.extend(sorted(cr.glob(f"{primary_doc_key}*")))
                    p_alt = hits[0] if hits else None
                _add_doc(primary_doc_key, p_alt)

            for cached_doc in _docs_for_valuation_accn(accn_nd):
                _add_doc(cached_doc.name, cached_doc)

            for dk, dp in manifest_docs_by_accn.get(accn_nd, []):
                _add_doc(dk, dp)

            doc_pref = f"doc_{accn_nd}_"
            for cr in cache_roots:
                for gp in sorted(cr.glob(f"{doc_pref}*")):
                    _add_doc(gp.name, gp)
            for cr in cache_roots:
                ocr_f = cr / f"ocr_{accn_nd}_index_images.txt"
                if ocr_f.exists():
                    _add_doc(f"ocr_{accn_nd}_index_images", ocr_f)
                    break

            docs_cache[accn_nd] = list(filing_docs)
            return list(filing_docs)

        def _extract_latest_buyback_remaining_from_sec(manifest_src: pd.DataFrame) -> Dict[str, Any]:
            out: Dict[str, Any] = {
                "remaining_dollars": None,
                "asof_date": None,
                "accn": None,
                "form": None,
                "doc_key": None,
                "doc_path": None,
                "snippet": None,
            }
            source_bundle = _load_buyback_auth_source_bundle(manifest_src)
            recent_rows = list(source_bundle.get("recent_rows") or [])
            if not recent_rows:
                print("[buyback_auth] no submissions cache file found", flush=True)
                return out

            all_candidates: List[Dict[str, Any]] = []

            def _build_auth_candidate(
                *,
                amount: Optional[float],
                snippet: Any,
                kind: str,
                base_score: int,
                asof_date: Optional[date],
                accn: str,
                form: str,
                doc_key: str,
                doc_path: Path,
                filing_ref_date: Optional[date],
            ) -> Optional[Dict[str, Any]]:
                if amount is None:
                    return None
                snip = str(snippet or "").strip()
                snip_low = snip.lower()
                if "repurchase" not in snip_low and "buyback" not in snip_low:
                    return None
                asof_d = asof_date or filing_ref_date
                if kind.startswith("authorization") and asof_d is not None and filing_ref_date is not None:
                    if (filing_ref_date - asof_d).days > 120 and ("remaining" not in snip_low and "remained" not in snip_low):
                        return None
                score = int(base_score)
                if "remaining" in snip_low or "remained" in snip_low:
                    score += 4
                if "authorized" in snip_low or "authorization" in snip_low:
                    score += 2
                if "available" in snip_low:
                    score += 1
                if "new" in snip_low:
                    score += 1
                if "board" in snip_low:
                    score += 1
                if "as of" in snip_low or "on " in snip_low:
                    score += 1
                return {
                    "remaining_dollars": float(amount),
                    "authorization_dollars": (float(amount) if kind.startswith("authorization") else None),
                    "asof_date": asof_d,
                    "accn": accn,
                    "form": form,
                    "doc_key": doc_key,
                    "doc_path": str(doc_path),
                    "snippet": snip[:360],
                    "kind": kind,
                    "_score": score,
                }

            for row in recent_rows:
                form = str(row.get("form") or "").upper().strip()
                if not (form.startswith("10-Q") or form.startswith("10-K") or form.startswith("8-K")):
                    continue
                accn = str(row.get("accn") or "").strip()
                primary = str(row.get("doc") or "").strip()
                if not accn or not primary:
                    continue
                accn_nd = accn.replace("-", "")
                dkey_primary = f"doc_{accn_nd}_{primary}"
                filing_docs = _buyback_auth_docs_for_accession(accn_nd, dkey_primary, source_bundle)
                if not filing_docs:
                    continue

                filing_ref_date = parse_date(row.get("report")) or parse_date(row.get("filed"))
                best_remaining: Optional[Dict[str, Any]] = None
                best_auth: Optional[Dict[str, Any]] = None
                best_spent_since_start: Optional[Dict[str, Any]] = None

                for doc_key, doc_path in filing_docs:
                    sfx = str(doc_path.suffix or "").lower()
                    if sfx not in {".htm", ".html", ".txt", ".xml"} and "ocr_" not in doc_key.lower():
                        continue
                    analysis = _analyze_cap_alloc_doc(doc_path, include_core=False, include_auth_details=True)
                    if not analysis.get("mentions_cap_alloc"):
                        continue

                    for cand_in in list(analysis.get("remaining_candidates") or []):
                        cand = _build_auth_candidate(
                            amount=cand_in.get("amount"),
                            snippet=cand_in.get("snippet"),
                            kind="remaining",
                            base_score=10,
                            asof_date=cand_in.get("asof_date"),
                            accn=accn,
                            form=form,
                            doc_key=doc_key,
                            doc_path=doc_path,
                            filing_ref_date=filing_ref_date,
                        )
                        if cand is None:
                            continue
                        if best_remaining is None or int(cand["_score"]) > int(best_remaining["_score"]):
                            best_remaining = cand

                    for cand_in in list(analysis.get("authorization_candidates") or []):
                        kind = str(cand_in.get("kind") or "authorization")
                        cand = _build_auth_candidate(
                            amount=cand_in.get("amount"),
                            snippet=cand_in.get("snippet"),
                            kind=kind,
                            base_score=4,
                            asof_date=cand_in.get("asof_date"),
                            accn=accn,
                            form=form,
                            doc_key=doc_key,
                            doc_path=doc_path,
                            filing_ref_date=filing_ref_date,
                        )
                        if cand is None:
                            continue
                        if kind == "authorization_increase_by":
                            cand["authorization_increase_dollars"] = cand.get("remaining_dollars")
                            cand["authorization_dollars"] = None
                            cand["remaining_dollars"] = None
                        if best_auth is None or int(cand["_score"]) > int(best_auth["_score"]):
                            best_auth = cand

                    for cand_in in list(analysis.get("spent_since_start_candidates") or []):
                        spent_amt = cand_in.get("spent_dollars")
                        if spent_amt is None:
                            continue
                        cand = {
                            "spent_dollars": float(spent_amt),
                            "snippet": str(cand_in.get("snippet") or "")[:360],
                            "doc_key": doc_key,
                            "doc_path": str(doc_path),
                            "_score": int(cand_in.get("_score") or 0),
                        }
                        if (
                            best_spent_since_start is None
                            or int(cand["_score"]) > int(best_spent_since_start["_score"])
                        ):
                            best_spent_since_start = cand

                if best_remaining is not None:
                    if best_auth is not None:
                        if best_auth.get("authorization_dollars") is not None:
                            best_remaining["authorization_dollars"] = best_auth.get("authorization_dollars")
                        if best_auth.get("authorization_increase_dollars") is not None:
                            best_remaining["authorization_increase_dollars"] = best_auth.get("authorization_increase_dollars")
                    best_remaining["_filing_date"] = filing_ref_date
                    best_remaining["_kind_pri"] = 3
                    all_candidates.append(best_remaining)
                    continue

                if best_auth is not None:
                    if best_spent_since_start is not None and "increase_by" not in str(best_auth.get("kind") or "").lower():
                        auth_amt = best_auth.get("remaining_dollars")
                        spent_amt = best_spent_since_start.get("spent_dollars")
                        if auth_amt is not None and spent_amt is not None:
                            best_auth["authorization_dollars"] = float(auth_amt)
                            best_auth["spent_since_start_dollars"] = float(spent_amt)
                            best_auth["remaining_dollars"] = max(float(auth_amt) - float(spent_amt), 0.0)
                            best_auth["kind"] = "authorization_less_since_start"
                            best_auth["snippet"] = (
                                f"{str(best_auth.get('snippet') or '').strip()} | {str(best_spent_since_start.get('snippet') or '').strip()}"
                            )[:360]
                    kkind = str(best_auth.get("kind") or "")
                    best_auth["_filing_date"] = filing_ref_date
                    best_auth["_kind_pri"] = 2 if "less_since_start" in kkind or "increase_to" in kkind else 1
                    all_candidates.append(best_auth)

            if all_candidates:
                def _cand_sort_key(c: Dict[str, Any]) -> Tuple[pd.Timestamp, int, int]:
                    fd = c.get("_filing_date")
                    fdt = pd.Timestamp(fd) if fd is not None else pd.Timestamp("1900-01-01")
                    return (
                        fdt,
                        int(c.get("_kind_pri") or 0),
                        int(c.get("_score") or 0),
                    )

                best = sorted(all_candidates, key=_cand_sort_key, reverse=True)[0]
                out.update({k: v for k, v in best.items() if not str(k).startswith("_")})
                rem_m = float(out["remaining_dollars"]) / 1e6 if out.get("remaining_dollars") is not None else float("nan")
                print(
                    f"[buyback_auth] match form={out.get('form')} accn={out.get('accn')} doc={Path(str(out.get('doc_path') or '')).name} "
                    f"kind={out.get('kind')} remaining={rem_m:.1f}m asof={out.get('asof_date')}",
                    flush=True,
                )
                return out

            print("[buyback_auth] no remaining/authorization buyback match in recent SEC filings", flush=True)
            return out

        def _yoy(
            src: Dict[pd.Timestamp, Any],
            positive_prev_only: bool = False,
            positive_cur_only: bool = False,
        ) -> Dict[pd.Timestamp, Any]:
            out: Dict[pd.Timestamp, Any] = {}
            for q in qs:
                q = pd.Timestamp(q)
                prev = q - pd.DateOffset(years=1)
                v = src.get(q)
                p = src.get(prev)
                if v is None or p in (None, 0):
                    out[q] = None
                elif positive_prev_only and p <= 0:
                    out[q] = None
                elif positive_cur_only and v <= 0:
                    out[q] = None
                else:
                    out[q] = (float(v) - float(p)) / abs(float(p))
            return out

        def _margin(num: Dict[pd.Timestamp, Any], denom: Dict[pd.Timestamp, Any]) -> Dict[pd.Timestamp, Any]:
            out: Dict[pd.Timestamp, Any] = {}
            for q in qs:
                q = pd.Timestamp(q)
                n = num.get(q)
                d = denom.get(q)
                if n is None or d in (None, 0):
                    out[q] = None
                else:
                    out[q] = n / d
            return out

        fcf_map: Dict[pd.Timestamp, Any] = {}
        for q in qs:
            q = pd.Timestamp(q)
            cfo = cfo_map.get(q)
            cap = capex_map.get(q)
            fcf_map[q] = (cfo - cap) if (cfo is not None and cap is not None) else None

        # Choose shares for market cap / per-share (prefer outstanding, fallback to diluted per quarter)
        shares_out_has = any(
            (shares_out_map.get(pd.Timestamp(q)) is not None) for q in qs
        ) if shares_out_map else False
        shares_for_value_map: Dict[pd.Timestamp, Any] = {}
        shares_source_map: Dict[pd.Timestamp, Optional[str]] = {}
        for q in qs:
            q = pd.Timestamp(q)
            so = shares_out_map.get(q) if shares_out_map else None
            sd = shares_map.get(q)
            if so is not None:
                shares_for_value_map[q] = so
                shares_source_map[q] = "outstanding"
            elif sd is not None:
                shares_for_value_map[q] = sd
                shares_source_map[q] = "diluted"
            else:
                shares_for_value_map[q] = None
                shares_source_map[q] = None

        # GAAP EPS (derived from net income / diluted shares)
        eps_gaap_map: Dict[pd.Timestamp, Any] = {}
        for q in qs:
            q = pd.Timestamp(q)
            ni = net_income_map.get(q)
            sh = shares_map.get(q)
            if ni is None or sh in (None, 0):
                eps_gaap_map[q] = None
            else:
                eps_gaap_map[q] = float(ni) / float(sh)

        # BV/TBV per share (if equity + shares exist) - prefer period-end shares outstanding
        bv_share_map: Dict[pd.Timestamp, Any] = {}
        tbv_share_map: Dict[pd.Timestamp, Any] = {}
        for q in qs:
            q = pd.Timestamp(q)
            eq = total_equity_map.get(q)
            sh = shares_out_map.get(q) if shares_out_map.get(q) is not None else shares_for_value_map.get(q)
            if eq is None or sh in (None, 0):
                bv_share_map[q] = None
            else:
                bv_share_map[q] = float(eq) / float(sh)
            gw = goodwill_map.get(q)
            ia = intangibles_map.get(q)
            if eq is None or sh in (None, 0):
                tbv_share_map[q] = None
            else:
                if gw is None and ia is None:
                    tbv_share_map[q] = None
                else:
                    tbv_share_map[q] = float(eq - (gw or 0) - (ia or 0)) / float(sh)

        # Adjusted EBITDA from EX-99: strict first, optional relaxed (when excel_mode != clean)
        adj_ebitda_map: Dict[pd.Timestamp, Any] = {}
        adj_source_df = adj_metrics
        if (adj_source_df is None or adj_source_df.empty or "adj_ebitda" not in adj_source_df.columns) and excel_mode != "clean":
            if adj_metrics_relaxed is not None and not adj_metrics_relaxed.empty:
                adj_source_df = adj_metrics_relaxed
        if adj_source_df is not None and not adj_source_df.empty and "quarter" in adj_source_df.columns:
            am = adj_source_df.copy()
            am["quarter"] = pd.to_datetime(am["quarter"], errors="coerce")
            if "adj_ebitda" in am.columns:
                for _, r in am.dropna(subset=["quarter"]).iterrows():
                    adj_ebitda_map[pd.Timestamp(r["quarter"])] = r.get("adj_ebitda")

        # Adjusted FCF (from filings/slides)
        adj_fcf_map: Dict[pd.Timestamp, Any] = {}
        if adj_source_df is not None and not adj_source_df.empty and "quarter" in adj_source_df.columns:
            am = adj_source_df.copy()
            am["quarter"] = pd.to_datetime(am["quarter"], errors="coerce")
            if "adj_fcf" in am.columns:
                for _, r in am.dropna(subset=["quarter"]).iterrows():
                    adj_fcf_map[pd.Timestamp(r["quarter"])] = r.get("adj_fcf")
        def _safe_float_or_none_local(value: Any) -> Optional[float]:
            try:
                coerced = pd.to_numeric(value, errors="coerce")
            except Exception:
                coerced = np.nan
            if pd.isna(coerced):
                return None
            try:
                return float(coerced)
            except Exception:
                return None
        adj_ebitda_diff_map: Dict[pd.Timestamp, Any] = {}
        for q in qs:
            q = pd.Timestamp(q)
            ae = _safe_float_or_none_local(adj_ebitda_map.get(q))
            ge = _safe_float_or_none_local(ebitda_map.get(q))
            if ae is None or ge is None:
                adj_ebitda_diff_map[q] = None
            else:
                adj_ebitda_diff_map[q] = ae - ge
        adj_fcf_diff_map: Dict[pd.Timestamp, Any] = {}
        for q in qs:
            q = pd.Timestamp(q)
            af = _safe_float_or_none_local(adj_fcf_map.get(q))
            gf = _safe_float_or_none_local(fcf_map.get(q))
            if af is None or gf is None:
                adj_fcf_diff_map[q] = None
            else:
                adj_fcf_diff_map[q] = af - gf

        # Adj EPS if available (same source as adj EBITDA)
        adj_eps_map: Dict[pd.Timestamp, Any] = {}
        if adj_source_df is not None and not adj_source_df.empty and "quarter" in adj_source_df.columns:
            am = adj_source_df.copy()
            am["quarter"] = pd.to_datetime(am["quarter"], errors="coerce")
            for col in ["adj_eps", "adj_eps_diluted", "adjusted_eps", "adj_eps_gaap"]:
                if col in am.columns:
                    for _, r in am.dropna(subset=["quarter"]).iterrows():
                        adj_eps_map[pd.Timestamp(r["quarter"])] = r.get(col)
                    break

        def _ttm_map(src: Dict[pd.Timestamp, Any]) -> Dict[pd.Timestamp, Any]:
            out: Dict[pd.Timestamp, Any] = {}
            for q in qs_ts:
                last4 = last4_quarters_map.get(pd.Timestamp(q))
                if not last4:
                    continue
                vals = [_safe_float_or_none_local(src.get(qq)) for qq in last4]
                if any(v is None for v in vals):
                    out[pd.Timestamp(q)] = None
                else:
                    out[pd.Timestamp(q)] = float(sum(vals))
            return out

        adj_ebitda_ttm_map = _ttm_map(adj_ebitda_map) if adj_ebitda_map else {}
        adj_fcf_ttm_map = _ttm_map(adj_fcf_map) if adj_fcf_map else {}
        adj_ebit_map: Dict[pd.Timestamp, Any] = {}
        if adj_metrics is not None and not adj_metrics.empty and "quarter" in adj_metrics.columns:
            am = _adj_metrics_view().copy()
            if "_quarter" in am.columns:
                am["quarter"] = am["_quarter"]
            if "adj_ebit" in am.columns:
                for _, r in am.dropna(subset=["quarter"]).iterrows():
                    adj_ebit_map[pd.Timestamp(r["quarter"])] = r.get("adj_ebit")
        adj_ebit_ttm_map = _ttm_map(adj_ebit_map) if adj_ebit_map else {}
        adj_eps_ttm_map = _ttm_map(adj_eps_map) if adj_eps_map else {}
        fcf_ttm_map = _ttm_map(fcf_map)
        rev_ttm_map = _ttm_map(rev_map)
        net_income_ttm_map = _ttm_map(net_income_map) if net_income_map else {}
        ebit_ttm_map = _ttm_map(ebit_map) if ebit_map else {}
        capex_ttm_map = _ttm_map(capex_map)
        buyback_ttm_map = dict(valuation_precompute_bundle.get("buyback_ttm_resolved_map") or (_ttm_map(buyback_map) if buyback_map else {}))
        dividend_ttm_map = dict(valuation_precompute_bundle.get("dividend_ttm_resolved_map") or (_ttm_map(dividend_map) if dividend_map else {}))
        acquisitions_ttm_map = _ttm_map(acquisitions_map) if acquisitions_map else {}
        debt_repay_ttm_map = _ttm_map(debt_repay_map) if debt_repay_map else {}
        debt_issuance_ttm_map = _ttm_map(debt_issuance_map) if debt_issuance_map else {}
        buyback_shares_ttm_map = dict(valuation_precompute_bundle.get("buyback_shares_ttm_resolved_map") or (_ttm_map(buyback_shares_map) if buyback_shares_map else {}))
        market_cap_for_yield_map: Dict[pd.Timestamp, Any] = {}
        for q in qs:
            q = pd.Timestamp(q)
            mc = market_cap_map.get(q)
            if mc is None:
                px = price_map.get(q)
                sh = shares_for_value_map.get(q)
                if px is not None and sh not in (None, 0):
                    mc = float(px) * float(sh)
            market_cap_for_yield_map[q] = mc
        fcf_yield_ttm_map: Dict[pd.Timestamp, Any] = {}
        for q in qs:
            q = pd.Timestamp(q)
            fcf_t = fcf_ttm_map.get(q)
            mc = market_cap_for_yield_map.get(q)
            if fcf_t is None or mc in (None, 0) or (mc is not None and mc <= 0):
                fcf_yield_ttm_map[q] = None
            else:
                fcf_yield_ttm_map[q] = float(fcf_t) / float(mc)
        # Keep FCF yield live against Price input when market cap is missing.
        fcf_yield_ttm_display: Dict[pd.Timestamp, Any] = {}
        for q in qs:
            q = pd.Timestamp(q)
            v = fcf_yield_ttm_map.get(q)
            if v is not None:
                fcf_yield_ttm_display[q] = v
                continue
            fcf_t = fcf_ttm_map.get(q)
            sh = shares_for_value_map.get(q)
            if fcf_t is None or sh in (None, 0):
                fcf_yield_ttm_display[q] = None
                continue
            fcf_yield_ttm_display[q] = f"=IF(OR(Price=\"\",Price<=0),\"\",{float(fcf_t)}/(Price*{float(sh)}))"
        owner_maint_capex_ratio_default = 0.70
        owner_fcf_proxy_map: Dict[pd.Timestamp, Any] = {}
        for q in qs:
            q = pd.Timestamp(q)
            cfo = cfo_map.get(q)
            cap = capex_map.get(q)
            if cfo is None or cap is None:
                owner_fcf_proxy_map[q] = None
            else:
                owner_fcf_proxy_map[q] = float(cfo) - float(cap) * owner_maint_capex_ratio_default

        _record_writer_substage("write_excel.valuation.precompute", valuation_precompute_started)
        valuation_render_started = time.perf_counter()

        r = data_start_row
        ws[f"A{r}"] = "Operating"
        ws[f"A{r}"].font = bold
        _row_fill(r, section_fill)
        r += 1

        _set_row(r, "Revenue", {k: (v / 1e6) if v is not None else None for k, v in rev_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Revenue (TTM)", {k: (v / 1e6) if v is not None else None for k, v in rev_ttm_map.items()}, "#,##0.000")
        r += 1
        revenue_yoy_row = r
        _set_row(r, "Revenue YoY %", _yoy(rev_map), "0.0%")
        r += 2
        _set_row(r, "Gross margin %", _margin(gross_profit_map, rev_map), "0.0%")
        r += 1
        _set_row(r, "Operating margin %", _margin(ebit_map, rev_map), "0.0%")
        r += 1
        _set_row(r, "R&D % of revenue", _margin(rd_map, rev_map), "0.0%")
        r += 2
        _set_row(r, "EBITDA", {k: (v / 1e6) if v is not None else None for k, v in ebitda_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "EBITDA margin %", _margin(ebitda_map, rev_map), "0.0%")
        r += 1
        ebitda_yoy_row = r
        _set_row(r, "EBITDA YoY %", _yoy(ebitda_map), "0.0%")
        r += 1
        _set_row(r, "EBITDA (TTM)", {k: (v / 1e6) if v is not None else None for k, v in ebitda_ttm_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "EBITDA margin (TTM)", _margin(ebitda_ttm_map, rev_ttm_map), "0.0%")
        r += 2
        _set_row(r, "EBIT", {k: (v / 1e6) if v is not None else None for k, v in ebit_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "EBIT margin %", _margin(ebit_map, rev_map), "0.0%")
        r += 1
        _set_row(r, "EBIT (TTM)", {k: (v / 1e6) if v is not None else None for k, v in ebit_ttm_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "EBIT margin (TTM)", _margin(ebit_ttm_map, rev_ttm_map), "0.0%")
        r += 2
        _set_row(r, "Net income", {k: (v / 1e6) if v is not None else None for k, v in net_income_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Net income margin %", _margin(net_income_map, rev_map), "0.0%")
        r += 1
        _set_row(r, "Net income YoY %", _yoy(net_income_map), "0.0%")
        r += 1
        if net_income_ttm_map:
            _set_row(r, "Net income (TTM)", {k: (v / 1e6) if v is not None else None for k, v in net_income_ttm_map.items()}, "#,##0.000")
            r += 1
            _set_row(r, "Net income margin (TTM)", _margin(net_income_ttm_map, rev_ttm_map), "0.0%")
            r += 2

        # Adjusted EBITDA (from filings) - always show rows
        _set_row(r, "Adj EBITDA", {k: (v / 1e6) if v is not None else None for k, v in adj_ebitda_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Adj EBITDA - EBITDA", {k: (v / 1e6) if v is not None else None for k, v in adj_ebitda_diff_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Adj EBITDA margin %", _margin(adj_ebitda_map, rev_map), "0.0%")
        r += 1
        adj_ebitda_yoy_row = r
        _set_row(r, "Adj EBITDA YoY %", _yoy(adj_ebitda_map), "0.0%")
        r += 2
        # TTM metrics
        _set_row(r, "Adj EBITDA (TTM)", {k: (v / 1e6) if v is not None else None for k, v in adj_ebitda_ttm_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Adj EBITDA margin (TTM)", _margin(adj_ebitda_ttm_map, rev_ttm_map), "0.0%")
        r += 1
        if adj_ebit_ttm_map:
            _set_row(r, "Adj EBIT (TTM)", {k: (v / 1e6) if v is not None else None for k, v in adj_ebit_ttm_map.items()}, "#,##0.000")
            r += 2

        ws[f"A{r}"] = "Cash Flow"
        ws[f"A{r}"].font = bold
        _row_fill(r, section_fill)
        r += 1
        _set_row(r, "CFO", {k: (v / 1e6) if v is not None else None for k, v in cfo_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Capex", {k: (v / 1e6) if v is not None else None for k, v in capex_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "FCF (CFO-Capex)", {k: (v / 1e6) if v is not None else None for k, v in fcf_map.items()}, "#,##0.000")
        r += 2
        # FCF YoY Δ ($m) is more robust when prior-year is negative/near-zero
        fcf_yoy_delta: Dict[pd.Timestamp, Any] = {}
        for q in qs:
            q = pd.Timestamp(q)
            prev = q - pd.DateOffset(years=1)
            v = fcf_map.get(q)
            p = fcf_map.get(prev)
            if v is None or p is None:
                fcf_yoy_delta[q] = None
            else:
                fcf_yoy_delta[q] = v - p
        fcf_yoy_row = r
        _set_row(r, "FCF YoY Δ ($m)", {k: (v / 1e6) if v is not None else None for k, v in fcf_yoy_delta.items()}, "#,##0.000")
        r += 1
        _set_row(r, "FCF (TTM)", {k: (v / 1e6) if v is not None else None for k, v in fcf_ttm_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "FCF margin (TTM)", _margin(fcf_ttm_map, rev_ttm_map), "0.0%")
        r += 1
        _set_row(r, "FCF yield (TTM, equity)", fcf_yield_ttm_display, "0.0%")
        r += 2
        _set_row(r, "Adj FCF - FCF", {k: (v / 1e6) if v is not None else None for k, v in adj_fcf_diff_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Owner earnings (proxy)", {k: (v / 1e6) if v is not None else None for k, v in owner_fcf_proxy_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Owner earnings margin %", _margin(owner_fcf_proxy_map, rev_map), "0.0%")
        r += 2
        _set_row(r, "Buybacks (TTM, cash)", {k: (v / 1e6) if v is not None else None for k, v in buyback_ttm_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Dividends (TTM, cash)", {k: (v / 1e6) if v is not None else None for k, v in dividend_ttm_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Acquisitions (TTM, cash)", {k: (v / 1e6) if v is not None else None for k, v in acquisitions_ttm_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Debt repaid (TTM)", {k: (v / 1e6) if v is not None else None for k, v in debt_repay_ttm_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Debt issued (TTM)", {k: (v / 1e6) if v is not None else None for k, v in debt_issuance_ttm_map.items()}, "#,##0.000")
        r += 2
        _set_row(r, "FCF margin %", _margin(fcf_map, rev_map), "0.0%")
        r += 1
        capex_pct_map = _margin(capex_map, rev_map)
        _set_row(r, "Capex % of revenue", capex_pct_map, "0.0%")
        r += 1
        # TTM capex % of revenue
        capex_ttm_pct = _margin(capex_ttm_map, rev_ttm_map)
        _set_row(r, "Capex % of revenue (TTM)", capex_ttm_pct, "0.0%")
        r += 1
        _set_row(r, "Interest paid", {k: (v / 1e6) if v is not None else None for k, v in int_paid_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Tax paid", {k: (v / 1e6) if v is not None else None for k, v in tax_paid_map.items()}, "#,##0.000")
        r += 2

        ws[f"A{r}"] = "Leverage & Liquidity"
        ws[f"A{r}"].font = bold
        _row_fill(r, section_fill)
        r += 1
        _set_row(r, "Cash", {k: (v / 1e6) if v is not None else None for k, v in cash_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Debt (core)", {k: (v / 1e6) if v is not None else None for k, v in debt_core_map.items()}, "#,##0.000")
        r += 1
        if pension_map:
            _set_row(r, "Net pension / OPEB", {k: (v / 1e6) if v is not None else None for k, v in pension_map.items()}, "#,##0.000")
            r += 1
        net_debt_map = {}
        for q in qs:
            q = pd.Timestamp(q)
            d = debt_core_map.get(q)
            c = cash_map.get(q)
            net_debt_map[q] = (d - c) if (d is not None and c is not None) else None
        _set_row(r, "Net debt (core)", {k: (v / 1e6) if v is not None else None for k, v in net_debt_map.items()}, "#,##0.000")
        r += 1
        net_debt_qoq_delta = {}
        for q in qs:
            q = pd.Timestamp(q)
            prev_d = _prev_quarter_end_from_qend(q.date())
            prev = pd.Timestamp(prev_d) if prev_d else (q - pd.DateOffset(months=3))
            v = net_debt_map.get(q)
            p = net_debt_map.get(prev)
            if v is None or p is None:
                net_debt_qoq_delta[q] = None
            else:
                net_debt_qoq_delta[q] = v - p
        _set_row(r, "Net debt QoQ Δ ($m)", {k: (v / 1e6) if v is not None else None for k, v in net_debt_qoq_delta.items()}, "#,##0.000")
        r += 1
        net_debt_yoy_delta = {}
        for q in qs:
            q = pd.Timestamp(q)
            prev = q - pd.DateOffset(years=1)
            v = net_debt_map.get(q)
            p = net_debt_map.get(prev)
            if v is None or p is None:
                net_debt_yoy_delta[q] = None
            else:
                net_debt_yoy_delta[q] = v - p
        _set_row(r, "Net debt YoY Δ ($m)", {k: (v / 1e6) if v is not None else None for k, v in net_debt_yoy_delta.items()}, "#,##0.000")
        r += 2  # blank spacer row
        _set_row(r, "EBITDA TTM", {k: (v / 1e6) if v is not None else None for k, v in ebitda_ttm_map.items()}, "#,##0.000")
        r += 1
        def _nm_display_map(raw_map: Dict[pd.Timestamp, Any], audit_key: str, denom_audit_key: str) -> Dict[pd.Timestamp, Any]:
            out: Dict[pd.Timestamp, Any] = {}
            for q in qs:
                qts = pd.Timestamp(q)
                audit_row = dict((valuation_audit.get(qts) or {}).get(audit_key) or {})
                denom_row = dict((valuation_audit.get(qts) or {}).get(denom_audit_key) or {})
                suppress_reason = str(audit_row.get("suppress_reason") or "").strip().lower()
                if "<= 0" in suppress_reason:
                    out[qts] = "N/M"
                    continue
                raw_val = audit_row.get("value")
                if raw_val is None:
                    raw_val = raw_map.get(qts)
                if raw_val is not None:
                    out[qts] = raw_val
                    continue
                denom_val = pd.to_numeric(denom_row.get("value"), errors="coerce")
                denom_val = float(denom_val) if pd.notna(denom_val) else None
                if denom_val is not None and denom_val <= 0:
                    out[qts] = "N/M"
                else:
                    out[qts] = None
            return out

        net_lev_display_map = _nm_display_map(net_lev_map, "net_leverage", "gaap_ebitda_ttm")
        net_lev_adj_display_map: Dict[pd.Timestamp, Any] = {}
        cov_pnl_display_map: Dict[pd.Timestamp, Any] = {}
        cov_cash_display_map: Dict[pd.Timestamp, Any] = {}
        _set_row(r, "Net leverage", net_lev_display_map, "#,##0.00")
        r += 1
        # Net leverage (Adj EBITDA TTM) if available
        net_lev_adj_map: Dict[pd.Timestamp, Any] = {}
        if adj_ebitda_ttm_map:
            for q in qs:
                q = pd.Timestamp(q)
                nd = net_debt_map.get(q)
                ae = adj_ebitda_ttm_map.get(q)
                if nd is None or ae in (None, 0):
                    net_lev_adj_map[q] = None
                else:
                    net_lev_adj_map[q] = nd / ae
        if net_lev_adj_map:
            net_lev_adj_display_map = _nm_display_map(net_lev_adj_map, "net_leverage_adj", "adj_ebitda_ttm")
            _set_row(r, "Net leverage (Adj)", net_lev_adj_display_map, "#,##0.00")
            r += 1
        if cov_pnl_map:
            cov_pnl_display_map = _nm_display_map(cov_pnl_map, "interest_coverage_pnl", "gaap_ebitda_ttm")
            _set_row(r, "Interest coverage (P&L TTM)", cov_pnl_display_map, "#,##0.00")
            r += 1
        cov_cash_map = {}
        for q in qs:
            q = pd.Timestamp(q)
            e = ebitda_ttm_map.get(q)
            i = int_paid_ttm_map.get(q)
            if e is None or i in (None, 0):
                cov_cash_map[q] = None
            else:
                cov_cash_map[q] = e / abs(i)
        cov_cash_display_map = _nm_display_map(cov_cash_map, "cash_interest_coverage", "gaap_ebitda_ttm")
        _set_row(r, "Cash interest coverage (TTM)", cov_cash_display_map, "#,##0.00")
        r += 1
        fcf_conv_map = {}
        for q in qs_ts:
            e = adj_ebitda_ttm_map.get(q) if adj_ebitda_ttm_map else ebitda_ttm_map.get(q)
            # compute FCF TTM from last 4 quarters
            fcf_ttm = None
            last4 = last4_quarters_map.get(q)
            if last4:
                cfo_sum = sum([cfo_map.get(qq) or 0 for qq in last4]) if all([cfo_map.get(qq) is not None for qq in last4]) else None
                cap_sum = sum([capex_map.get(qq) or 0 for qq in last4]) if all([capex_map.get(qq) is not None for qq in last4]) else None
                if cfo_sum is not None and cap_sum is not None:
                    fcf_ttm = cfo_sum - cap_sum
            if e in (None, 0) or fcf_ttm is None:
                fcf_conv_map[q] = None
            else:
                fcf_conv_map[q] = fcf_ttm / e
        _set_row(r, "FCF conversion (TTM)", fcf_conv_map, "0.0%")
        r += 2  # blank spacer row
        _set_row(r, "Revolver capacity", {k: (v / 1e6) if v is not None else None for k, v in rev_commit_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Revolver facility size", {k: (v / 1e6) if v is not None else None for k, v in rev_facility_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Revolver drawn", {k: (v / 1e6) if v is not None else None for k, v in rev_drawn_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Revolver letters of credit", {k: (v / 1e6) if v is not None else None for k, v in rev_lc_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Revolver availability", {k: (v / 1e6) if v is not None else None for k, v in rev_avail_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Liquidity (cash+availability)", {k: (v / 1e6) if v is not None else None for k, v in liquidity_map.items()}, "#,##0.000")
        r += 2
        _set_row(r, "Total assets ($m)", {k: (v / 1e6) if v is not None else None for k, v in assets_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Total liabilities ($m)", {k: (v / 1e6) if v is not None else None for k, v in liabilities_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Current ratio", _margin(assets_current_map, liabilities_current_map), "#,##0.00")
        r += 1
        quick_ratio_map: Dict[pd.Timestamp, Any] = {}
        for _q in qs:
            _q = pd.Timestamp(_q)
            cash_v = cash_map.get(_q)
            sti_v = sti_map.get(_q)
            ar_v = ar_map.get(_q)
            lc = liabilities_current_map.get(_q)
            if cash_v is None or ar_v is None or lc in (None, 0):
                quick_ratio_map[_q] = None
            else:
                quick_ratio_map[_q] = (float(cash_v) + float(sti_v or 0.0) + float(ar_v)) / float(lc)
        _set_row(r, "Quick ratio", quick_ratio_map, "#,##0.00")
        r += 1
        _set_row(r, "Goodwill % of assets", _margin(goodwill_map, assets_map), "0.0%")
        r += 2

        # Equity / Per-share
        ws[f"A{r}"] = "Equity / Per-share"
        ws[f"A{r}"].font = bold
        _row_fill(r, section_fill)
        r += 1
        _set_row(r, "Diluted shares (m)", {k: (v / 1e6) if v is not None else None for k, v in shares_map.items()}, "#,##0.000")
        r += 1
        _set_row(r, "Shares outstanding (m)", {k: (v / 1e6) if v is not None else None for k, v in shares_out_map.items()}, "#,##0.000")
        r += 1
        shares_change_base = shares_out_map if shares_out_has else shares_map
        shares_change_label = "Shares QoQ Δ (m) [out]" if shares_out_has else "Shares QoQ Δ (m) [dil]"
        shares_qoq_delta = {}
        for q in qs:
            q = pd.Timestamp(q)
            prev_d = _prev_quarter_end_from_qend(q.date())
            prev = pd.Timestamp(prev_d) if prev_d else (q - pd.DateOffset(months=3))
            v = shares_change_base.get(q)
            p = shares_change_base.get(prev)
            if v is None or p is None:
                shares_qoq_delta[q] = None
            else:
                shares_qoq_delta[q] = v - p
        _set_row(r, shares_change_label, {k: (v / 1e6) if v is not None else None for k, v in shares_qoq_delta.items()}, "#,##0.000")
        r += 1
        shares_yoy_label = "Shares YoY Δ (m) [out]" if shares_out_has else "Shares YoY Δ (m) [dil]"
        shares_yoy_delta = {}
        for q in qs:
            q = pd.Timestamp(q)
            prev = q - pd.DateOffset(years=1)
            v = shares_change_base.get(q)
            p = shares_change_base.get(prev)
            if v is None or p is None:
                shares_yoy_delta[q] = None
            else:
                shares_yoy_delta[q] = v - p
        _set_row(r, shares_yoy_label, {k: (v / 1e6) if v is not None else None for k, v in shares_yoy_delta.items()}, "#,##0.000")
        r += 2  # blank spacer row
        _set_row(r, "EPS (GAAP)", eps_gaap_map, "#,##0.000")
        r += 1
        eps_yoy_delta = {}
        for q in qs:
            q = pd.Timestamp(q)
            prev = q - pd.DateOffset(years=1)
            v = eps_gaap_map.get(q)
            p = eps_gaap_map.get(prev)
            if v is None or p is None:
                eps_yoy_delta[q] = None
            else:
                eps_yoy_delta[q] = v - p
        _set_row(r, "EPS YoY Δ ($)", eps_yoy_delta, "#,##0.000")
        r += 1
        # EPS TTM per quarter (if NI + shares available)
        eps_ttm_map: Dict[pd.Timestamp, Any] = {}
        for i, q in enumerate(qs_ts):
            if i < 3:
                continue
            last4 = last4_quarters_map.get(q) or ()
            ni_vals = [net_income_map.get(qq) for qq in last4]
            sh_vals = [shares_map.get(qq) for qq in last4]
            if any(v is None for v in ni_vals) or any(v in (None, 0) for v in sh_vals):
                eps_ttm_map[q] = None
            else:
                ni_ttm = float(sum(ni_vals))
                sh_avg = float(sum(sh_vals)) / 4.0
                eps_ttm_map[q] = ni_ttm / sh_avg if sh_avg != 0 else None
        if eps_ttm_map:
            _set_row(r, "EPS (TTM)", eps_ttm_map, "#,##0.000")
            r += 2  # blank spacer row between EPS (TTM) and Adj EPS
        # EPS YoY % removed per request (use YoY Δ instead)
        if adj_eps_map:
            _set_row(r, "Adj EPS", adj_eps_map, "#,##0.000")
            r += 1
        if adj_eps_ttm_map:
            _set_row(r, "Adj EPS (TTM)", adj_eps_ttm_map, "#,##0.000")
            r += 2  # blank spacer row
        _set_row(r, "BV/share", bv_share_map, "#,##0.000")
        r += 1
        _set_row(r, "TBV/share", tbv_share_map, "#,##0.000")
        r += 1
        # FCF/share (TTM)
        fcf_per_share_ttm = {}
        for q in qs:
            q = pd.Timestamp(q)
            fcf_t = fcf_ttm_map.get(q)
            sh = shares_for_value_map.get(q)
            if fcf_t is None or sh in (None, 0):
                fcf_per_share_ttm[q] = None
            else:
                fcf_per_share_ttm[q] = float(fcf_t) / float(sh)
        _set_row(r, "FCF/share (TTM)", fcf_per_share_ttm, "#,##0.000")
        r += 2
        # EV / yield rows (TTM-based, where market-cap and debt/cash are available)
        # If historical market cap is missing, keep rows live using current Price input
        # against quarter-specific shares/debt/cash (same pattern as FCF yield (equity)).
        ev_ttm_map: Dict[pd.Timestamp, Any] = {}
        ev_ebitda_ttm_map: Dict[pd.Timestamp, Any] = {}
        ev_adj_ebitda_ttm_map: Dict[pd.Timestamp, Any] = {}
        fcf_yield_ev_ttm_map: Dict[pd.Timestamp, Any] = {}
        ev_ttm_display: Dict[pd.Timestamp, Any] = {}
        ev_ebitda_ttm_display: Dict[pd.Timestamp, Any] = {}
        ev_adj_ebitda_ttm_display: Dict[pd.Timestamp, Any] = {}
        fcf_yield_ev_ttm_display: Dict[pd.Timestamp, Any] = {}
        for q in qs:
            q = pd.Timestamp(q)
            mc = market_cap_for_yield_map.get(q)
            d = debt_core_map.get(q)
            c = cash_map.get(q)
            sh = shares_for_value_map.get(q)
            ev_val = None
            if mc is not None and d is not None and c is not None:
                ev_val = float(mc) + (float(d) - float(c))
            ev_ttm_map[q] = ev_val
            eb_ttm = ebitda_ttm_map.get(q)
            aeb_ttm = adj_ebitda_ttm_map.get(q) if adj_ebitda_ttm_map else None
            fcf_t = fcf_ttm_map.get(q)
            ev_ebitda_ttm_map[q] = (ev_val / eb_ttm) if (ev_val is not None and eb_ttm not in (None, 0)) else None
            ev_adj_ebitda_ttm_map[q] = (ev_val / aeb_ttm) if (ev_val is not None and aeb_ttm not in (None, 0)) else None
            fcf_yield_ev_ttm_map[q] = (fcf_t / ev_val) if (fcf_t is not None and ev_val not in (None, 0)) else None

            # Display values: prefer numeric history, otherwise formula fallback via Price input.
            if ev_val is not None:
                ev_ttm_display[q] = float(ev_val) / 1e6
            else:
                ev_ttm_display[q] = None
            ev_ebitda_ttm_display[q] = ev_ebitda_ttm_map.get(q)
            ev_adj_ebitda_ttm_display[q] = ev_adj_ebitda_ttm_map.get(q)
            fcf_yield_ev_ttm_display[q] = fcf_yield_ev_ttm_map.get(q)

            if (
                ev_val is None
                and sh not in (None, 0)
                and d is not None
                and c is not None
            ):
                ev_expr = f"(Price*{float(sh)}+{float(d)}-{float(c)})"
                ev_guard = f"OR(Price=\"\",Price<=0,({ev_expr})<=0)"
                ev_ttm_display[q] = f"=IF({ev_guard},\"\",{ev_expr}/1e6)"
                if eb_ttm not in (None, 0):
                    ev_ebitda_ttm_display[q] = f"=IF({ev_guard},\"\",{ev_expr}/{float(eb_ttm)})"
                if aeb_ttm not in (None, 0):
                    ev_adj_ebitda_ttm_display[q] = f"=IF({ev_guard},\"\",{ev_expr}/{float(aeb_ttm)})"
                if fcf_t is not None:
                    fcf_yield_ev_ttm_display[q] = f"=IF({ev_guard},\"\",{float(fcf_t)}/{ev_expr})"

        _set_row(r, "EV ($m)", ev_ttm_display, "#,##0.000")
        r += 1
        _set_row(r, "EV/EBITDA (TTM)", ev_ebitda_ttm_display, "0.00x")
        r += 1
        _set_row(r, "EV/Adj EBITDA (TTM)", ev_adj_ebitda_ttm_display, "0.00x")
        r += 1
        _set_row(r, "FCF yield (TTM, EV)", fcf_yield_ev_ttm_display, "0.0%")
        r += 2

        # Debt detail (latest)
        tieout_diff_m: Optional[float] = None
        ws[f"A{r}"] = "Debt Detail (latest)"
        ws[f"A{r}"].font = bold
        _row_fill(r, section_fill)
        r += 1
        debt_header_map = {
            1: "Year/Label",
            2: "Principal due ($m)",
            3: "Rate type",
            4: "Coupon/Spread %",
            6: "Maturity",
            7: "Conversion price",
            9: "Added shares on full conversion (m)",
            12: "Concurrent repurchased shares (m)",
            15: "Basis",
            17: "Source",
        }
        for col_idx, h in debt_header_map.items():
            cell = ws.cell(row=r, column=col_idx, value=h)
            cell.font = bold
            cell.fill = header_fill
        try:
            ws.merge_cells(start_row=r, start_column=7, end_row=r, end_column=8)
        except Exception:
            pass
        try:
            ws.merge_cells(start_row=r, start_column=9, end_row=r, end_column=11)
        except Exception:
            pass
        try:
            ws.merge_cells(start_row=r, start_column=12, end_row=r, end_column=14)
        except Exception:
            pass
        try:
            ws.merge_cells(start_row=r, start_column=15, end_row=r, end_column=16)
        except Exception:
            pass
        try:
            ws.merge_cells(start_row=r, start_column=17, end_row=r, end_column=18)
        except Exception:
            pass
        r += 1
        latest_debt_review = False
        if debt_tranches_latest is not None and not debt_tranches_latest.empty:
            df = debt_tranches_latest.copy()
            latest_debt_review = bool(
                ("source_kind" in df.columns and df["source_kind"].astype(str).str.lower().eq("qa_guardrail").any())
                or ("tranche_name" in df.columns and df["tranche_name"].astype(str).str.contains("Needs review", case=False, na=False).any())
            )
            sum_listed_principal = 0.0
            near_term = 0.0
            carrying_total_m = None
            principal_total_m = None
            carrying_minus_principal_m = None
            debt_current_latest_m = None
            debt_long_term_latest_m = None
            if debt_profile is not None and not debt_profile.empty:
                dpf = debt_profile.copy()
                if "metric" in dpf.columns and "value" in dpf.columns:
                    try:
                        v = pd.to_numeric(dpf.loc[dpf["metric"] == "debt_carrying_total", "value"], errors="coerce").dropna()
                        if not v.empty:
                            carrying_total_m = float(v.iloc[-1]) / 1e6
                    except Exception:
                        pass
                    try:
                        v = pd.to_numeric(dpf.loc[dpf["metric"] == "debt_principal_total", "value"], errors="coerce").dropna()
                        if not v.empty:
                            principal_total_m = float(v.iloc[-1]) / 1e6
                    except Exception:
                        pass
                    try:
                        v = pd.to_numeric(
                            dpf.loc[dpf["metric"] == "debt_net_discounts_issuance_costs", "value"],
                            errors="coerce",
                        ).dropna()
                        if not v.empty:
                            carrying_minus_principal_m = float(v.iloc[-1]) / 1e6
                    except Exception:
                        pass
                    try:
                        v = pd.to_numeric(dpf.loc[dpf["metric"] == "debt_current", "value"], errors="coerce").dropna()
                        if not v.empty:
                            debt_current_latest_m = float(v.iloc[-1]) / 1e6
                    except Exception:
                        pass
                    try:
                        v = pd.to_numeric(dpf.loc[dpf["metric"] == "debt_long_term", "value"], errors="coerce").dropna()
                        if not v.empty:
                            debt_long_term_latest_m = float(v.iloc[-1]) / 1e6
                    except Exception:
                        pass
            if latest_debt_review and debt_maturity is not None and not debt_maturity.empty:
                for col_idx, header in debt_header_map.items():
                    cell = ws.cell(row=r - 1, column=col_idx, value=header)
                    cell.font = bold
                    cell.fill = header_fill
                try:
                    ws.merge_cells(start_row=r - 1, start_column=7, end_row=r - 1, end_column=8)
                    ws.merge_cells(start_row=r - 1, start_column=9, end_row=r - 1, end_column=11)
                    ws.merge_cells(start_row=r - 1, start_column=12, end_row=r - 1, end_column=14)
                    ws.merge_cells(start_row=r - 1, start_column=15, end_row=r - 1, end_column=16)
                    ws.merge_cells(start_row=r - 1, start_column=17, end_row=r - 1, end_column=18)
                except Exception:
                    pass
                mat_latest = debt_maturity.copy()
                if "quarter" in mat_latest.columns:
                    mat_latest["quarter"] = pd.to_datetime(mat_latest["quarter"], errors="coerce")
                    mat_latest = mat_latest[mat_latest["quarter"].dt.to_period("Q") == pd.Timestamp(qs[-1]).to_period("Q")]
                max_rows = 8
                mat_latest = mat_latest.head(max_rows)
                basis_label = "principal_excl_issuance_costs"
                if "source_basis" in mat_latest.columns:
                    vals = [str(v).strip() for v in mat_latest["source_basis"].dropna().tolist() if str(v).strip()]
                    if vals:
                        basis_label = vals[0]
                for _, row in mat_latest.iterrows():
                    amt_total = pd.to_numeric(row.get("amount_total"), errors="coerce")
                    ws.cell(row=r, column=1, value=row.get("maturity_label") or row.get("maturity_year"))
                    ws.cell(row=r, column=2, value=(float(amt_total) / 1e6) if pd.notna(amt_total) else None).number_format = "#,##0.000"
                    ws.cell(row=r, column=3, value=None)
                    ws.cell(row=r, column=4, value=None)
                    ws.cell(row=r, column=6, value=row.get("maturity_label") or row.get("maturity_year"))
                    ws.cell(row=r, column=7, value=None)
                    ws.cell(row=r, column=9, value=None)
                    ws.cell(row=r, column=12, value=None)
                    try:
                        ws.merge_cells(start_row=r, start_column=15, end_row=r, end_column=16)
                    except Exception:
                        pass
                    try:
                        ws.merge_cells(start_row=r, start_column=17, end_row=r, end_column=18)
                    except Exception:
                        pass
                    ws.cell(row=r, column=15, value=basis_label)
                    ws.cell(row=r, column=17, value=row.get("source_kind") or "Debt_Maturity_Ladder")
                    if pd.notna(amt_total):
                        sum_listed_principal += float(amt_total)
                    r += 1
                r += 1
                ws.cell(
                    row=r,
                    column=1,
                    value="Scheduled repayments / principal basis (excludes debt issuance costs). Carrying debt_core may differ from principal total.",
                )
                try:
                    ws.merge_cells(start_row=r, start_column=1, end_row=r, end_column=15)
                except Exception:
                    pass
                ws.cell(row=r, column=1).alignment = Alignment(wrap_text=True, vertical="top")
                r += 2
            else:
                max_rows = 14
                if len(df) > max_rows:
                    df = df.head(max_rows)
                for _, row in df.iterrows():
                    ws.cell(row=r, column=1, value=row.get("tranche_name"))
                    amt_pr = pd.to_numeric(row.get("amount_principal", row.get("amount")), errors="coerce")
                    amt_ca = pd.to_numeric(row.get("amount_carrying"), errors="coerce")
                    if pd.notna(amt_pr):
                        sum_listed_principal += float(amt_pr)
                        if bool(row.get("near_term")):
                            near_term += float(amt_pr)
                    ws.cell(row=r, column=2, value=(float(amt_pr) / 1e6) if pd.notna(amt_pr) else None).number_format = "#,##0.000"
                    m_disp = row.get("maturity_display")
                    if not m_disp and pd.notna(row.get("maturity_year")):
                        m_disp = str(int(pd.to_numeric(row.get("maturity_year"), errors="coerce")))
                    ws.cell(row=r, column=3, value=row.get("rate_type") or row.get("instrument_type"))
                    ws.cell(row=r, column=4, value=row.get("coupon_pct") if pd.notna(row.get("coupon_pct")) else row.get("spread_pct"))
                    ws.cell(row=r, column=6, value=m_disp)
                    conv_price = pd.to_numeric(row.get("conversion_price"), errors="coerce")
                    conv_shares = pd.to_numeric(row.get("shares_on_full_conversion"), errors="coerce")
                    rep_shares = pd.to_numeric(row.get("concurrent_repurchase_shares"), errors="coerce")
                    ws.cell(row=r, column=7, value=float(conv_price) if pd.notna(conv_price) else None).number_format = "$#,##0.00"
                    ws.cell(row=r, column=9, value=(float(conv_shares) / 1e6) if pd.notna(conv_shares) else None).number_format = "#,##0.000"
                    ws.cell(row=r, column=12, value=(float(rep_shares) / 1e6) if pd.notna(rep_shares) else None).number_format = "#,##0.000"
                    try:
                        ws.merge_cells(start_row=r, start_column=15, end_row=r, end_column=16)
                    except Exception:
                        pass
                    try:
                        ws.merge_cells(start_row=r, start_column=17, end_row=r, end_column=18)
                    except Exception:
                        pass
                    ws.cell(row=r, column=15, value="principal_tranche_sum")
                    ws.cell(row=r, column=17, value=row.get("source_kind") or "Debt_Tranches_Latest")
                    row_conv_note = _safe_text_value(row.get("conversion_terms_note"))
                    if (pd.notna(conv_price) or pd.notna(conv_shares)) and row_conv_note:
                        try:
                            comment_parts = [row_conv_note]
                            if pd.notna(pd.to_numeric(row.get("concurrent_repurchase_amount"), errors="coerce")):
                                comment_parts.append(
                                    f"Concurrent repurchase: ${float(pd.to_numeric(row.get('concurrent_repurchase_amount'), errors='coerce'))/1e6:,.1f}m"
                                )
                            if pd.notna(pd.to_numeric(row.get("concurrent_repurchase_shares"), errors="coerce")):
                                comment_parts.append(
                                    f"Concurrent repurchase shares: {float(pd.to_numeric(row.get('concurrent_repurchase_shares'), errors='coerce'))/1e6:,.1f}m"
                                )
                            if _safe_text_value(row.get("hedge_or_call_spread")):
                                comment_parts.append(f"Hedge/call spread: {_safe_text_value(row.get('hedge_or_call_spread'))}")
                            if _safe_text_value(row.get("settlement_type")):
                                comment_parts.append(f"Settlement: {_safe_text_value(row.get('settlement_type'))}")
                            if _safe_text_value(row.get("conversion_conditions_note")):
                                comment_parts.append(f"Conditions: {_safe_text_value(row.get('conversion_conditions_note'))}")
                            _set_cell_comment_local(
                                ws.cell(row=r, column=17),
                                "\n".join([x for x in comment_parts if x])
                                + f"\n\nSource: {_safe_text_value(row.get('conversion_terms_source')) or _safe_text_value(row.get('source_kind'))}",
                            )
                        except Exception:
                            pass
                    r += 1
            # visual spacer before tie-out rows
            r += 1
            # principal/carrying reconciliation rows
            principal_total_m = principal_total_m if principal_total_m is not None else (sum_listed_principal / 1e6 if sum_listed_principal else None)
            if carrying_total_m is None:
                debt_core_latest = debt_core_map.get(pd.Timestamp(qs[-1])) if qs else None
                carrying_total_m = (float(debt_core_latest) / 1e6) if debt_core_latest is not None else None
            debt_current_latest = None
            if debt_current_latest_m is None:
                debt_current_latest = debt_current_map.get(pd.Timestamp(qs[-1])) if qs else None
                debt_current_latest_m = (float(debt_current_latest) / 1e6) if debt_current_latest is not None else None
            if debt_long_term_latest_m is None:
                total_debt_latest = total_debt_map.get(pd.Timestamp(qs[-1])) if qs else None
                if total_debt_latest is not None:
                    debt_st_latest = debt_current_latest if debt_current_latest is not None else 0.0
                    debt_long_term_latest_m = (float(total_debt_latest) - float(debt_st_latest)) / 1e6
            if carrying_minus_principal_m is None and carrying_total_m is not None and principal_total_m is not None:
                carrying_minus_principal_m = float(carrying_total_m) - float(principal_total_m)

            ws.cell(row=r, column=1, value="Principal total ($m)").font = bold
            ws.cell(row=r, column=2, value=principal_total_m).number_format = "#,##0.000"
            r += 1
            ws.cell(row=r, column=1, value="Carrying debt_core ($m)").font = bold
            ws.cell(row=r, column=2, value=carrying_total_m).number_format = "#,##0.000"
