        row_qadj_hdr = row_toggle_conc + 2
        row_qadj_ev_adj = row_qadj_hdr + 1
        row_qadj_ev = row_qadj_hdr + 2
        row_qadj_yield = row_qadj_hdr + 3
        row_dcf_end = max(row_dcf_sens_last_row, row_qadj_yield, row_mi_toggle)
        row_hv_hdr = 68
        row_hv_total = 69
        row_hv_prof = 70
        row_hv_cash = 71
        row_hv_delev = 72
        row_hv_quality = 73
