    valuation_summary_df = pd.DataFrame()
    valuation_grid_df = pd.DataFrame()
    summary_df = pd.DataFrame()
    signals_base_df = pd.DataFrame()
    flags_df = pd.DataFrame()
    flags_audit_df = pd.DataFrame()
    flags_recompute_df = pd.DataFrame()
