    def _build_qn_evidence_src() -> pd.DataFrame:
        if quarter_notes is None or quarter_notes.empty:
            return pd.DataFrame(columns=["note_id", "quarter", "category", "claim", "metric", "doc_path", "evidence_id", "snippet"])
        src = _quarter_notes_view()
        q_col = _resolve_col(src, ["quarter", "quarter_end", "as_of_quarter"])
        cat_col = _resolve_col(src, ["category", "tag", "topic"])
        claim_col = _resolve_col(src, ["claim", "headline", "note", "body"])
        metric_col = _resolve_col(src, ["metric_ref", "metric", "metric_tag"])
        note_id_col = _resolve_col(src, ["note_id", "id"])
        doc_col = _resolve_col(src, ["doc_path", "evidence_doc", "doc"])
        snip_col = _resolve_col(src, ["evidence_snippet", "snippet"])
        out_rows: List[Dict[str, Any]] = []
        for _, r in src.iterrows():
            qd = _qend_date(r.get(q_col) if q_col else None)
            if qd is None:
                continue
            claim = str(r.get(claim_col) or "").strip() if claim_col else ""
            note_id = str(r.get(note_id_col) or "").strip() if note_id_col else ""
            if not note_id:
                note_id = hashlib.sha1(f"{qd}|{claim}".encode("utf-8")).hexdigest()[:12]
            ev = _parse_first_evidence(r)
            doc_path = str(r.get(doc_col) or ev.get("doc_path") or "").strip() if doc_col else str(ev.get("doc_path") or "").strip()
            snippet = str(r.get(snip_col) or ev.get("snippet") or claim).strip() if snip_col else str(ev.get("snippet") or claim).strip()
            out_rows.append(
                {
                    "note_id": note_id,
                    "quarter": qd,
                    "category": str(r.get(cat_col) or "").strip() if cat_col else "",
                    "claim": claim,
                    "metric": str(r.get(metric_col) or "").strip() if metric_col else "",
                    "doc_path": doc_path,
                    "evidence_id": hashlib.sha1(f"{note_id}|{doc_path}|{snippet[:64]}".encode("utf-8")).hexdigest()[:12],
                    "snippet": snippet,
                }
            )
        out = pd.DataFrame(out_rows)
        if out.empty:
            return pd.DataFrame(columns=["note_id", "quarter", "category", "claim", "metric", "doc_path", "evidence_id", "snippet"])
        return out.sort_values(["quarter", "category", "note_id"]).reset_index(drop=True)

    def _build_promise_evidence_src() -> pd.DataFrame:
        out_rows: List[Dict[str, Any]] = []
        if promise_progress is not None and not promise_progress.empty:
            src = promise_progress.copy()
            pid_col = _resolve_col(src, ["promise_id", "id"])
            q_col = _resolve_col(src, ["quarter", "as_of"])
            st_col = _resolve_col(src, ["status"])
            doc_col = _resolve_col(src, ["doc_path", "evidence_doc", "doc"])
            snip_col = _resolve_col(src, ["evidence_snippet", "snippet"])
            if pid_col is not None and q_col is not None:
                for _, r in src.iterrows():
                    pid = str(r.get(pid_col) or "").strip()
                    qd = _qend_date(r.get(q_col))
                    if not pid or qd is None:
                        continue
                    ev = _parse_first_evidence(r)
                    doc_path = (
                        str(r.get(doc_col) or ev.get("doc_path") or "").strip()
                        if doc_col
                        else str(ev.get("doc_path") or "").strip()
                    )
                    snippet = (
                        str(r.get(snip_col) or ev.get("snippet") or "").strip()
                        if snip_col
                        else str(ev.get("snippet") or "").strip()
                    )
                    out_rows.append(
                        {
                            "promise_id": pid,
                            "quarter": qd,
                            "status": str(r.get(st_col) or "").strip() if st_col else "",
                            "doc_path": doc_path,
                            "evidence_id": hashlib.sha1(f"{pid}|{qd}|{doc_path}|{snippet[:64]}".encode("utf-8")).hexdigest()[:12],
                            "snippet": snippet,
                        }
                    )

        if promises is not None and not promises.empty:
            ps = _promises_view()
            pid_col = _resolve_col(ps, ["promise_id", "id"])
            q_col = _resolve_col(ps, ["first_seen_evidence_quarter", "created_quarter", "first_seen_q", "first_seen_quarter", "quarter"])
            ev_json_col = _resolve_col(ps, ["source_evidence_json", "evidence_history_json", "evidence_json"])
            snip_col = _resolve_col(ps, ["evidence_snippet", "snippet", "promise_text", "statement"])
            if pid_col is not None and q_col is not None:
                for _, r in ps.iterrows():
                    pid = str(r.get(pid_col) or "").strip()
                    qd = _qend_date(r.get(q_col))
                    if not pid or qd is None:
                        continue
                    doc_path = ""
                    snippet = str(r.get(snip_col) or "").strip() if snip_col else ""
                    if ev_json_col:
                        raw = r.get(ev_json_col)
                        if isinstance(raw, str) and raw.strip():
                            try:
                                parsed = json.loads(raw)
                                ev = parsed[0] if isinstance(parsed, list) and parsed else (parsed if isinstance(parsed, dict) else {})
                                if isinstance(ev, dict):
                                    doc_path = str(ev.get("doc_path") or ev.get("doc_name") or "").strip()
                                    snippet = str(ev.get("snippet") or snippet).strip()
                            except Exception:
                                pass
                    out_rows.append(
                        {
                            "promise_id": pid,
                            "quarter": qd,
                            "status": "",
                            "doc_path": doc_path,
                            "evidence_id": hashlib.sha1(f"{pid}|{qd}|{doc_path}|{snippet[:64]}".encode("utf-8")).hexdigest()[:12],
                            "snippet": snippet,
                        }
                    )

        if not out_rows:
            return pd.DataFrame(columns=["promise_id", "quarter", "status", "doc_path", "evidence_id", "snippet"])
        out = pd.DataFrame(out_rows)
        out = out.sort_values(["promise_id", "quarter"]).drop_duplicates(["promise_id", "quarter"], keep="first")
        return out.reset_index(drop=True)

    quarter_notes_evidence_df = pd.DataFrame()
    promise_evidence_df = pd.DataFrame()
    ui_state = {"quarters": [], "promise_rows": pd.DataFrame()}

    def _latest_quarter_sec_text_corpus(qref: pd.Timestamp) -> str:
        cache_key = pd.Timestamp(qref).normalize().date().isoformat()
        cached_text = document_cache.latest_quarter_sec_text_by_quarter.get(cache_key)
        if cached_text is not None:
            return cached_text

        q0 = pd.Timestamp(qref)
        sec_docs: List[Path] = []
        if audit is not None and not audit.empty:
            aq = _audit_view()
            accn_col = _resolve_col(aq, ["accn"])
            form_col = _resolve_col(aq, ["form"])
            if accn_col:
                aq = aq[aq["_quarter"].notna()]
                aq = aq[aq["_quarter"].dt.to_period("Q") == q0.to_period("Q")]
                if form_col:
                    aq = aq[aq[form_col].astype(str).str.upper().str.startswith(("8-K", "10-Q", "10-K"))]
                for _, rr in aq.dropna(subset=[accn_col]).iterrows():
                    accn = str(rr.get(accn_col) or "").strip()
                    if not accn:
                        continue
                    sec_docs.extend(_sec_docs_for_accession(accn))

        cache_dir = cache_root
        if cache_dir.exists():
            for fr in _submission_recent_rows(max_files=8):
                form = str(fr.get("form") or "").upper().strip()
                if not form.startswith(("8-K", "10-Q", "10-K")):
                    continue
                accn = str(fr.get("accn") or "").strip()
                if not accn:
                    continue
                q_guess = _submission_recent_row_quarter(fr)
                if q_guess is None or pd.Timestamp(q_guess).to_period("Q") != q0.to_period("Q"):
                    continue
                primary = str(fr.get("doc") or "").strip()
                if primary:
                    cand = _resolve_cached_doc_path(accn=accn, doc_name=primary, path_hint=primary)
                    if cand is not None and cand.exists() and re.search(r"(ex99|ex-99|earnings|press|letter|presentation|slides|ceo)", cand.name, re.I):
                        sec_docs.append(cand)
                for cand in _sec_docs_for_accession(accn):
                    if re.search(r"(ex99|ex-99|earnings|press|letter|presentation|slides|ceo)", cand.name, re.I):
                        sec_docs.append(cand)

        sec_docs = sorted({p for p in sec_docs if p.exists()})[:40]

        def _qa_norm_txt(v: Any) -> str:
            return re.sub(r"\s+", " ", str(v or "").strip())

        sec_text = ""
        for dp in sec_docs:
            sec_text += " " + _qa_norm_txt(_read_cached_doc_text(dp))

        er_dir = _first_existing_material_dir(
            "earnings_release",
            "Earnings Release",
            "Earnings Releases",
            "press_release",
            "Press Release",
        )
        if er_dir is not None and er_dir.exists():
            for fp in sorted([x for x in er_dir.glob("*") if x.is_file()])[:80]:
                if not _path_belongs_to_ticker(fp, ticker, ticker_roots):
                    continue
                suf = fp.suffix.lower()
                if suf in {".htm", ".html", ".txt"}:
                    sec_text += " " + _qa_norm_txt(_read_cached_doc_text(fp))
                elif suf == ".pdf":
                    txt_pdf = _read_cached_doc_text(fp)
                    if txt_pdf:
                        sec_text += " " + _qa_norm_txt(txt_pdf)

        if ocr_log is not None and not ocr_log.empty:
            oq = ocr_log.copy()
            q_col = _resolve_col(oq, ["quarter", "quarter_end", "as_of_quarter", "period_end"])
            t_col = _resolve_col(oq, ["text", "ocr_text", "content", "snippet"])
            f_col = _resolve_col(oq, ["source_file", "path", "doc", "doc_path", "file"])
            if t_col is not None:
                if q_col is not None:
                    oq[q_col] = pd.to_datetime(oq[q_col], errors="coerce")
                    oq = oq[oq[q_col].notna()]
                    oq = oq[oq[q_col].dt.to_period("Q") == q0.to_period("Q")]
                for _, rr in oq.iterrows():
                    ftxt = str(rr.get(f_col) or "").lower() if f_col is not None else ""
                    if ftxt and not any(k in ftxt for k in ("earnings_release", "slides", "presentation", "ceo", "letter", "ex99", "press")):
                        continue
                    sec_text += " " + _qa_norm_txt(rr.get(t_col) or "")

        if slides_guidance is not None and not slides_guidance.empty:
            sg = slides_guidance.copy()
            q_col = _resolve_col(sg, ["quarter", "quarter_end"])
            t_col = _resolve_col(sg, ["line", "text"])
            n_col = _resolve_col(sg, ["numbers"])
            if q_col is not None and t_col is not None:
                sg[q_col] = pd.to_datetime(sg[q_col], errors="coerce")
                sg = sg[sg[q_col].notna()]
                sg = sg[sg[q_col].dt.to_period("Q") == q0.to_period("Q")]
                for _, rr in sg.iterrows():
                    sec_text += " " + _qa_norm_txt(f"{rr.get(t_col) or ''} {rr.get(n_col) or ''}")

        document_cache.latest_quarter_sec_text_by_quarter[cache_key] = sec_text
        return sec_text

    def _run_latest_quarter_qa() -> List[Dict[str, Any]]:
        qa_rows: List[Dict[str, Any]] = []
        if hist is None or hist.empty or "quarter" not in hist.columns:
            return qa_rows

        hq = _hist_view()
        hq = hq[hq["_quarter"].notna()].sort_values("_quarter")
        if hq.empty:
            return qa_rows
        q0 = pd.Timestamp(hq["_quarter"].max())
        q0d = q0.date()
        hq0 = hq[hq["_quarter"] == q0].iloc[-1]
        qa_quarters = tuple(pd.Timestamp(qv) for qv in hq["_quarter"].tolist())
        qa_render_bundle = dict(getattr(getattr(ctx_ref, "derived", None), "valuation_render_bundle", {}) or {})
        if not qa_render_bundle:
            qa_render_bundle = _ensure_valuation_render_bundle(qa_quarters, leverage_df)
        qa_precompute_bundle = dict(getattr(getattr(ctx_ref, "derived", None), "valuation_precompute_bundle", {}) or {})
        if not qa_precompute_bundle:
            qa_precompute_bundle = _ensure_valuation_precompute_bundle(qa_quarters, qa_render_bundle)
        ebitda_map = dict(qa_render_bundle.get("ebitda_map") or {})
        net_income_map = dict(qa_render_bundle.get("net_income_map") or {})
        buyback_map = dict(qa_precompute_bundle.get("buyback_map") or qa_render_bundle.get("buyback_map") or {})
        buyback_shares_map = dict(qa_precompute_bundle.get("buyback_shares_map") or {})
        buyback_avg_price_doc_map = dict(qa_precompute_bundle.get("buyback_avg_price_doc_map") or {})
        buyback_doc_note_map = dict(qa_precompute_bundle.get("buyback_doc_note_map") or {})
        dividend_map = dict(qa_precompute_bundle.get("dividend_map") or qa_render_bundle.get("dividend_map") or {})
        docs_by_quarter = dict(qa_precompute_bundle.get("docs_by_quarter") or {})

        def _add(sev: str, metric: str, msg: str, src: str = "") -> None:
            qa_rows.append(
                {
                    "quarter": q0d,
                    "metric": metric,
                    "severity": sev,
                    "message": msg,
                    "source": src,
                }
            )

        def _qa_norm_txt(v: Any) -> str:
            return re.sub(r"\s+", " ", str(v or "").strip())

        def _money_m(v: Any) -> str:
            try:
                fv = float(v)
            except Exception:
                return "N/A"
            if not pd.notna(fv):
                return "N/A"
            return f"${fv/1e6:,.1f}m"

        def _qa_shares_m(v: Any) -> str:
            try:
                fv = float(v)
            except Exception:
                return "N/A"
            if not pd.notna(fv):
                return "N/A"
            return f"{fv/1_000_000.0:+,.3f}m"

        def _qmap_lookup(map_in: Any, qref: Any) -> Any:
            if not isinstance(map_in, dict):
                return None
            candidates: List[Any] = []
            if qref is not None:
                candidates.append(qref)
                try:
                    qts = pd.Timestamp(qref)
                    candidates.extend([qts, qts.normalize(), qts.date()])
                except Exception:
                    pass
            seen_local: set[str] = set()
            for key in candidates:
                key_sig = f"{type(key).__name__}:{repr(key)}"
                if key_sig in seen_local:
                    continue
                seen_local.add(key_sig)
                if key in map_in:
                    return map_in.get(key)
            return None

        def _docs_for_quarter(map_in: Any, qref: Any) -> List[Dict[str, Any]]:
            docs_local = _qmap_lookup(map_in, qref)
            if isinstance(docs_local, list):
                return [dict(x) for x in docs_local if isinstance(x, dict)]
            return []

        with _timed_writer_substage("write_excel.ui.latest_quarter_qa.sec_text"):
            sec_text = _latest_quarter_sec_text_corpus(q0)
        sec_text_l = sec_text.lower()

        def _parse_money_from_text(patterns: List[str]) -> Optional[float]:
            for pat in patterns:
                m = re.search(pat, sec_text, re.I)
                if not m:
                    continue
                try:
                    val = float(str(m.group(1)).replace(",", ""))
                except Exception:
                    continue
                unit = str(m.group(2) or "").lower() if m.lastindex and m.lastindex >= 2 else ""
                if unit in {"billion", "bn"}:
                    return val * 1e9
                if unit in {"million", "m"}:
                    return val * 1e6
                # default money in filings text for these checks.
                return val * 1e6 if abs(val) < 10000 else val
            return None

        def _cmp_money(metric_name: str, model_val: Optional[float], parsed_val: Optional[float], src: str) -> None:
            if model_val is None:
                _add("warn", "QA_QTR", f"{metric_name}: model value missing for {q0d}", src)
                return
            if parsed_val is None:
                _add("warn", "QA_QTR", f"{metric_name}: not found in SEC/earnings text for {q0d}", src)
                return
            diff_abs = abs(float(model_val) - float(parsed_val))
            tol_abs = 5_000_000.0
            tol_rel = 0.02
            rel = diff_abs / max(1.0, abs(float(model_val)))
            if diff_abs <= tol_abs or rel <= tol_rel:
                _add("info", "QA_QTR", f"{metric_name}: PASS model {_money_m(model_val)} vs text {_money_m(parsed_val)}", src)
            else:
                _add("warn", "QA_QTR", f"{metric_name}: WARN model {_money_m(model_val)} vs text {_money_m(parsed_val)} (diff {_money_m(diff_abs)})", src)

        rev_model = pd.to_numeric(hq0.get("revenue"), errors="coerce")
        cash_model = pd.to_numeric(hq0.get("cash"), errors="coerce")
        debt_model = pd.to_numeric(hq0.get("debt_core"), errors="coerce")
        total_debt_model = pd.to_numeric(hq0.get("total_debt"), errors="coerce")
        ebitda_model = pd.to_numeric(ebitda_map.get(q0), errors="coerce") if ebitda_map else pd.NA
        net_income_model = pd.to_numeric(net_income_map.get(q0), errors="coerce") if net_income_map else pd.NA
        cfo_q = pd.to_numeric(hq0.get("cfo"), errors="coerce")
        cap_q = pd.to_numeric(hq0.get("capex"), errors="coerce")
        fcf_model = (float(cfo_q) - float(cap_q)) if pd.notna(cfo_q) and pd.notna(cap_q) else None
        net_debt_model = (float(debt_model) - float(cash_model)) if pd.notna(debt_model) and pd.notna(cash_model) else None
        adj_ebitda_model = None
        if adj_metrics is not None and not adj_metrics.empty and "quarter" in adj_metrics.columns:
            am = _adj_metrics_view()
            am = am[am["_quarter"].notna()]
            am = am[am["_quarter"].dt.to_period("Q") == q0.to_period("Q")]
            if not am.empty and "adj_ebitda" in am.columns:
                adj_ebitda_model = pd.to_numeric(am.iloc[-1].get("adj_ebitda"), errors="coerce")

        rev_txt = _parse_money_from_text([r"(?:total\s+)?revenue[^0-9]{0,40}\$?\s*([0-9]{1,4}(?:,[0-9]{3})*(?:\.\d+)?)\s*(billion|million|bn|m)"])
        ebitda_txt = _parse_money_from_text([r"(?<!adjusted\s)ebitda[^0-9]{0,40}\$?\s*([0-9]{1,4}(?:,[0-9]{3})*(?:\.\d+)?)\s*(billion|million|bn|m)"])
        net_income_txt = _parse_money_from_text(
            [
                r"net\s+(?:income|earnings)[^0-9]{0,40}\$?\s*([0-9]{1,4}(?:,[0-9]{3})*(?:\.\d+)?)\s*(billion|million|bn|m)",
                r"net\s+loss[^0-9]{0,40}\$?\s*([0-9]{1,4}(?:,[0-9]{3})*(?:\.\d+)?)\s*(billion|million|bn|m)",
            ]
        )
        if net_income_txt is not None and re.search(
            r"net\s+loss[^0-9]{0,40}\$?\s*([0-9]{1,4}(?:,[0-9]{3})*(?:\.\d+)?)\s*(billion|million|bn|m)",
            sec_text,
            re.I,
        ):
            net_income_txt = -abs(float(net_income_txt))
        adj_ebitda_txt = _parse_money_from_text([r"adjusted\s+ebitda[^0-9]{0,40}\$?\s*([0-9]{1,4}(?:,[0-9]{3})*(?:\.\d+)?)\s*(billion|million|bn|m)"])
        fcf_txt = _parse_money_from_text([r"free\s+cash\s+flow[^0-9]{0,40}\$?\s*([0-9]{1,4}(?:,[0-9]{3})*(?:\.\d+)?)\s*(billion|million|bn|m)"])
        cash_txt = _parse_money_from_text([r"cash(?:\s+and\s+cash\s+equivalents)?[^0-9]{0,60}\$?\s*([0-9]{1,4}(?:,[0-9]{3})*(?:\.\d+)?)\s*(billion|million|bn|m)"])
        debt_txt = _parse_money_from_text(
            [
                r"(?:total\s+debt(?:\s+outstanding)?|debt\s+outstanding|principal\s+debt\s+outstanding)\s*[^0-9]{0,40}\$?\s*([0-9]{1,4}(?:,[0-9]{3})*(?:\.\d+)?)\s*(billion|million|bn|m)"
            ]
        )

        _cmp_money("Revenue (Q)", float(rev_model) if pd.notna(rev_model) else None, rev_txt, "sec_cache docs")
        _cmp_money("EBITDA (Q)", float(ebitda_model) if pd.notna(ebitda_model) else None, ebitda_txt, "sec_cache / earnings_release / slides")
        _cmp_money("Net income (Q)", float(net_income_model) if pd.notna(net_income_model) else None, net_income_txt, "sec_cache / earnings_release")
        _cmp_money("Adj EBITDA (Q)", float(adj_ebitda_model) if pd.notna(adj_ebitda_model) else None, adj_ebitda_txt, "sec_cache / earnings_release / slides")
        _cmp_money("FCF (Q)", fcf_model, fcf_txt, "sec_cache docs")
        _cmp_money("Cash (Q)", float(cash_model) if pd.notna(cash_model) else None, cash_txt, "sec_cache docs")
        _cmp_money("Total debt (Q)", float(total_debt_model) if pd.notna(total_debt_model) else None, debt_txt, "sec_cache docs")
        _cmp_money("Debt core (Q)", float(debt_model) if pd.notna(debt_model) else None, debt_txt, "sec_cache docs")
        if net_debt_model is not None and debt_txt is not None and cash_txt is not None:
            net_txt = float(debt_txt) - float(cash_txt)
            _cmp_money("Net debt (Q)", net_debt_model, net_txt, "sec_cache docs")
        resolved_cap_return_latest = dict((qa_precompute_bundle.get("capital_return_resolved") or {}).get(q0) or {})
        buyback_shares_latest = resolved_cap_return_latest.get("buyback_shares_q")
        buyback_cash_latest = resolved_cap_return_latest.get("buyback_cash_q")
        buyback_avg_price_latest = resolved_cap_return_latest.get("buyback_avg_price")
        buyback_qa_summary = str(resolved_cap_return_latest.get("buyback_qa_summary") or "").strip()
        buyback_note_latest = str(resolved_cap_return_latest.get("buyback_note_source") or _qmap_lookup(buyback_doc_note_map, q0) or "").strip()
        if buyback_shares_latest is not None or buyback_cash_latest is not None or buyback_note_latest:
            src_lbl = "sec_cache repurchase table/text"
            _add(
                "info",
                "QA_Buybacks",
                buyback_qa_summary or buyback_note_latest[:180],
                src_lbl,
            )
        elif re.search(r"\brepurchas\w*|buyback\b", sec_text_l, re.I):
            _add("warn", "QA_Buybacks", f"Buyback wording found for {q0d}, but explicit execution values were not parsed.", "sec_cache docs")
        else:
            _add("info", "QA_Buybacks", f"No explicit buyback execution disclosed for {q0d}.", "sec_cache docs")
        dividend_cash_latest = _qmap_lookup(dividend_map, q0)
        if dividend_cash_latest is not None:
            _add(
                "info",
                "QA_Dividends",
                f"Explicit common dividend cash support found for {q0d}: {_money_m(dividend_cash_latest)}.",
                "history/sec_cache common-dividend support",
            )
        elif re.search(r"\bdividends and distributions\b|\bpayments of dividends\b", sec_text_l, re.I):
            _add(
                "info",
                "QA_Dividends",
                f"Generic dividends/distributions disclosure found for {q0d}, but it was not mapped to common dividend logic.",
                "sec_cache docs",
            )
        else:
            _add("info", "QA_Dividends", f"No explicit common dividend disclosure detected for {q0d}.", "sec_cache docs")

        valuation_audit = dict(qa_precompute_bundle.get("valuation_audit") or {})
        latest_audit = dict(valuation_audit.get(q0) or {})
        suppress_metric_map = {
            "net_leverage": "Net leverage",
            "net_leverage_adj": "Net leverage (Adj)",
            "interest_coverage_pnl": "Interest coverage (P&L TTM)",
            "cash_interest_coverage": "Cash interest coverage (TTM)",
        }
        for audit_key, label in suppress_metric_map.items():
            audit_row = dict(latest_audit.get(audit_key) or {})
            suppress_reason = str(audit_row.get("suppress_reason") or "").strip()
            if not suppress_reason:
                continue
            sev = "warn" if "denominator <= 0" in suppress_reason.lower() else "info"
            _add(sev, "QA_Valuation", f"{label} suppressed: {suppress_reason}", "valuation_audit")

        # Guidance completeness: Low/High ranges expected for key metrics in EX-99 window.
        g_checks = {
            "Revenue": r"revenue[^\n\r]{0,80}([0-9]{2,4}(?:,[0-9]{3})*(?:\.[0-9]+)?)[^\n\r]{0,40}([0-9]{2,4}(?:,[0-9]{3})*(?:\.[0-9]+)?)",
            "Adj EBIT": r"adjusted\s+ebit[^\n\r]{0,80}([0-9]{1,4}(?:,[0-9]{3})*(?:\.[0-9]+)?)[^\n\r]{0,40}([0-9]{1,4}(?:,[0-9]{3})*(?:\.[0-9]+)?)",
            "Adj EPS": r"adjusted\s+(?:diluted\s+)?(?:earnings\s+per\s+share|eps)[^\n\r]{0,80}([0-9]+(?:\.[0-9]+)?)[^\n\r]{0,40}([0-9]+(?:\.[0-9]+)?)",
            "FCF": r"(?:free\s+cash\s+flow|\bfcf\b)[^\n\r]{0,80}([0-9]{1,4}(?:,[0-9]{3})*(?:\.[0-9]+)?)[^\n\r]{0,40}([0-9]{1,4}(?:,[0-9]{3})*(?:\.[0-9]+)?)",
        }
        g_mentions = {
            "Revenue": r"\b(revenue|sales)\b",
            "Adj EBIT": r"\badjusted\s+ebit\b",
            "Adj EPS": r"\badjusted\s+(?:diluted\s+)?(?:earnings\s+per\s+share|eps)\b",
            "FCF": r"\b(free\s+cash\s+flow|fcf)\b",
        }
        snap_items_q0: List[Dict[str, Any]] = []
        try:
            gstore = ui_state.get("guidance_snapshot_by_q", {}) if isinstance(ui_state, dict) else {}
            if isinstance(gstore, dict):
                snap_items_q0 = list(gstore.get(pd.Timestamp(q0).date(), []))
                if not snap_items_q0:
                    snap_items_q0 = list(gstore.get(pd.Timestamp(q0), []))
        except Exception:
            snap_items_q0 = []

        def _guidance_metric_key(metric_name: str) -> str:
            m = str(metric_name or "").strip().lower()
            if not m:
                return ""
            if "revenue" in m or "sales" in m:
                return "revenue"
            if "ebitda" in m:
                return "adj ebitda"
            if "ebit" in m:
                return "adj ebit"
            if "eps" in m or "earnings per share" in m:
                return "adj eps"
            if "free cash flow" in m or re.search(r"\bfcf\b", m):
                return "fcf"
            if "capex" in m or "capital expenditure" in m:
                return "capex"
            return m

        def _snapshot_has_metric_range(metric_name: str) -> bool:
            metric_k = _guidance_metric_key(metric_name)
            for it in snap_items_q0:
                mname = str(it.get("metric_canon") or it.get("metric") or "")
                if _guidance_metric_key(mname) != metric_k:
                    continue
                lo = pd.to_numeric(it.get("low") if "low" in it else it.get("value_low"), errors="coerce")
                hi = pd.to_numeric(it.get("high") if "high" in it else it.get("value_high"), errors="coerce")
                if pd.notna(lo) and pd.notna(hi):
                    return True
            return False

        def _snapshot_has_metric(metric_name: str) -> bool:
            metric_k = _guidance_metric_key(metric_name)
            for it in snap_items_q0:
                mname = str(it.get("metric_canon") or it.get("metric") or "")
                if _guidance_metric_key(mname) == metric_k:
                    return True
            return False

        has_guidance_context = bool(snap_items_q0)
        if not has_guidance_context:
            has_guidance_context = bool(
                re.search(
                    r"\b(provides?\s+the\s+following\s+guidance|full[- ]year\s+guidance|fiscal\s+20\d{2}\s+guidance|"
                    r"guidance\s+for\s+(?:fiscal|fy)\s+20\d{2}|outlook[^.\n]{0,120}(revenue|ebit|eps|cash\s+flow|fcf|capex))\b",
                    sec_text_l,
                    re.I,
                )
            )
        if not has_guidance_context:
            _add(
                "info",
                "QA_Guidance",
                f"No explicit numeric guidance disclosure detected for {q0d}; range completeness checks skipped.",
                "sec_cache docs/guidance_snapshot",
            )
        else:
            for mk, pat in g_checks.items():
                mention_pat = g_mentions.get(mk, "")
                mention_guidance_ctx = (
                    rf"{mention_pat}[^\n\r]{{0,120}}(guidance|outlook|target|targets|range|between|to\s+\$?[0-9]|low|high)"
                    if mention_pat
                    else ""
                )
                mentioned = bool(_snapshot_has_metric(mk))
                if not mentioned and mention_guidance_ctx:
                    mentioned = bool(re.search(mention_guidance_ctx, sec_text_l, re.I))
                ok_text = bool(re.search(pat, sec_text_l, re.I))
                ok_snap = _snapshot_has_metric_range(mk)
                ok = bool(ok_text or ok_snap)
                src_lbl = "sec_cache docs" if ok_text else ("guidance_snapshot" if ok_snap else "sec_cache docs")
                if not mentioned:
                    _add("info", "QA_Guidance", f"{mk} guidance not disclosed for {q0d}", "sec_cache docs/guidance_snapshot")
                else:
                    _add("info" if ok else "warn", "QA_Guidance", f"{mk} range {'PASS' if ok else 'MISSING'} for {q0d}", src_lbl)

        # Leverage text-vs-calc consistency.
        if leverage_df is not None and not leverage_df.empty:
            lv = leverage_df.copy()
            lv["quarter"] = pd.to_datetime(lv["quarter"], errors="coerce")
            lv0 = lv[lv["quarter"].dt.to_period("Q") == q0.to_period("Q")]
            if not lv0.empty:
                rr = lv0.iloc[-1]
                lev_txt = pd.to_numeric(rr.get("corporate_net_leverage_text"), errors="coerce")
                lev_calc = pd.to_numeric(rr.get("corporate_net_leverage_calc"), errors="coerce")
                if pd.notna(lev_txt) and pd.notna(lev_calc):
                    diff = abs(float(lev_txt) - float(lev_calc))
                    sev = "info" if diff <= 0.15 else "warn"
                    _add(sev, "QA_Leverage", f"Adjusted net leverage text {float(lev_txt):.2f}x vs calc {float(lev_calc):.2f}x (diff {diff:.2f}x)", "sec_cache/slides")
                elif pd.notna(lev_calc):
                    _add("info", "QA_Leverage", f"Adjusted net leverage uses calc {float(lev_calc):.2f}x (no text ratio found)", "computed")
                else:
                    _add("warn", "QA_Leverage", "Adjusted net leverage unavailable (calc/text missing)", "computed")

        # Debt tie-out QA: tranches + revolver + other items vs debt_core, bucket coverage, and recon-to-history.
        try:
            debt_core_latest = float(debt_model) if pd.notna(debt_model) else None
            debt_basis_latest = debt_core_latest
            debt_basis_label = "debt_core"
            tr_sum_unique = None
            if debt_tranches_latest is not None and not debt_tranches_latest.empty:
                dtl = debt_tranches_latest.copy()
                if "quarter" in dtl.columns:
                    dtl["quarter"] = pd.to_datetime(dtl["quarter"], errors="coerce")
                    dtl = dtl[dtl["quarter"].notna()]
                    dtl = dtl[dtl["quarter"].dt.to_period("Q") == q0.to_period("Q")]
                if not dtl.empty:
                    amt_col = _resolve_col(dtl, ["amount_principal", "amount", "principal", "principal_amount"])
                    if amt_col:
                        dedup_cols = [c for c in ["tranche_key", "tranche_name", amt_col, "maturity_year", "coupon_pct", "spread_pct"] if c in dtl.columns]
                        dtl2 = dtl.drop_duplicates(subset=dedup_cols) if dedup_cols else dtl
                        tr_sum_unique = float(pd.to_numeric(dtl2[amt_col], errors="coerce").dropna().sum())
            if (tr_sum_unique is None or abs(float(tr_sum_unique or 0.0)) < 1.0) and debt_buckets is not None and not debt_buckets.empty:
                db0 = debt_buckets.copy()
                asof_col_db0 = _resolve_col(db0, ["as_of", "quarter"])
                sum_col_db0 = _resolve_col(db0, ["Tranche_sum", "tranche_sum", "Total_bucketed", "total_bucketed"])
                if asof_col_db0 and sum_col_db0:
                    db0[asof_col_db0] = pd.to_datetime(db0[asof_col_db0], errors="coerce")
                    db0 = db0[db0[asof_col_db0].notna()]
                    db0 = db0[db0[asof_col_db0].dt.to_period("Q") == q0.to_period("Q")]
                    if not db0.empty:
                        db0_last = db0.sort_values(asof_col_db0).iloc[-1]
                        sum_num = pd.to_numeric(db0_last.get(sum_col_db0), errors="coerce")
                        if pd.notna(sum_num):
                            tr_sum_unique = float(sum_num)
                        src_db0 = str(db0_last.get(_resolve_col(db0, ["Source", "source"]) or "") or "").lower()
                        if "scheduled_repayments_fallback" in src_db0 and debt_profile is not None and not debt_profile.empty:
                            dpf0 = debt_profile.copy()
                            metric_col_dpf0 = _resolve_col(dpf0, ["metric"])
                            value_col_dpf0 = _resolve_col(dpf0, ["value"])
                            if metric_col_dpf0 and value_col_dpf0:
                                v_long = pd.to_numeric(
                                    dpf0.loc[dpf0[metric_col_dpf0] == "debt_long_term", value_col_dpf0],
                                    errors="coerce",
                                ).dropna()
                                if not v_long.empty:
                                    debt_basis_latest = float(v_long.iloc[-1])
                                    debt_basis_label = "debt_long_term"

            rev_drawn_latest = None
            if revolver_history is not None and not revolver_history.empty:
                rv = revolver_history.copy()
                q_col_rv = _resolve_col(rv, ["quarter", "quarter_end", "as_of"])
                drawn_col = _resolve_col(rv, ["revolver_drawn", "drawn", "drawn_amount"])
                if q_col_rv and drawn_col:
                    rv[q_col_rv] = pd.to_datetime(rv[q_col_rv], errors="coerce")
                    rv = rv[rv[q_col_rv].notna()]
                    rv = rv[rv[q_col_rv].dt.to_period("Q") == q0.to_period("Q")]
                    if not rv.empty:
                        rv_last = rv.sort_values(q_col_rv).iloc[-1]
                        rv_num = pd.to_numeric(rv_last.get(drawn_col), errors="coerce")
                        if pd.notna(rv_num):
                            rev_drawn_latest = float(rv_num)

            other_debt_items = 0.0
            other_source = "default_zero"
            if debt_recon is not None and not debt_recon.empty:
                dr = debt_recon.copy()
                q_col_dr = _resolve_col(dr, ["quarter", "as_of"])
                diff_col_dr = _resolve_col(dr, ["diff", "other_debt_items"])
                if q_col_dr and diff_col_dr:
                    dr[q_col_dr] = pd.to_datetime(dr[q_col_dr], errors="coerce")
                    dr = dr[dr[q_col_dr].notna()]
                    dr = dr[dr[q_col_dr].dt.to_period("Q") == q0.to_period("Q")]
                    if not dr.empty:
                        dr_last = dr.sort_values(q_col_dr).iloc[-1]
                        other_num = pd.to_numeric(dr_last.get(diff_col_dr), errors="coerce")
                        if pd.notna(other_num):
                            other_debt_items = float(other_num)
                            other_source = "Debt_Recon.diff"

            if debt_basis_latest is not None and tr_sum_unique is not None:
                comp = float(tr_sum_unique) + float(rev_drawn_latest or 0.0) + float(other_debt_items or 0.0)
                diff = comp - float(debt_basis_latest)
                abs_diff = abs(diff)
                rel_diff = abs_diff / max(1.0, abs(float(debt_basis_latest)))
                if abs_diff <= 5_000_000.0 or rel_diff <= 0.02:
                    sev = "info"
                elif abs_diff <= 25_000_000.0:
                    sev = "warn"
                else:
                    sev = "fail"
                _add(
                    sev,
                    "QA_DebtTieOut",
                    (
                        f"Debt tie-out ({q0d}): tranches {_money_m(tr_sum_unique)} + revolver_drawn {_money_m(rev_drawn_latest)} "
                        f"+ other_debt_items {_money_m(other_debt_items)} [{other_source}] vs {debt_basis_label} {_money_m(debt_basis_latest)} "
                        f"=> diff {_money_m(diff)}"
                    ),
                    "Debt_Tranches_Latest/Revolver_History/Debt_Recon/History_Q",
                )
            else:
                _add(
                    "warn",
                    "QA_DebtTieOut",
                    "Debt tie-out skipped: missing debt_core or tranche principal sum for latest quarter.",
                    "Debt_Tranches_Latest/History_Q",
                )

            if debt_buckets is not None and not debt_buckets.empty:
                db = debt_buckets.copy()
                asof_col = _resolve_col(db, ["as_of", "quarter"])
                cov_col = _resolve_col(db, ["Bucket_coverage_pct", "bucket_coverage_pct", "coverage_pct"])
                if asof_col and cov_col:
                    db[asof_col] = pd.to_datetime(db[asof_col], errors="coerce")
                    db = db[db[asof_col].notna()]
                    db = db[db[asof_col].dt.to_period("Q") == q0.to_period("Q")]
                    if db.empty:
                        db = debt_buckets.copy()
                    if not db.empty:
                        db_last = db.sort_values(asof_col).iloc[-1]
                        cov_val = pd.to_numeric(db_last.get(cov_col), errors="coerce")
                        if pd.notna(cov_val):
                            cov_f = float(cov_val)
                            sev = "info" if cov_f >= 0.90 else "warn"
                            _add(
                                sev,
                                "QA_DebtCoverage",
                                f"Debt_Buckets coverage {cov_f:.2%} (target >= 90%).",
                                "Debt_Buckets",
                            )
                        else:
                            _add("warn", "QA_DebtCoverage", "Debt_Buckets coverage metric missing.", "Debt_Buckets")
                else:
                    _add("warn", "QA_DebtCoverage", "Debt_Buckets missing as_of/coverage columns.", "Debt_Buckets")

            if debt_recon is not None and not debt_recon.empty and debt_core_latest is not None:
                dr = debt_recon.copy()
                q_col_dr = _resolve_col(dr, ["quarter", "as_of"])
                total_col_dr = _resolve_col(dr, ["total_debt", "debt_core", "table_total_debt"])
                if q_col_dr and total_col_dr:
                    dr[q_col_dr] = pd.to_datetime(dr[q_col_dr], errors="coerce")
                    dr = dr[dr[q_col_dr].notna()]
                    dr = dr[dr[q_col_dr].dt.to_period("Q") == q0.to_period("Q")]
                    if not dr.empty:
                        dr_last = dr.sort_values(q_col_dr).iloc[-1]
                        recon_total = pd.to_numeric(dr_last.get(total_col_dr), errors="coerce")
                        if pd.notna(recon_total):
                            diff_abs = abs(float(recon_total) - float(debt_core_latest))
                            sev = "info" if diff_abs <= 5_000_000.0 else "warn"
                            _add(
                                sev,
                                "QA_DebtRecon",
                                f"Debt_Recon {total_col_dr} {_money_m(recon_total)} vs History_Q debt_core {_money_m(debt_core_latest)}.",
                                "Debt_Recon/History_Q",
                            )
                        else:
                            _add("warn", "QA_DebtRecon", "Debt_Recon total value missing for latest quarter.", "Debt_Recon")
                    else:
                        _add("warn", "QA_DebtRecon", "Debt_Recon has no latest-quarter row.", "Debt_Recon")
                else:
                    _add("warn", "QA_DebtRecon", "Debt_Recon missing quarter/total columns.", "Debt_Recon")
        except Exception as _debt_qa_ex:
            _add("warn", "QA_DebtTieOut", f"Debt tie-out QA failed: {_debt_qa_ex}", "pipeline")

        # Source coverage checks.
        er_dir = _first_existing_material_dir(
            "earnings_release",
            "Earnings Release",
            "Earnings Releases",
            "press_release",
            "Press Release",
        )
        er_files = (
            sorted(
                [
                    p
                    for p in er_dir.glob("*")
                    if p.is_file() and _path_belongs_to_ticker(p, ticker, ticker_roots)
                ]
            )
            if er_dir is not None and er_dir.exists()
            else []
        )
        _add(
            "info" if er_files else "warn",
            "QA_Sources",
            f"earnings_release files: {len(er_files)}",
            str(er_dir) if er_dir is not None else "N/A",
        )
        seg_files: List[Path] = []
        for root in material_roots:
            seg_files.extend(
                [
                    p
                    for p in sorted(root.glob("*Segment*Q4*2025*.xlsx"))
                    if _path_belongs_to_ticker(p, ticker, ticker_roots)
                ]
            )
            if (root / "financial_statement").exists():
                seg_files.extend(
                    [
                        p
                        for p in sorted((root / "financial_statement").glob("*Segment*Q4*2025*.xlsx"))
                        if _path_belongs_to_ticker(p, ticker, ticker_roots)
                    ]
                )
        _add(
            "info" if seg_files else "warn",
            "QA_Sources",
            f"segment workbook files: {len(seg_files)}",
            "ticker_root/*Segment*Q4*2025*.xlsx",
        )
        has_slides_seg = False
        seg_subset = pd.DataFrame()
        if slides_segments is not None and not slides_segments.empty and "quarter" in slides_segments.columns:
            ss = slides_segments.copy()
            ss["quarter"] = pd.to_datetime(ss["quarter"], errors="coerce")
            seg_subset = ss[ss["quarter"].dt.to_period("Q") == q0.to_period("Q")].copy()
            has_slides_seg = not seg_subset.empty
        _add("info" if has_slides_seg else "warn", "QA_Sources", f"slides segment rows for {q0d}: {'present' if has_slides_seg else 'missing'}", "Slides_Segments")

        # Segment workbook check (when a workbook and extracted slide segments are both available).
        if seg_files and has_slides_seg and not seg_subset.empty:
            try:
                s_col = _resolve_col(seg_subset, ["segment", "segment_name"])
                m_col = _resolve_col(seg_subset, ["metric"])
                v_col = _resolve_col(seg_subset, ["value"])
                if s_col and m_col and v_col:
                    seg_subset[v_col] = pd.to_numeric(seg_subset[v_col], errors="coerce")
                    seg_subset = seg_subset[seg_subset[v_col].notna()]
                    seg_subset = seg_subset[seg_subset[m_col].astype(str).str.lower().str.contains("revenue|ebitda|adj_segment_ebitda")]
                    seg_model = (
                        seg_subset.groupby(seg_subset[s_col].astype(str).str.strip())[v_col]
                        .sum()
                        .sort_values(key=lambda s: s.abs(), ascending=False)
                        .head(3)
                    )
                    wb_seg = pd.ExcelFile(seg_files[-1])
                    seg_lines: List[str] = []
                    for sh in wb_seg.sheet_names[:12]:
                        try:
                            df_sh = wb_seg.parse(sh, header=None)
                        except Exception:
                            continue
                        # flatten each row for fuzzy segment matching
                        for _, rr in df_sh.head(300).iterrows():
                            line = " ".join([str(x) for x in rr.tolist() if str(x).strip().lower() not in {"", "nan", "none"}])
                            if line:
                                seg_lines.append(line)

                    def _line_number_candidates(line: str) -> List[float]:
                        vals: List[float] = []
                        for mm in re.finditer(r"(?<![A-Za-z])\(?-?[0-9]{1,3}(?:,[0-9]{3})*(?:\.[0-9]+)?\)?", line):
                            raw = str(mm.group(0) or "").replace("(", "-").replace(")", "").replace(",", "")
                            try:
                                vals.append(float(raw))
                            except Exception:
                                continue
                        return vals

                    for seg_name, seg_val in seg_model.items():
                        seg_l = str(seg_name).lower()
                        best_num: Optional[float] = None
                        for ln in seg_lines:
                            if seg_l not in ln.lower():
                                continue
                            nums = _line_number_candidates(ln)
                            if not nums:
                                continue
                            cand = max(nums, key=lambda x: abs(x))
                            if best_num is None or abs(cand) > abs(best_num):
                                best_num = cand
                        if best_num is None:
                            _add("warn", "QA_Segment", f"{seg_name}: not found in segment workbook text rows", str(seg_files[-1]))
                            continue
                        # Workbook values are often in $m; normalize into dollars when needed.
                        wb_val = float(best_num) * (1e6 if abs(float(best_num)) < 10000 else 1.0)
                        model_val = float(seg_val)
                        diff_abs = abs(model_val - wb_val)
                        rel = diff_abs / max(1.0, abs(model_val))
                        sev = "info" if (diff_abs <= 20_000_000 or rel <= 0.20) else "warn"
                        _add(
                            sev,
                            "QA_Segment",
                            f"{seg_name}: model {_money_m(model_val)} vs workbook {_money_m(wb_val)}",
                            str(seg_files[-1]),
                        )
            except Exception:
                _add("warn", "QA_Segment", "segment workbook comparison failed (parse error)", str(seg_files[-1]))

        return qa_rows

    def _write_bs_segments_sheet(quarters_shown: int = 8) -> List[Dict[str, Any]]:
        qa_rows: List[Dict[str, Any]] = []
        if "BS_Segments" in wb.sheetnames:
            old = wb["BS_Segments"]
            idx_old = wb._sheets.index(old)
            wb.remove(old)
            ws = wb.create_sheet("BS_Segments", idx_old)
        else:
            ws = wb.create_sheet("BS_Segments")

        ws.sheet_format.defaultRowHeight = 18
        ws.sheet_view.zoomScale = 110

        ws_val = wb["Valuation"] if "Valuation" in wb.sheetnames else None
        style_bundle = _get_valuation_style_bundle()
        header_fill = copy(style_bundle["header_fill"])
        section_fill = copy(style_bundle["section_fill"])
        bold = copy(style_bundle["bold_font"])
        title_fill = copy(style_bundle["title_fill"])
        thin_border = copy(style_bundle["thin_border"])
        valuation_quarter_style_a = style_bundle.get("valuation_quarter_style_a")
        valuation_quarter_style_col = style_bundle.get("valuation_quarter_style_col")
        valuation_actuals_style_col = style_bundle.get("valuation_actuals_style_col")
        valuation_section_label_style = style_bundle.get("valuation_section_label_style")
        valuation_section_col_style = style_bundle.get("valuation_section_col_style")
        valuation_label_style = style_bundle.get("valuation_label_style")
        valuation_numeric_style = style_bundle.get("valuation_numeric_style")
        valuation_bucket_fills: Dict[str, PatternFill] = dict(style_bundle.get("valuation_bucket_fills") or {})
        valuation_col_widths: Dict[str, Optional[float]] = dict(style_bundle.get("valuation_col_widths") or {})
        valuation_row_height_actual: Optional[float] = style_bundle.get("valuation_row_height_actual")
        valuation_row_height_quarter: Optional[float] = style_bundle.get("valuation_row_height_quarter")
        valuation_data_font_size: float = float(style_bundle.get("valuation_data_font_size") or font_size)

        if ws_val is not None:
            for cc in range(1, 8):
                src = ws_val.cell(row=1, column=cc)
                dst = ws.cell(row=1, column=cc)
                dst.value = src.value
                dst._style = copy(src._style)
        else:
            ws["A1"] = "Scale"
            ws["B1"] = "$m"
        ws["A2"] = "Values scaled to $m unless %"
        ws["A4"] = "QA: pending"
        ws["A4"].font = Font(bold=True, size=11)

        if hist is None or hist.empty or "quarter" not in hist.columns:
            ws["A4"] = "No data."
            return qa_rows

        h = _hist_view().copy()
        if "_quarter" in h.columns:
            h["quarter"] = h["_quarter"]
        h = h[h["quarter"].notna()].sort_values("quarter")
        if h.empty:
            ws["A4"] = "No data."
            return qa_rows

        qs = sorted(h["quarter"].dropna().unique())
        qs = qs[-int(max(1, quarters_shown)) :]
        start_col = 2
        actuals_row = 10
        quarter_row = 11
        row_idx = 12
        last_col = start_col + len(qs) - 1
        last_col_letter = get_column_letter(last_col)

        title_end_col = max(last_col, 9)
        ws.merge_cells(start_row=8, start_column=1, end_row=8, end_column=title_end_col)
        ws["A8"] = "Balance sheet & Segments"
        ws["A8"].font = Font(bold=True, size=15)
        ws["A8"].alignment = Alignment(horizontal="center", vertical="center")
        ws["A8"].fill = title_fill
        ws.row_dimensions[8].height = 24

        ws.merge_cells(start_row=actuals_row, start_column=start_col, end_row=actuals_row, end_column=last_col)
        ws[f"{get_column_letter(start_col)}{actuals_row}"] = "Actuals"
        ws[f"{get_column_letter(start_col)}{actuals_row}"].font = bold
        ws[f"{get_column_letter(start_col)}{actuals_row}"].alignment = Alignment(horizontal="center")
        ws[f"A{quarter_row}"] = "Quarter"
        if valuation_quarter_style_a is not None:
            ws[f"A{quarter_row}"]._style = copy(valuation_quarter_style_a)
        else:
            ws[f"A{quarter_row}"].font = bold
            ws[f"A{quarter_row}"].fill = header_fill
        for i, q in enumerate(qs):
            col = start_col + i
            col_letter = get_column_letter(col)
            qd = pd.Timestamp(q).date()
            ws[f"{col_letter}{quarter_row}"] = f"{qd.year}-Q{((qd.month - 1) // 3) + 1}"
            if valuation_quarter_style_col is not None:
                ws[f"{col_letter}{quarter_row}"]._style = copy(valuation_quarter_style_col)
            else:
                ws[f"{col_letter}{quarter_row}"].font = bold
                ws[f"{col_letter}{quarter_row}"].alignment = Alignment(horizontal="center")
                ws[f"{col_letter}{quarter_row}"].fill = header_fill
                ws[f"{col_letter}{quarter_row}"].border = thin_border
            if valuation_actuals_style_col is not None:
                ws[f"{col_letter}{actuals_row}"]._style = copy(valuation_actuals_style_col)
            else:
                ws[f"{col_letter}{actuals_row}"].fill = header_fill
                ws[f"{col_letter}{actuals_row}"].border = thin_border
        if valuation_row_height_actual is not None:
            ws.row_dimensions[actuals_row].height = valuation_row_height_actual
        if valuation_row_height_quarter is not None:
            ws.row_dimensions[quarter_row].height = valuation_row_height_quarter

        h_idx = h.set_index("quarter")

        def _load_local_balance_sheet_detail_payloads(target_quarters: set[date]) -> Dict[date, Dict[str, Any]]:
            out_local: Dict[date, Dict[str, Any]] = {}
            for path_in in _operating_driver_financial_statement_files():
                raw_txt = _read_operating_driver_text(path_in)
                if not raw_txt:
                    continue
                qd = _parse_quarter_from_filename(path_in.name) or _parse_quarter_from_follow_text(raw_txt) or infer_quarter_end_from_text(raw_txt)
                if not isinstance(qd, date) or qd not in target_quarters:
                    continue
                result = None
                try:
                    if path_in.suffix.lower() in {".htm", ".html"}:
                        result = _extract_balance_sheet_from_html(path_in.read_bytes(), qd)
                    else:
                        result = _extract_balance_sheet_from_text(raw_txt, qd)
                except Exception:
                    result = None
                if not result:
                    continue
                payload = dict(result)
                payload["source_doc"] = str(path_in)
                if qd not in out_local or len(payload.get("values", {})) >= len(out_local[qd].get("values", {})):
                    out_local[qd] = payload
            return out_local

        def _extract_segment_line_values(line_in: Any, year_count: int, *, exact_count: bool = False) -> List[float]:
            return ew_extract_segment_line_values(line_in, year_count, exact_count=exact_count)

        def _annual_segment_label(metric_label: str, line_in: Any) -> str:
            return ew_annual_segment_label(
                metric_label,
                line_in,
                annual_segment_alias_patterns=annual_segment_alias_patterns,
                company_segment_alias_patterns=company_profile.segment_alias_patterns,
            )

        def _extract_year_from_cell(value_in: Any) -> Optional[int]:
            return ew_extract_year_from_cell(value_in)

        def _latest_segment_financials_workbook() -> Optional[Path]:
            return ew_latest_segment_financials_workbook(_first_existing_material_dir("segment_financials"))

        def _extract_quarter_from_cell(value_in: Any) -> Optional[pd.Timestamp]:
            return ew_extract_quarter_from_cell(value_in)

        def _quarterly_segment_label(metric_label: str, line_in: Any) -> str:
            return ew_quarterly_segment_label(
                metric_label,
                line_in,
                annual_segment_alias_patterns=annual_segment_alias_patterns,
                company_segment_alias_patterns=company_profile.segment_alias_patterns,
            )

        def _parse_quarterly_segment_data_from_workbook(path_in: Path) -> Dict[str, Any]:
            return ew_parse_quarterly_segment_data_from_workbook(
                path_in,
                annual_segment_alias_patterns=annual_segment_alias_patterns,
                company_segment_alias_patterns=company_profile.segment_alias_patterns,
            )

        def _parse_annual_segment_data_from_workbook(path_in: Path) -> Dict[str, Any]:
            return ew_parse_annual_segment_data_from_workbook(
                path_in,
                annual_segment_alias_patterns=annual_segment_alias_patterns,
                company_segment_alias_patterns=company_profile.segment_alias_patterns,
            )

        def _parse_annual_segment_data_from_text(text_in: Any) -> Dict[str, Any]:
            raw_txt = str(text_in or "")
            if not raw_txt:
                return {}
            out: Dict[str, Any] = {"metrics": {}, "assets": {}, "years": []}
            annual_segment_noise_re = re.compile(
                r"\b(ebitda margin|adjusted segment ebitda|pbi adj(?:u)?ted ebitda|"
                r"adjusted segment ebit|pbi adjusted ebit)\b",
                re.I,
            )
            lines = []
            for raw_line in raw_txt.replace("\r", "").splitlines():
                line = str(raw_line or "").replace("â€”", "—")
                line = re.sub(r"\(\d+\)", "", line)
                line = re.sub(r"\s+", " ", line).strip()
                if line:
                    lines.append(line)
            if not lines:
                return {}

            def _line_years(line_in: str) -> List[int]:
                years = [int(y) for y in re.findall(r"\b20\d{2}\b", line_in)]
                if len(years) >= 2 and years == sorted(years, reverse=True):
                    return years
                return []

            metric_map = {
                "revenues": "Revenues",
                "gross_margin": "Gross margin",
                "depreciation_amortization": "Depreciation & amortization",
                "operating_income_loss": "Operating income (loss)",
            }
            in_financials = False
            in_assets = False
            section_key = ""
            section_years: List[int] = []
            asset_years: List[int] = []
            current_segment = ""
            for line in lines:
                low = line.lower()
                if annual_segment_noise_re.search(line):
                    continue
                if "selected operating segment financial information are as follows" in low:
                    in_financials = True
                    in_assets = False
                    section_key = ""
                    section_years = []
                    current_segment = ""
                    continue
                if "total assets by segment are as follows" in low:
                    in_financials = False
                    in_assets = True
                    asset_years = []
                    continue
                if low.startswith("we use ebitda") or low.startswith("the following table reconciles net loss"):
                    in_financials = False
                if low.startswith("year ended december 31, ") and "compared with" in low:
                    in_assets = False
                if low.startswith("the following discussion provides greater detail") or low.startswith("key operating data for our ethanol production segment is as follows"):
                    in_assets = False
                if line.startswith("F-") or low.startswith("table of contents"):
                    continue

                if in_financials:
                    years = _line_years(line)
                    if low.startswith("year ended december 31"):
                        continue
                    if years:
                        section_years = years
                        out["years"] = sorted(set(list(out["years"]) + years))
                        continue
                    if low == "revenues":
                        section_key = "revenues"
                        current_segment = ""
                        continue
                    if low == "cost of goods sold":
                        section_key = ""
                        current_segment = ""
                        continue
                    if low == "gross margin":
                        section_key = "gross_margin"
                        current_segment = ""
                        continue
                    if low == "depreciation and amortization":
                        section_key = "depreciation_amortization"
                        current_segment = ""
                        continue
                    if low.startswith("operating income"):
                        section_key = "operating_income_loss"
                        current_segment = ""
                        continue
                    if line.startswith("$"):
                        continue
                    seg = _annual_segment_label("Revenues" if section_key == "revenues" else metric_map.get(section_key, ""), line)
                    if section_key == "revenues":
                        if seg and seg != "Intersegment eliminations":
                            current_segment = seg
                            continue
                        if not section_years:
                            continue
                        if "total segment revenues" in low and current_segment:
                            vals = _extract_segment_line_values(line, len(section_years), exact_count=True)
                            if len(vals) == len(section_years):
                                for yy, vv in zip(section_years, vals):
                                    out["metrics"].setdefault("Revenues", {}).setdefault(current_segment, {})[yy] = vv
                            continue
                        if seg == "Intersegment eliminations":
                            vals = _extract_segment_line_values(line, len(section_years), exact_count=True)
                            if len(vals) == len(section_years):
                                for yy, vv in zip(section_years, vals):
                                    out["metrics"].setdefault("Revenues", {}).setdefault(seg, {})[yy] = vv
                            continue
                    elif section_key in {"gross_margin", "depreciation_amortization", "operating_income_loss"} and seg and section_years:
                        if any(
                            cue in low
                            for cue in [
                                " includes ",
                                " include ",
                                " compared with ",
                                " as a result ",
                                " primarily due ",
                                " primarily as a result ",
                                " for the year ended ",
                            ]
                        ):
                            continue
                        if len(line) > 120:
                            continue
                        vals = _extract_segment_line_values(line, len(section_years), exact_count=True)
                        if len(vals) != len(section_years):
                            continue
                        metric_label = metric_map.get(section_key, section_key)
                        for yy, vv in zip(section_years, vals):
                            out["metrics"].setdefault(metric_label, {}).setdefault(seg, {})[yy] = vv

                if in_assets:
                    years = _line_years(line)
                    if low.startswith("year ended december 31"):
                        continue
                    if years:
                        asset_years = years
                        out["years"] = sorted(set(list(out["years"]) + years))
                        continue
                    if low.startswith("total assets") or line.startswith("$"):
                        continue
                    seg = _annual_segment_label("Total assets", line)
                    if not seg or not asset_years:
                        continue
                    vals = _extract_segment_line_values(line, len(asset_years), exact_count=True)
                    if len(vals) != len(asset_years):
                        continue
                    for yy, vv in zip(asset_years, vals):
                        out["assets"].setdefault(seg, {})[yy] = vv
            return out

        def _load_latest_annual_segment_data() -> Dict[str, Any]:
            if not enable_annual_segment_block:
                return {}
            workbook_path = _latest_segment_financials_workbook()
            if workbook_path is not None:
                parsed_wb = _parse_annual_segment_data_from_workbook(workbook_path)
                if parsed_wb.get("metrics") or parsed_wb.get("assets"):
                    parsed_wb["source_doc"] = str(workbook_path)
                    parsed_wb["source_qd"] = _parse_quarter_from_filename(workbook_path.name)
                    return parsed_wb
            best_path: Optional[Path] = None
            best_qd: Optional[date] = None
            for path_in in _operating_driver_financial_statement_files():
                nm = path_in.name.lower()
                if "10-k" not in nm and "10k" not in nm:
                    continue
                raw_txt = _read_operating_driver_text(path_in)
                if not raw_txt:
                    continue
                qd = _parse_quarter_from_filename(path_in.name) or _parse_quarter_from_follow_text(raw_txt) or infer_quarter_end_from_text(raw_txt)
                if not isinstance(qd, date) or qd.month != 12:
                    continue
                if best_qd is None or qd > best_qd:
                    best_qd = qd
                    best_path = path_in
            if best_path is None:
                return {}
            raw_txt = _read_operating_driver_text(best_path)
            parsed = _parse_annual_segment_data_from_text(raw_txt)
            if parsed:
                parsed["source_doc"] = str(best_path)
                parsed["source_qd"] = best_qd
            return parsed

        def _load_latest_quarterly_segment_data() -> Dict[str, Any]:
            if not enable_quarterly_segment_block:
                return {}
            workbook_path = _latest_segment_financials_workbook()
            if workbook_path is None:
                return {}
            parsed = _parse_quarterly_segment_data_from_workbook(workbook_path)
            if parsed:
                parsed["source_doc"] = str(workbook_path)
                parsed["source_qd"] = _parse_quarter_from_filename(workbook_path.name)
            return parsed

        def _pick_col(cands: List[str]) -> Optional[str]:
            cols_lc = {str(c).strip().lower(): c for c in h_idx.columns}
            for cand in cands:
                c = cols_lc.get(str(cand).strip().lower())
                if c is None:
                    continue
                ser = pd.to_numeric(h_idx[c], errors="coerce")
                if ser.notna().any():
                    return str(c)
            return None

        def _map_from_col(col: Optional[str]) -> Dict[pd.Timestamp, Optional[float]]:
            if col is None or col not in h_idx.columns:
                return {}
            ser = pd.to_numeric(h_idx[col], errors="coerce")
            out: Dict[pd.Timestamp, Optional[float]] = {}
            for k, v in ser.items():
                out[pd.Timestamp(k)] = float(v) if pd.notna(v) else None
            return out

        maps: Dict[str, Dict[pd.Timestamp, Optional[float]]] = {
            "cash": _map_from_col(_pick_col(["cash", "cash_and_cash_equivalents"])),
            "sti": _map_from_col(_pick_col(["short_term_investments", "short_term_investment"])),
            "ar": _map_from_col(_pick_col(["accounts_receivable", "accounts_receivable_net"])),
            "inventory": _map_from_col(_pick_col(["inventory"])),
            "assets_current": _map_from_col(_pick_col(["assets_current", "total_current_assets"])),
            "assets": _map_from_col(_pick_col(["assets", "total_assets"])),
            "ppne": _map_from_col(_pick_col(["ppne_net", "property_plant_equipment_net", "ppe_net"])),
            "goodwill": _map_from_col(_pick_col(["goodwill"])),
            "intangibles": _map_from_col(_pick_col(["intangibles", "intangible_assets_net_excluding_goodwill"])),
            "other_lt_assets": _map_from_col(_pick_col(["other_assets_noncurrent", "other_long_term_assets"])),
            "ap": _map_from_col(_pick_col(["accounts_payable", "accounts_payable_current"])),
            "accrued": _map_from_col(_pick_col(["accrued_liabilities", "accrued_liabilities_current", "other_accrued_liabilities"])),
            "def_rev": _map_from_col(_pick_col(["deferred_revenue", "deferred_revenue_current", "bank_deposits"])),
            "liabilities_current": _map_from_col(_pick_col(["liabilities_current", "total_current_liabilities"])),
            "liabilities": _map_from_col(_pick_col(["liabilities", "total_liabilities"])),
            "debt_st": _map_from_col(_pick_col(["debt_current", "short_term_debt", "long_term_debt_current"])),
            "debt_total": _map_from_col(_pick_col(["debt_core", "total_debt", "long_term_debt"])),
            "lease_lt": _map_from_col(_pick_col(["lease_liabilities_noncurrent", "lease_liabilities"])),
            "pension": _map_from_col(_pick_col(["pension_obligation_net", "pension_liabilities"])),
            "other_lt_liab": _map_from_col(_pick_col(["other_liabilities_noncurrent", "other_long_term_liabilities"])),
            "equity": _map_from_col(_pick_col(["total_equity", "stockholders_equity"])),
            "shares_out": _map_from_col(_pick_col(["shares_outstanding"])),
            "shares_dil": _map_from_col(_pick_col(["shares_diluted"])),
            "fin_recv": _map_from_col(_pick_col(["bank_finance_receivables"])),
            "deposits": _map_from_col(_pick_col(["bank_deposits"])),
            "bank_net_funding": _map_from_col(_pick_col(["bank_net_funding"])),
            "revenue": _map_from_col(_pick_col(["revenue"])),
        }

        local_bs_payloads = _shared_load_local_balance_sheet_detail_payloads({pd.Timestamp(x).date() for x in qs})

        def _payload_map(keys: List[str], hist_cols: Optional[List[str]] = None) -> Dict[pd.Timestamp, Optional[float]]:
            hist_map = _map_from_col(_pick_col(hist_cols or [])) if hist_cols else {}
            out_map: Dict[pd.Timestamp, Optional[float]] = {}
            for q in [pd.Timestamp(x) for x in qs]:
                hist_val = hist_map.get(q)
                if hist_val is not None:
                    out_map[q] = hist_val
                    continue
                payload = local_bs_payloads.get(q.date()) or {}
                vals = payload.get("values", {}) or {}
                chosen: Optional[float] = None
                for key_name in keys:
                    if key_name in vals and vals.get(key_name) is not None:
                        chosen = float(vals[key_name])
                        break
                out_map[q] = chosen
            return out_map

        maps["restricted_cash"] = _payload_map(["restricted_cash"], ["restricted_cash"])
        maps["prepaid_expenses_other_current"] = _payload_map(
            ["prepaid_other_current_assets", "prepaid_expenses_and_other_current_assets"],
            ["prepaid_other_current_assets"],
        )
        maps["derivative_asset"] = _payload_map(["derivative_assets"], ["derivative_assets"])
        maps["rou_asset"] = _payload_map(["operating_lease_rou_assets"], ["operating_lease_rou_assets"])
        maps["deferred_tax"] = _payload_map(["deferred_income_taxes_net"], ["deferred_income_taxes_net"])
        maps["goodwill"] = _payload_map(["goodwill"], ["goodwill"])
        maps["intangibles"] = _payload_map(
            ["intangibles", "intangible_assets_net_excluding_goodwill"],
            ["intangibles", "intangible_assets_net_excluding_goodwill"],
        )
        maps["short_term_notes_borrowings"] = _payload_map(
            ["short_term_notes_payable_and_other_borrowings"],
            ["short_term_notes_payable_and_other_borrowings"],
        )
        maps["current_maturities_ltd"] = _payload_map(
            ["current_maturities_of_long_term_debt"],
            ["current_maturities_of_long_term_debt", "long_term_debt_current"],
        )
        maps["derivative_liability"] = _payload_map(["derivative_liabilities"], ["derivative_liabilities"])
        maps["lease_current"] = _payload_map(["operating_lease_current_liabilities"], ["operating_lease_current_liabilities"])
        maps["lease_long_term"] = _payload_map(
            ["operating_lease_long_term_liabilities"],
            ["operating_lease_long_term_liabilities", "lease_liabilities_noncurrent"],
        )
        maps["carbon_equipment_liabilities"] = _payload_map(["carbon_equipment_liabilities"], ["carbon_equipment_liabilities"])
        maps["other_liabilities_explicit"] = _payload_map(["other_liabilities"], ["other_liabilities_noncurrent"])
        for q in [pd.Timestamp(x) for x in qs]:
            gw_v = maps["goodwill"].get(q)
            if gw_v is not None and abs(float(gw_v)) < 1_000_000.0:
                maps["goodwill"][q] = None
            int_v = maps["intangibles"].get(q)
            if int_v is not None and abs(float(int_v)) < 1_000_000.0:
                maps["intangibles"][q] = None
        maps["goodwill"] = _carry_forward_low_change_series(maps["goodwill"], list(qs))
        maps["intangibles"] = _carry_forward_low_change_series(maps["intangibles"], list(qs))

        total_cash_restricted_map: Dict[pd.Timestamp, Optional[float]] = {}
        for q in [pd.Timestamp(x) for x in qs]:
            cash_v = maps["cash"].get(q)
            restricted_v = maps["restricted_cash"].get(q)
            if cash_v is None and restricted_v is None:
                total_cash_restricted_map[q] = None
            else:
                total_cash_restricted_map[q] = float(cash_v or 0.0) + float(restricted_v or 0.0)

        def _qoq_delta_map(src_map: Dict[pd.Timestamp, Optional[float]]) -> Dict[pd.Timestamp, Optional[float]]:
            out_map: Dict[pd.Timestamp, Optional[float]] = {}
            prev_val: Optional[float] = None
            for q in [pd.Timestamp(x) for x in qs]:
                vv = src_map.get(q)
                if vv is None or prev_val is None:
                    out_map[q] = None
                else:
                    out_map[q] = float(vv) - float(prev_val)
                prev_val = float(vv) if vv is not None else None
            return out_map

        delta_cash_qoq_map = _qoq_delta_map(maps["cash"])
        delta_total_debt_qoq_map = _qoq_delta_map(maps["debt_total"])

        accrued_tag_by_q: Dict[pd.Timestamp, str] = {}
        if audit is not None and not audit.empty:
            try:
                aud_bs = audit.copy()
                qcol_a = _resolve_col(aud_bs, ["quarter", "period_end"])
                mcol_a = _resolve_col(aud_bs, ["metric"])
                tcol_a = _resolve_col(aud_bs, ["tag"])
                vcol_a = _resolve_col(aud_bs, ["value"])
                scol_a = _resolve_col(aud_bs, ["source"])
                fcol_a = _resolve_col(aud_bs, ["filed", "filed_date"])
                if qcol_a and mcol_a and tcol_a and vcol_a:
                    aud_bs["_q"] = pd.to_datetime(aud_bs[qcol_a], errors="coerce").dt.normalize()
                    if fcol_a:
                        aud_bs["_filed"] = pd.to_datetime(aud_bs[fcol_a], errors="coerce")
                    else:
                        aud_bs["_filed"] = pd.NaT
                    aud_bs["_metric"] = aud_bs[mcol_a].astype(str).str.strip().str.lower()
                    if scol_a:
                        aud_bs["_source"] = aud_bs[scol_a].astype(str).str.strip().str.lower()
                        aud_bs = aud_bs[aud_bs["_source"] != "missing"]
                    aud_bs = aud_bs[aud_bs["_q"].notna()]
                    if not aud_bs.empty:
                        aud_bs["_val_num"] = pd.to_numeric(aud_bs[vcol_a], errors="coerce")
                        aud_bs = aud_bs[aud_bs["_val_num"].notna()]
                        accrued_metrics = {"accrued_liabilities_current", "accrued_liabilities", "other_accrued_liabilities"}
                        a_acc = aud_bs[aud_bs["_metric"].isin(accrued_metrics)].copy()
                        if not a_acc.empty:
                            a_acc = a_acc.sort_values("_filed")
                            for _, rr in a_acc.iterrows():
                                qk = pd.Timestamp(rr["_q"])
                                accrued_tag_by_q[qk] = str(rr[tcol_a] or "").strip().lower()
            except Exception:
                pass

        prepaid_map: Dict[pd.Timestamp, Optional[float]] = {}
        for q in [pd.Timestamp(x) for x in qs]:
            explicit_prepaid = maps["prepaid_expenses_other_current"].get(q)
            if explicit_prepaid is not None:
                prepaid_map[q] = float(explicit_prepaid)
                continue
            ac = maps["assets_current"].get(q)
            if ac is None:
                prepaid_map[q] = None
                continue
            parts = [maps["cash"].get(q), maps["sti"].get(q), maps["ar"].get(q), maps["inventory"].get(q), maps["derivative_asset"].get(q)]
            if any(v is None for v in parts):
                prepaid_map[q] = None
                continue
            prepaid_map[q] = float(ac) - sum(float(v) for v in parts if v is not None)

        debt_lt_map: Dict[pd.Timestamp, Optional[float]] = {}
        for q in [pd.Timestamp(x) for x in qs]:
            total = maps["debt_total"].get(q)
            st = maps["current_maturities_ltd"].get(q)
            if st is None:
                st = maps["debt_st"].get(q)
            if total is None:
                debt_lt_map[q] = None
            elif st is None:
                debt_lt_map[q] = float(total)
            else:
                debt_lt_map[q] = float(total) - float(st)

        # If accrued liabilities came from AP+accrued combined tag, strip AP where both are available.
        for q in [pd.Timestamp(x) for x in qs]:
            tag_l = str(accrued_tag_by_q.get(q) or "").strip().lower()
            if "accountspayableandaccruedliabilitiescurrent" not in tag_l:
                continue
            acc_v = maps["accrued"].get(q)
            ap_v = maps["ap"].get(q)
            if acc_v is None or ap_v is None:
                continue
            adj_v = float(acc_v) - float(ap_v)
            if adj_v >= -1_000_000.0:
                maps["accrued"][q] = max(adj_v, 0.0)

        # Residual fallbacks for long-term "other" buckets when explicit tags are absent.
        for q in [pd.Timestamp(x) for x in qs]:
            if maps["other_lt_assets"].get(q) is None:
                a_tot = maps["assets"].get(q)
                a_cur = maps["assets_current"].get(q)
                ppne_v = maps["ppne"].get(q)
                rou_v = maps["rou_asset"].get(q)
                dtx_v = maps["deferred_tax"].get(q)
                gw_v = maps["goodwill"].get(q)
                int_v = maps["intangibles"].get(q)
                if all(v is not None for v in [a_tot, a_cur, ppne_v, gw_v, int_v]):
                    resid_a = float(a_tot) - (
                        float(a_cur)
                        + float(ppne_v)
                        + float(rou_v or 0.0)
                        + float(dtx_v or 0.0)
                        + float(gw_v)
                        + float(int_v)
                    )
                    if resid_a >= -5_000_000.0 and abs(resid_a) <= max(abs(float(a_tot)) * 1.25, 10_000_000.0):
                        maps["other_lt_assets"][q] = resid_a
                    elif q == pd.Timestamp(qs[-1]):
                        qa_rows.append(
                            {
                                "quarter": pd.Timestamp(q).date(),
                                "metric": "BS_Segments",
                                "check": "other_lt_assets_residual",
                                "status": "warn",
                                "message": f"Residual other LT assets looks unstable ({resid_a/1e6:,.1f}m); left blank.",
                                "source": "History_Q",
                            }
                        )
            if maps["ppne"].get(q) is None:
                a_tot = maps["assets"].get(q)
                a_cur = maps["assets_current"].get(q)
                oth_a = maps["other_lt_assets"].get(q)
                rou_v = maps["rou_asset"].get(q)
                dtx_v = maps["deferred_tax"].get(q)
                gw_v = maps["goodwill"].get(q)
                int_v = maps["intangibles"].get(q)
                if all(v is not None for v in [a_tot, a_cur, oth_a, gw_v, int_v]):
                    resid_ppne = float(a_tot) - (
                        float(a_cur)
                        + float(oth_a)
                        + float(rou_v or 0.0)
                        + float(dtx_v or 0.0)
                        + float(gw_v)
                        + float(int_v)
                    )
                    if resid_ppne >= -5_000_000.0 and abs(resid_ppne) <= max(abs(float(a_tot)) * 1.25, 10_000_000.0):
                        maps["ppne"][q] = resid_ppne
                    elif q == pd.Timestamp(qs[-1]):
                        qa_rows.append(
                            {
                                "quarter": pd.Timestamp(q).date(),
                                "metric": "BS_Segments",
                                "check": "ppne_residual",
                                "status": "warn",
                                "message": f"Residual PP&E looks unstable ({resid_ppne/1e6:,.1f}m); left blank.",
                                "source": "History_Q",
                            }
                        )
            if maps["other_lt_liab"].get(q) is None:
                l_tot = maps["liabilities"].get(q)
                l_cur = maps["liabilities_current"].get(q)
                d_lt = debt_lt_map.get(q)
                lease_v = maps["lease_long_term"].get(q) if maps["lease_long_term"].get(q) is not None else maps["lease_lt"].get(q)
                pension_v = maps["pension"].get(q)
                carbon_v = maps["carbon_equipment_liabilities"].get(q)
                explicit_other_v = maps["other_liabilities_explicit"].get(q)
                if explicit_other_v is not None:
                    maps["other_lt_liab"][q] = float(explicit_other_v)
                elif all(v is not None for v in [l_tot, l_cur, d_lt, lease_v, pension_v]):
                    resid_l = float(l_tot) - (
                        float(l_cur)
                        + float(d_lt)
                        + float(lease_v)
                        + float(pension_v)
                        + float(carbon_v or 0.0)
                    )
                    if resid_l >= -5_000_000.0 and abs(resid_l) <= max(abs(float(l_tot)) * 1.25, 10_000_000.0):
                        maps["other_lt_liab"][q] = resid_l
                    elif q == pd.Timestamp(qs[-1]):
                        qa_rows.append(
                            {
                                "quarter": pd.Timestamp(q).date(),
                                "metric": "BS_Segments",
                                "check": "other_lt_liabilities_residual",
                                "status": "warn",
                                "message": f"Residual other LT liabilities looks unstable ({resid_l/1e6:,.1f}m); left blank.",
                                "source": "History_Q",
                            }
                        )

        numeric_rows: List[int] = []
        pct_rows: List[int] = []
        no_bucket_rows: set = set()
        delta_nwc_rows: set = set()
        nwc_rows: set = set()

        def _apply_data_font(cell: Any, *, bold_flag: bool = False) -> None:
            f0 = cell.font if cell.font is not None else Font()
            cell.font = Font(
                name=f0.name,
                size=valuation_data_font_size,
                bold=bool(bold_flag),
                italic=f0.italic,
                color=f0.color,
                underline=f0.underline,
                strike=f0.strike,
            )

        def _write_section(label: str) -> None:
            nonlocal row_idx
            ws[f"A{row_idx}"] = label
            if valuation_section_label_style is not None:
                for cc in range(1, last_col + 1):
                    c = ws[f"{get_column_letter(cc)}{row_idx}"]
                    if cc == 1:
                        c._style = copy(valuation_section_label_style)
                    elif valuation_section_col_style is not None:
                        c._style = copy(valuation_section_col_style)
                    else:
                        c._style = copy(valuation_section_label_style)
                    if cc != 1:
                        c.value = None
            else:
                ws[f"A{row_idx}"].font = bold
                for cc in range(1, last_col + 1):
                    c = ws[f"{get_column_letter(cc)}{row_idx}"]
                    c.fill = section_fill
                    c.border = thin_border
            row_idx += 1

        def _set_comment(cell: Any, txt: str) -> None:
            if not txt:
                return
            try:
                _set_cell_comment_local(cell, txt)
            except Exception:
                pass

        def _write_metric(
            label: str,
            val_map: Dict[pd.Timestamp, Optional[float]],
            *,
            value_scale: float = 1e6,
            number_format: str = "#,##0.0",
            bold_label: bool = False,
            comments: Optional[Dict[pd.Timestamp, str]] = None,
            bucket_mode: str = "qoq",
        ) -> int:
            nonlocal row_idx
            ws[f"A{row_idx}"] = label
            if valuation_label_style is not None:
                ws[f"A{row_idx}"]._style = copy(valuation_label_style)
                _apply_data_font(ws[f"A{row_idx}"], bold_flag=False)
            else:
                ws[f"A{row_idx}"].font = Font(bold=False, size=valuation_data_font_size)
            metric_row = row_idx
            for i, q in enumerate(qs):
                qk = pd.Timestamp(q)
                val = val_map.get(qk)
                cc = start_col + i
                cell = ws.cell(row=row_idx, column=cc, value=None if val is None else (float(val) / value_scale if value_scale != 1.0 else float(val)))
                if valuation_numeric_style is not None:
                    cell._style = copy(valuation_numeric_style)
                _apply_data_font(cell, bold_flag=False)
                cell.number_format = number_format
                cell.border = thin_border
                cell.alignment = Alignment(horizontal="right")
                if comments and qk in comments:
                    _set_comment(cell, comments[qk])
            numeric_rows.append(metric_row)
            if "%" in str(number_format):
                pct_rows.append(metric_row)
            if bucket_mode == "none":
                no_bucket_rows.add(metric_row)
            elif bucket_mode == "delta_nwc":
                delta_nwc_rows.add(metric_row)
            elif bucket_mode == "nwc":
                nwc_rows.add(metric_row)
            row_idx += 1
            return metric_row

        _write_section("Liquidity / Assets")
        _write_metric("Cash & cash equivalents", maps["cash"])
        _write_metric("Restricted cash", maps["restricted_cash"])
        _write_metric("Total cash + restricted cash", total_cash_restricted_map, bold_label=True, bucket_mode="none")
        _write_metric("Δ Cash QoQ ($m)", delta_cash_qoq_map, bucket_mode="none")
        _write_metric("Short-term investments", maps["sti"])
        _write_metric("Accounts receivable (net)", maps["ar"])
        _write_metric("Inventory", maps["inventory"])
        _write_metric("Derivative financial instruments (asset)", maps["derivative_asset"])
        _write_metric("Prepaid & other current assets", prepaid_map)
        _write_metric("Total current assets", maps["assets_current"], bold_label=True)
        _write_metric("Property, plant & equipment (net)", maps["ppne"])
        _write_metric("Operating lease right-of-use assets", maps["rou_asset"])
        _write_metric("Deferred income taxes, net", maps["deferred_tax"])
        _write_metric("Goodwill", maps["goodwill"])
        _write_metric("Intangibles (net)", maps["intangibles"])
        _write_metric("Other long-term assets", maps["other_lt_assets"])
        _write_metric("Total assets", maps["assets"], bold_label=True)

        _write_section("Liabilities")
        _write_metric("Accounts payable", maps["ap"])
        _write_metric("Accrued liabilities", maps["accrued"])
        _write_metric("Deferred revenue / customer deposits", maps["def_rev"])
        _write_metric("Derivative financial instruments (liability)", maps["derivative_liability"])
        _write_metric("Short-term notes payable and other borrowings", maps["short_term_notes_borrowings"])
        _write_metric("Current maturities of long-term debt", maps["current_maturities_ltd"])
        _write_metric("Operating lease current liabilities", maps["lease_current"])
        _write_metric("Total current liabilities", maps["liabilities_current"], bold_label=True)
        nwc_map: Dict[pd.Timestamp, Optional[float]] = {}
        delta_nwc_map: Dict[pd.Timestamp, Optional[float]] = {}
        current_ratio_map: Dict[pd.Timestamp, Optional[float]] = {}
        quick_ratio_map: Dict[pd.Timestamp, Optional[float]] = {}
        prev_nwc_val: Optional[float] = None
        for q in [pd.Timestamp(x) for x in qs]:
            ca_v = maps["assets_current"].get(q)
            cl_v = maps["liabilities_current"].get(q)
            c_v = maps["cash"].get(q)
            sti_v = maps["sti"].get(q)
            ar_v = maps["ar"].get(q)
            if ca_v is not None and cl_v is not None:
                nwc_v = float(ca_v) - float(cl_v)
                nwc_map[q] = nwc_v
                if prev_nwc_val is None:
                    delta_nwc_map[q] = None
                else:
                    delta_nwc_map[q] = nwc_v - float(prev_nwc_val)
                prev_nwc_val = nwc_v
                if abs(float(cl_v)) > 1e-12:
                    current_ratio_map[q] = float(ca_v) / float(cl_v)
                else:
                    current_ratio_map[q] = None
            else:
                nwc_map[q] = None
                delta_nwc_map[q] = None
                current_ratio_map[q] = None
                prev_nwc_val = None
            quick_num = None
            if c_v is not None and ar_v is not None:
                quick_num = float(c_v) + float(sti_v or 0.0) + float(ar_v)
            if quick_num is not None and cl_v is not None and abs(float(cl_v)) > 1e-12:
                quick_ratio_map[q] = quick_num / float(cl_v)
            else:
                quick_ratio_map[q] = None
        _write_metric("Net working capital", nwc_map, bold_label=True, bucket_mode="nwc")
        _write_metric("Δ NWC QoQ", delta_nwc_map, bucket_mode="delta_nwc")
        _write_metric("Current ratio", current_ratio_map, value_scale=1.0, number_format="0.00x", bucket_mode="none")
        _write_metric("Quick ratio", quick_ratio_map, value_scale=1.0, number_format="0.00x", bucket_mode="none")
        _write_metric("Long-term debt", debt_lt_map)
        _write_metric("Δ Total debt QoQ ($m)", delta_total_debt_qoq_map, bucket_mode="none")
        _write_metric("Carbon equipment liabilities", maps["carbon_equipment_liabilities"])
        _write_metric(
            "Operating lease long-term liabilities",
            {q: (maps["lease_long_term"].get(q) if maps["lease_long_term"].get(q) is not None else maps["lease_lt"].get(q)) for q in [pd.Timestamp(x) for x in qs]},
        )
        _write_metric("Pension / OPEB obligation (net)", maps["pension"])
        _write_metric("Other long-term liabilities", maps["other_lt_liab"])
        _write_metric("Total liabilities", maps["liabilities"], bold_label=True)

        _write_section("Equity")
        _write_metric("Total equity", maps["equity"], bold_label=True)
        _write_metric("Shares outstanding (m)", maps["shares_out"], value_scale=1e6, number_format="0.0")
        _write_metric("Shares diluted (m)", maps["shares_dil"], value_scale=1e6, number_format="0.0")

        if bank_metrics_enabled:
            _write_section("Bank / Financing (optional)")
            _write_metric("Finance receivables (total)", maps["fin_recv"])
            _write_metric("Deposits (bank/customer)", maps["deposits"])
            _write_metric("Bank net funding", maps["bank_net_funding"])

        quarterly_segment_data = _load_latest_quarterly_segment_data()
        quarterly_metrics = dict(quarterly_segment_data.get("metrics") or {})
        quarterly_source_note = str(quarterly_segment_data.get("source_doc") or "").strip()
        if quarterly_metrics:
            row_idx += 1
            _write_section("Quarterly segments")

            quarterly_metric_order = [
                ("Revenue", "#,##0.0", 1e6),
                ("Adjusted EBIT", "#,##0.0", 1e6),
                ("EBIT margin %", "0.0%", 1.0),
                ("Depreciation & amortization", "#,##0.0", 1e6),
            ]

            def _write_quarterly_segment_metric(
                metric_label: str,
                seg_values: Dict[str, Dict[pd.Timestamp, float]],
                *,
                number_format: str,
                value_scale: float,
            ) -> None:
                nonlocal row_idx
                eligible_segments: List[str] = []
                ordered_segments = list(quarterly_segment_labels) or list(seg_values.keys())
                for seg in ordered_segments + [s for s in seg_values.keys() if s not in ordered_segments]:
                    if seg in eligible_segments or seg not in seg_values:
                        continue
                    has_value = any(
                        vv is not None and abs(float(vv)) > 1e-9
                        for q in [pd.Timestamp(x) for x in qs]
                        for vv in [seg_values.get(seg, {}).get(pd.Timestamp(q))]
                    )
                    if has_value:
                        eligible_segments.append(seg)
                if not eligible_segments:
                    return
                _write_section(metric_label)
                for seg in eligible_segments:
                    ws[f"A{row_idx}"] = seg
                    if valuation_label_style is not None:
                        ws[f"A{row_idx}"]._style = copy(valuation_label_style)
                        _apply_data_font(ws[f"A{row_idx}"], bold_flag=False)
                    else:
                        ws[f"A{row_idx}"].font = Font(bold=False, size=valuation_data_font_size)
                    for idx_q, q in enumerate(qs):
                        cc = start_col + idx_q
                        qk = pd.Timestamp(q)
                        vv = seg_values.get(seg, {}).get(qk)
                        cell = ws.cell(
                            row=row_idx,
                            column=cc,
                            value=None if vv is None else (float(vv) / value_scale if value_scale != 1.0 else float(vv)),
                        )
                        if valuation_numeric_style is not None:
                            cell._style = copy(valuation_numeric_style)
                        _apply_data_font(cell, bold_flag=False)
                        cell.number_format = number_format
                        cell.border = thin_border
                        cell.alignment = Alignment(horizontal="right")
                        if quarterly_source_note and idx_q == 0:
                            _set_comment(cell, quarterly_source_note)
                    numeric_rows.append(row_idx)
                    no_bucket_rows.add(row_idx)
                    if "%" in str(number_format):
                        pct_rows.append(row_idx)
                    row_idx += 1

            for metric_label, number_format, value_scale in quarterly_metric_order:
                seg_values = quarterly_metrics.get(metric_label, {})
                if seg_values:
                    _write_quarterly_segment_metric(
                        metric_label,
                        seg_values,
                        number_format=number_format,
                        value_scale=value_scale,
                    )

        annual_segment_data = _load_latest_annual_segment_data()
        row_idx += 1
        _write_section("Annual segments")

        annual_metrics = dict(annual_segment_data.get("metrics") or {})
        annual_assets = dict(annual_segment_data.get("assets") or {})
        available_years = sorted({int(y) for y in annual_segment_data.get("years", []) if str(y).isdigit()})
        year_cols = [yy for yy in available_years if yy in {2023, 2024, 2025}]
        if not year_cols:
            year_cols = available_years[-3:]

        if not annual_metrics and not annual_assets:
            ws[f"A{row_idx}"] = f"No annual segment data found for {str(ticker or 'this ticker').upper()}."
            ws[f"A{row_idx}"].font = Font(italic=True, size=font_size)
            row_idx += 1
        else:
            ws[f"A{row_idx}"] = "Year"
            if valuation_quarter_style_a is not None:
                ws[f"A{row_idx}"]._style = copy(valuation_quarter_style_a)
            else:
                ws[f"A{row_idx}"].font = bold
                ws[f"A{row_idx}"].fill = header_fill
                ws[f"A{row_idx}"].border = thin_border
            for idx_y, yy in enumerate(year_cols):
                cc = start_col + idx_y
                cell = ws.cell(row=row_idx, column=cc, value=int(yy))
                if valuation_quarter_style_col is not None:
                    cell._style = copy(valuation_quarter_style_col)
                else:
                    cell.font = bold
                    cell.alignment = Alignment(horizontal="center")
                    cell.fill = header_fill
                    cell.border = thin_border
            row_idx += 1

            default_annual_segments = list(annual_segment_labels) or [
                "Ethanol production",
                "Agribusiness and energy services",
                "Corporate activities",
                "Corporate expense",
                "Corporate assets",
                "Other operations",
                "Intersegment eliminations",
            ]
            annual_metric_order = [
                ("Revenues", default_annual_segments),
                ("Gross margin", default_annual_segments),
                ("Depreciation & amortization", default_annual_segments),
                ("Operating income (loss)", default_annual_segments),
                ("Total assets", default_annual_segments),
            ]

            annual_source_note = str(annual_segment_data.get("source_doc") or "").strip()

            def _write_annual_segment_metric(metric_label: str, seg_values: Dict[str, Dict[int, float]]) -> None:
                nonlocal row_idx
                _write_section(metric_label)
                segment_order = next((order for met, order in annual_metric_order if met == metric_label), list(seg_values.keys()))
                seen_segments: List[str] = []
                for seg in segment_order + [s for s in seg_values.keys() if s not in segment_order]:
                    if seg in seen_segments or seg not in seg_values:
                        continue
                    seen_segments.append(seg)
                    ws[f"A{row_idx}"] = seg
                    if valuation_label_style is not None:
                        ws[f"A{row_idx}"]._style = copy(valuation_label_style)
                        _apply_data_font(ws[f"A{row_idx}"], bold_flag=False)
                    else:
                        ws[f"A{row_idx}"].font = Font(bold=False, size=valuation_data_font_size)
                    for idx_y, yy in enumerate(year_cols):
                        cc = start_col + idx_y
                        vv = seg_values.get(seg, {}).get(int(yy))
                        cell = ws.cell(row=row_idx, column=cc, value=None if vv is None else float(vv) / 1e6)
                        if valuation_numeric_style is not None:
                            cell._style = copy(valuation_numeric_style)
                        _apply_data_font(cell, bold_flag=False)
                        cell.number_format = "#,##0.0"
                        cell.border = thin_border
                        cell.alignment = Alignment(horizontal="right")
                        if annual_source_note and idx_y == 0:
                            _set_comment(cell, annual_source_note)
                    numeric_rows.append(row_idx)
                    no_bucket_rows.add(row_idx)
                    row_idx += 1

            for metric_label, _segment_order in annual_metric_order:
                if metric_label == "Total assets":
                    seg_values = annual_assets
                else:
                    seg_values = annual_metrics.get(metric_label, {})
                if seg_values:
                    _write_annual_segment_metric(metric_label, seg_values)

        # BS + segment QA (latest quarter)
        latest_q = pd.Timestamp(qs[-1]) if qs else None
        qa_status_bits: List[str] = []
        if latest_q is not None:
            # Surface missing key BS sub-lines clearly for latest quarter.
            for key_metric, key_label in [
                ("ap", "Accounts payable"),
                ("accrued", "Accrued liabilities"),
                ("debt_st", "Short-term debt (current portion)"),
                ("ppne", "Property, plant & equipment (net)"),
            ]:
                key_val = maps.get(key_metric, {}).get(latest_q)
                if key_val is None:
                    qa_rows.append(
                        {
                            "quarter": latest_q.date(),
                            "metric": "BS_Segments",
                            "check": f"{key_metric}_availability",
                            "status": "warn",
                            "message": f"{key_label} missing for latest quarter (no mapped fact for {latest_q.date()}).",
                            "source": "History_Q",
                        }
                    )
            a = maps["assets"].get(latest_q)
            l = maps["liabilities"].get(latest_q)
            e = maps["equity"].get(latest_q)
            if a is not None and l is not None and e is not None:
                diff = abs(float(a) - (float(l) + float(e)))
                st = "pass" if diff <= 5_000_000 else ("warn" if diff <= 20_000_000 else "fail")
                qa_rows.append(
                    {
                        "quarter": latest_q.date(),
                        "metric": "BS_Segments",
                        "check": "assets_liab_equity_tie_out",
                        "status": st,
                        "message": f"Assets {(a/1e6):,.1f}m vs Liab+Eq {((l+e)/1e6):,.1f}m (diff {(diff/1e6):,.1f}m).",
                        "source": "History_Q",
                    }
                )
                qa_status_bits.append(f"A=L+E {st.upper()}")
            st_debt = maps["debt_st"].get(latest_q)
            lt_debt = debt_lt_map.get(latest_q)
            debt_core = maps["debt_total"].get(latest_q)
            if st_debt is not None and lt_debt is not None and debt_core is not None:
                diff_d = abs((float(st_debt) + float(lt_debt)) - float(debt_core))
                st = "pass" if diff_d <= 5_000_000 else ("warn" if diff_d <= 20_000_000 else "fail")
                qa_rows.append(
                    {
                        "quarter": latest_q.date(),
                        "metric": "BS_Segments",
                        "check": "debt_tie_out",
                        "status": st,
                        "message": f"ST+LT debt {(float(st_debt)+float(lt_debt))/1e6:,.1f}m vs debt_core {float(debt_core)/1e6:,.1f}m (diff {diff_d/1e6:,.1f}m).",
                        "source": "History_Q",
                    }
                )
                qa_status_bits.append(f"Debt {st.upper()}")
            else:
                qa_rows.append(
                    {
                        "quarter": latest_q.date(),
                        "metric": "BS_Segments",
                        "check": "debt_tie_out",
                        "status": "warn",
                        "message": "Debt tie-out not attempted (missing short-term debt and/or debt_core components).",
                        "source": "History_Q",
                    }
                )
                qa_status_bits.append("Debt N/A")

            cash_latest = maps["cash"].get(latest_q)
            if cash_latest is not None:
                st = "pass" if float(cash_latest) >= 0 else "fail"
                qa_rows.append(
                    {
                        "quarter": latest_q.date(),
                        "metric": "BS_Segments",
                        "check": "cash_non_negative",
                        "status": st,
                        "message": f"Cash {float(cash_latest)/1e6:,.1f}m.",
                        "source": "History_Q",
                    }
                )
                qa_status_bits.append(f"Cash {st.upper()}")

            quarterly_revenue_values = quarterly_metrics.get("Revenue", {})
            quarterly_source_q = quarterly_segment_data.get("source_qd")
            if quarterly_revenue_values and isinstance(quarterly_source_q, date):
                latest_qd = pd.Timestamp(latest_q).date()
                visible_rev = 0.0
                has_visible_rev = False
                for seg_nm, by_quarter in quarterly_revenue_values.items():
                    if "total" in str(seg_nm).strip().lower():
                        continue
                    v_seg = by_quarter.get(pd.Timestamp(latest_q))
                    if v_seg is None:
                        continue
                    visible_rev += float(v_seg)
                    has_visible_rev = True
                if has_visible_rev:
                    qa_rows.append(
                        {
                            "quarter": latest_qd,
                            "metric": "BS_Segments",
                            "check": "quarterly_segment_data",
                            "status": "pass",
                            "message": f"Quarterly segment block populated for {latest_qd} (visible revenue {visible_rev/1e6:,.1f}m).",
                            "source": str(quarterly_segment_data.get("source_doc") or "segment_financials"),
                        }
                    )
                    qa_status_bits.append("Quarterly Seg PASS")
                else:
                    qa_status_bits.append("Quarterly Seg N/A")
            else:
                qa_status_bits.append("Quarterly Seg N/A")

            annual_revenue_values = annual_metrics.get("Revenues", {})
            fy_source_q = annual_segment_data.get("source_qd")
            if annual_revenue_values and isinstance(fy_source_q, date):
                latest_fy = int(fy_source_q.year)
                seg_sum = 0.0
                has_any_seg = False
                for seg_nm, by_year in annual_revenue_values.items():
                    if "intersegment eliminations" in str(seg_nm).strip().lower():
                        continue
                    v_seg = by_year.get(latest_fy)
                    if v_seg is None:
                        continue
                    seg_sum += float(v_seg)
                    has_any_seg = True
                elim_v = annual_revenue_values.get("Intersegment eliminations", {}).get(latest_fy)
                total_rev = seg_sum + float(elim_v or 0.0) if has_any_seg else None
                if total_rev is not None:
                    qa_rows.append(
                        {
                            "quarter": latest_q.date(),
                            "metric": "BS_Segments",
                            "check": "annual_segment_data",
                            "status": "pass",
                            "message": f"Annual segment block populated from FY{latest_fy} 10-K (revenue total {total_rev/1e6:,.1f}m).",
                            "source": str(annual_segment_data.get("source_doc") or "financial_statement"),
                        }
                    )
                    qa_status_bits.append("Annual Seg PASS")
                else:
                    qa_status_bits.append("Annual Seg N/A")
            else:
                qa_status_bits.append("Annual Seg N/A")

        ws["A4"] = "QA: " + (" | ".join(qa_status_bits) if qa_status_bits else "No latest-quarter checks")
        ws["A4"].font = Font(bold=True, size=11)

        def _bucket_fill(v: float) -> PatternFill:
            x = float(v)
            if x <= -0.15:
                return copy(fill_neg_strong)
            if x <= -0.05:
                return copy(fill_neg_mild)
            if x < 0.05:
                return copy(fill_neutral)
            if x < 0.15:
                return copy(fill_pos_mild)
            return copy(fill_pos_strong)

        def _solid_bucket_fill(fill_in: Any, fallback_color: str) -> PatternFill:
            try:
                rgb = str(getattr(getattr(fill_in, "fgColor", None), "rgb", "") or "").strip()
            except Exception:
                rgb = ""
            if not rgb or rgb.lower() == "00000000":
                rgb = fallback_color
            return PatternFill("solid", fgColor=rgb)

        fill_neg_strong = _solid_bucket_fill(valuation_bucket_fills.get("neg_strong"), "00A63A00")
        fill_neg_mild = _solid_bucket_fill(valuation_bucket_fills.get("neg_mild"), "00D55E00")
        fill_neutral = _solid_bucket_fill(valuation_bucket_fills.get("neutral"), "00DDDDDD")
        fill_pos_mild = _solid_bucket_fill(valuation_bucket_fills.get("pos_mild"), "009BD3F5")
        fill_pos_strong = _solid_bucket_fill(valuation_bucket_fills.get("pos_strong"), "002F80ED")

        # Give visible value blocks the same restrained valuation-style language before bucket fills.
        for rr in numeric_rows:
            label_cell = ws.cell(row=rr, column=1)
            if valuation_label_style is not None and label_cell.value not in (None, ""):
                label_cell._style = copy(valuation_label_style)
                _apply_data_font(label_cell, bold_flag=False)
            for cc in range(start_col, last_col + 1):
                data_cell = ws.cell(row=rr, column=cc)
                if data_cell.value in (None, ""):
                    continue
                data_cell.border = thin_border
                data_cell.alignment = Alignment(horizontal="right")
                if rr in no_bucket_rows or rr in pct_rows or rr in delta_nwc_rows or rr in nwc_rows:
                    data_cell.fill = copy(fill_neutral)

        # Clear sheet-level CF and apply direct bucket fills (Valuation-like visual behavior).
        try:
            ws.conditional_formatting._cf_rules.clear()  # type: ignore[attr-defined]
        except Exception:
            pass

        # Apply direct fills to numeric rows by QoQ % change.
        if numeric_rows:
            for rr in numeric_rows:
                if rr in pct_rows or rr in no_bucket_rows or rr in delta_nwc_rows or rr in nwc_rows:
                    continue
                for cc in range(start_col + 1, last_col + 1):
                    cur_cell = ws.cell(row=rr, column=cc)
                    prev_cell = ws.cell(row=rr, column=cc - 1)
                    cur_v = pd.to_numeric(cur_cell.value, errors="coerce")
                    prev_v = pd.to_numeric(prev_cell.value, errors="coerce")
                    if pd.isna(cur_v) or pd.isna(prev_v) or float(prev_v) == 0.0:
                        continue
                    delta = (float(cur_v) - float(prev_v)) / abs(float(prev_v))
                    cur_cell.fill = _bucket_fill(delta)

        # Delta NWC row uses robust denominator.
        if delta_nwc_rows:
            qts = [pd.Timestamp(x) for x in qs]
            for rr in delta_nwc_rows:
                for i in range(1, len(qts)):
                    q_prev = qts[i - 1]
                    q_cur = qts[i]
                    cc = start_col + i
                    cur_cell = ws.cell(row=rr, column=cc)
                    delta_raw = pd.to_numeric(cur_cell.value, errors="coerce")
                    if pd.isna(delta_raw):
                        continue
                    nwc_prev = nwc_map.get(q_prev)
                    denom = None
                    if nwc_prev is not None and abs(float(nwc_prev)) >= 1_000_000.0:
                        denom = float(nwc_prev)
                    else:
                        ca_prev = maps["assets_current"].get(q_prev)
                        if ca_prev is not None and abs(float(ca_prev)) >= 1_000_000.0:
                            denom = float(ca_prev)
                    if denom is None or abs(denom) < 1_000_000.0:
                        continue
                    ratio = float(delta_raw * 1e6) / abs(float(denom))
                    cur_cell.fill = _bucket_fill(ratio)

        # Percent rows: fill by level-bucket on current value (not QoQ delta).
        if pct_rows:
            for rr in pct_rows:
                for cc in range(start_col, last_col + 1):
                    c_pct = ws.cell(row=rr, column=cc)
                    v_pct = pd.to_numeric(c_pct.value, errors="coerce")
                    if pd.isna(v_pct):
                        continue
                    c_pct.fill = _bucket_fill(float(v_pct))

        ws.freeze_panes = "B12"
        w_a = valuation_col_widths.get("A")
        ws.column_dimensions["A"].width = max(54, float(w_a) if w_a is not None else 54)
        for i in range(start_col, last_col + 1):
            letter = get_column_letter(i)
            ws.column_dimensions[letter].width = 12
        # Keep mid quarter columns compact to avoid oversized visual gaps in BS_Segments.
        for letter, idx_letter in (("F", 6), ("G", 7)):
            if start_col <= idx_letter <= last_col:
                ws.column_dimensions[letter].width = 10
        for rr in range(10, ws.max_row + 1):
            for cc in range(1, last_col + 1):
                ws.cell(row=rr, column=cc).border = thin_border
        for r in qa_rows:
            ui_info_rows.append(
                {
                    "quarter": r.get("quarter"),
                    "metric": "BS_Segments",
                    "severity": str(r.get("status") or "info"),
                    "message": f"{r.get('check')}: {r.get('message')}",
                    "source": r.get("source") or "",
                }
            )
        return qa_rows

    _operating_driver_source_cache: Optional[List[Dict[str, Any]]] = None
    _operating_driver_source_by_quarter_cache: Optional[Dict[date, List[Dict[str, Any]]]] = None
    _operating_driver_crush_detail_cache: Dict[str, Dict[str, Any]] = {}
    _operating_driver_metric_parse_cache: Dict[Tuple[str, str], Any] = {}

    def _operating_driver_quarters() -> List[date]:
        qset: set[date] = set()
        for df_in in (hist, adj_metrics):
            if df_in is None or df_in.empty or "quarter" not in df_in.columns:
                continue
            q_series = pd.to_datetime(df_in["quarter"], errors="coerce").dropna()
            for qv in q_series:
                try:
                    qset.add(pd.Timestamp(qv).date())
                except Exception:
                    continue
        return sorted(qset, reverse=True)

    def _driver_source_display(source_type: Any, source_doc: Any = "") -> str:
        return driver_source_display(source_type, source_doc)

    def _driver_source_note(source_doc: Any, snippet: Any = "", extra: Any = "") -> str:
        bits = [str(source_doc or "").strip(), str(extra or "").strip(), str(snippet or "").strip()]
        return "\n\n".join([x for x in bits if x])[:32000]

    def _path_cache_key(path_in: Path) -> str:
        return source_path_cache_key(path_in)

